// Helper for retry
async function withRetry<T>(fn: () => Promise<T>, retries = 3, delay = 1000): Promise<T> {
  try {
    return await fn();
  } catch (error: any) {
    if (retries > 0) {
      console.warn(`Attempt failed, retries remaining: ${retries}`, error);
      await new Promise(resolve => setTimeout(resolve, delay));
      return withRetry(fn, retries - 1, delay * 2); // Exponential backoff
    }
    throw error;
  }
}

// Updated chance event logic
async function triggerChanceEvent(): Promise<string> {
  try {
    return await withRetry(() => generateContent(chanceEventPrompt, apiKey), 3);
  } catch (error: any) {
    console.error("Chance event generation failed after retries:", error);
    const classicEvents = [
        "Message in a Bottle: You find a cryptic message, hinting at treasure.",
        "Ghost Ship: A spectral vessel appears on the horizon, bringing a chill.",
        "Bountiful Catch: Your crew hauls in a massive haul of fish!",
        "Stormy Seas: Weather conditions worsen, requiring you to carefully navigate",
        "Calm Seas: Weather conditions have settled down, making you travel faster"
    ];
    return classicEvents[Math.floor(Math.random() * classicEvents.length)]; // Fallback
  }
}

// Updated property image logic
async function generatePropertyImage(prompt: string): Promise<string> {
  try {
    return await withRetry(() => generateImage(prompt, apiKey), 3);
  } catch (error: any) {
    console.error("Property image generation failed after retries:", error);
    // Return a default image or placeholder
    return "url/to/default/image.png"; // Placeholder URL
  }
}

// Updated description logic
async function generateDescription(prompt: string): Promise<string> {
  try {
    return await withRetry(() => generateContent(prompt, apiKey), 3);
  } catch (error: any) {
    console.error("Description generation failed after retries:", error);
    // Return a default description
    return "A mysterious property awaits!";
  }
}

// Updated portraits
async function generatePortrait(prompt: string): Promise<string> {
  try {
    return await withRetry(() => generateImage(prompt, apiKey), 3);
  } catch (error: any) {
    console.error("Portrait generation failed after retries:", error);
    return "/images/boat_icon.png"; // Default image path
  }
}
```

**Implementing Error Handling**

I'm now implementing the provided error handling code into the existing application. I'm focusing on integrating the `withRetry` helper function to provide a resilient solution, ensuring API calls are retried on `503` or `429` errors. This is crucial for maintaining app functionality, even with API instability. The provided fallback array will be useful in event generation and I will test this code.

