const DEFAULT_PLAYERS: Player[] = [
  { id: 0, name: "Skipstjóri 1", color: "bg-amber-500", position: 0, money: START_MONEY, hunger: START_HUNGER, isJailed: false, inventory: [], isAi: false, boatType: 'TRAWLER', job: "Fisherman", age: 45, personality: "Stoic" },
  { id: 1, name: "Gervigreind", color: "bg-cyan-500", position: 0, money: START_MONEY, hunger: START_HUNGER, isJailed: false, inventory: [], isAi: true, boatType: 'YACHT', job: "AI Overlord", age: 2, personality: "Calculated" },
