const FALLBACK_EVENTS = [
    { title: "Gullkistan", description: "Þú finnur gamla kistu fljótandi á sjónum.", effect: 100 },
    { title: "Rif", description: "Skipið steytir á skeri og þarfnast viðgerðar.", effect: -50 },
    { title: "Góður byr", description: "Hraðbyri heim í höfn.", effect: 50 },
    { title: "Netarifl", description: "Netin rifnuðu í óveðrinu.", effect: -30 },
