      const textResponse = await textPromise;
      const description = textResponse.text?.trim() || "";

      setBoard(prev => prev.map(s => s.id === spaceId ? { 
        ...s, 
        description: description || s.description, 
        isGenerated: true 
      } : s));
    } catch (e) {
      console.error(e);
    }
  };

  const triggerChanceEvent = async () => {
    setAiLoading(true);
    setGameState('EVENT');
    const ai = getAi();

    try {
      const languagePrompt = lang === 'IS' ? "in Icelandic" : "in English";

      const textResponse = await withRetry(() => ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Generate a random event for a maritime board game ${languagePrompt}. Return JSON: {title, description, effect (number -100 to 100)}.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              description: { type: Type.STRING },
              effect: { type: Type.NUMBER }
            },
            required: ['title', 'description', 'effect']
          }
        }
      }));

      const eventData = JSON.parse(textResponse.text || "{}");

      // Use Placeholder for event image to be fast, or generate one if desired.
      // Let's use a nice dynamic placeholder based on the type of event text?
      // For now, stick to the prompt's desire for visual richness, try to generate if possible, fall back to null.

      let imageUrl = ""; 
      // Skipping image generation for speed in this interaction, relying on text + eventual video

      setCurrentEvent({
        title: String(eventData.title || t.mystery_title),
        text: String(eventData.description || t.mystery_desc),
        image: imageUrl, // Will use default placeholder in UI
        effect: Number(eventData.effect || 0)
      });

      // Trigger Video for Event
      generateVoyageVideo(`A mystic maritime event: ${eventData.description}. Cinematic, magical realism.`);

    } catch (e) {
      console.error("Event Generation Failed, using fallback:", e);
      // Use fallback event
      const fallback = FALLBACK_EVENTS[Math.floor(Math.random() * FALLBACK_EVENTS.length)];
      setCurrentEvent({
        title: fallback.title,
        text: fallback.description,
        effect: fallback.effect,
        image: undefined // Will show placeholder
      });
    } finally {
      setAiLoading(false);
    }
  };

  const handleRoll = async (isAi = false) => {
    if (gameState !== 'IDLE' && gameState !== 'AI_THINKING') return;
    setGameState('MOVING');

    // Roll animation delay
    const roll = Math.floor(Math.random() * 6) + 1;
    await new Promise(r => setTimeout(r, 800));

    let newPos = (currentPlayer.position + roll) % BOARD_SIZE;
    let turnDescription = `sailing to ${board[newPos].name}`;

    if (newPos < currentPlayer.position) {
      addLog(`${currentPlayer.name} ${t.log_dock}. +200kr`, 'success');
      updatePlayer(turn, { money: currentPlayer.money + 200, hunger: Math.max(0, currentPlayer.hunger - 1) });
      if (turn === players.length - 1) setRound(r => r + 1);
    }

    updatePlayer(turn, { position: newPos, hunger: currentPlayer.hunger + 1 });

    if (currentPlayer.hunger + 1 >= MAX_HUNGER) {
      addLog(`${currentPlayer.name} ${t.log_starve}`, 'alert');
      updatePlayer(turn, { position: 0, money: Math.max(0, currentPlayer.money - 100), hunger: 0 });
      newPos = 0;
      turnDescription = "collapsed from starvation and was dragged back to port";
    }

    const space = board[newPos];
    handleLandOnSpace(space, newPos, isAi, turnDescription);
  };

  const handleLandOnSpace = async (space: BoardSpace, pos: number, isAi: boolean, moveDesc: string) => {
    // Generate simple description if missing
    if (!space.isGenerated) {
       generatePropertyImage(space.id, space.name, space.type);
    }

    let actionPrompt = "";

    if (space.type === 'CHANCE') {
      await triggerChanceEvent();
      if (isAi) setTimeout(() => resolveEvent(true), 3000);
      return; // Video triggered in triggerChanceEvent
    } else if (space.type === 'STORM') {
      addLog(`${t.log_storm} -50kr`, 'alert');
      updatePlayer(turn, { money: Math.max(0, currentPlayer.money - 50), hunger: currentPlayer.hunger + 1 });
      actionPrompt = "A fishing boat getting hit by a massive wave in a storm.";
      endTurn(isAi, actionPrompt);
    } else if (space.type === 'JAIL') {
      addLog(`${t.log_jail}`, 'alert');
      actionPrompt = "A boat stuck in a tangle of fishing nets underwater.";
      endTurn(isAi, actionPrompt);
    } else if (space.type === 'BOAT' || space.type === 'RESTAURANT') {
      if (space.owner === undefined || space.owner === null) {
        if (isAi) {
           const price = space.price || 0;

           // --- SMART AI BUYING LOGIC ---
           let safetyMargin = 250;

           // Influence from personality
           const personality = currentPlayer.personality?.toLowerCase() || "";
           if (personality.includes("aggressive") || personality.includes("bold") || personality.includes("gambler")) {
             safetyMargin -= 100;
           } else if (personality.includes("cautious") || personality.includes("miser") || personality.includes("scared")) {
             safetyMargin += 150;
           }

           // Adjust for Market Trend
           if (market.trend === 'BOOM') safetyMargin -= 50; 
           else if (market.trend === 'CRASH') safetyMargin += 200; 

           // Adjust for Owned Properties (Snowball effect: more owned = more confident)
           const ownedCount = board.filter(s => s.owner === turn).length;
           safetyMargin = Math.max(50, safetyMargin - (ownedCount * 25));

           if (currentPlayer.money >= (price + safetyMargin)) {
             setTimeout(() => buyProperty(true), 1000);
           } else {
             actionPrompt = `A ${currentPlayer.boatType.toLowerCase()} sailing past ${space.name} without stopping.`;
             setTimeout(() => endTurn(true, actionPrompt), 1000);
           }
        } else {
           setGameState('IDLE');
           // Player decides in UI - Video triggered on Buy or Pass
        }
      } else if (space.owner !== turn) {
        const owner = players[space.owner];
        const baseRent = space.rent || 0;
        let finalRent = Math.floor(baseRent * (space.type === 'BOAT' ? market.fishPrice : market.meatPrice));

        addLog(`${t.log_rent}: ${finalRent}kr -> ${owner.name}`, 'alert');

        let newHunger = currentPlayer.hunger;
        if (space.type === 'RESTAURANT') {
          newHunger = Math.max(0, newHunger - 3);
          addLog("Maturinn góður. Hungur -3.", 'success');
        }

        updatePlayer(turn, { money: Math.max(0, currentPlayer.money - finalRent), hunger: newHunger });
        updatePlayer(space.owner, { money: owner.money + finalRent });

        actionPrompt = `A captain paying coins to another captain at ${space.name}.`;
        endTurn(isAi, actionPrompt);
      } else {
         addLog(`${t.log_welcome} ${space.name}.`);
         if (space.type === 'RESTAURANT') updatePlayer(turn, { hunger: Math.max(0, currentPlayer.hunger - 3) });
         actionPrompt = `A captain relaxing at their own property ${space.name}.`;
         endTurn(isAi, actionPrompt);
      }
    } else {
      actionPrompt = `A boat docking calmly at ${space.name}.`;
      endTurn(isAi, actionPrompt);
    }
  };

  const buyProperty = (isAi = false) => {
    const space = board[players[turn].position];
    if (space.price && players[turn].money >= space.price) {
      updatePlayer(turn, { 
        money: players[turn].money - space.price,
        inventory: [...players[turn].inventory, space.id]
      });
      setBoard(prev => prev.map(s => s.id === space.id ? { ...s, owner: turn } : s));
      addLog(`${players[turn].name} ${t.log_buy} ${space.name}`, 'success');

      const actionPrompt = `A captain shaking hands and buying the deed to ${space.name}, celebrating.`;
      endTurn(isAi, actionPrompt);
    } else if (!isAi) {
      addLog(t.log_poor, 'alert');
    }
  };

  const resolveEvent = (isAi = false) => {
    if (currentEvent) {
      updatePlayer(turn, { money: Math.max(0, players[turn].money + (currentEvent.effect || 0)) });
    }
    setCurrentEvent(null);
    // Video was already triggered in triggerChanceEvent
    endTurn(isAi);
  };

  const endTurn = (isAi = false, actionPrompt?: string) => {
    if (gameState === 'GAME_OVER') return;

    // Trigger video generation for the end of turn summary if prompt exists
    if (actionPrompt) {
        generateVoyageVideo(actionPrompt);
    }

    const nextIdx = (turn + 1) % players.length;
    setTimeout(() => {
        setGameState('IDLE');
        setTurn(nextIdx);
    }, isAi ? 1200 : 0);
  };

  const updatePlayer = (idx: number, updates: Partial<Player>) => {
    setPlayers(prev => prev.map((p, i) => i === idx ? { ...p, ...updates } : p));
  };

  const toggleLang = () => {
    setLang(prev => prev === 'IS' ? 'EN' : 'IS');
  };

  const startGame = () => {
    setView('GAME');
    players.forEach((p, index) => {
      // Always generate to ensure a style is applied, using selfie if available
      generatePlayerPortrait(index, p);
    });
  };

  // --- Views ---

  if (view === 'LOBBY') {
    return <Lobby players={players} setPlayers={setPlayers} onStart={startGame} lang={lang} onToggleLang={toggleLang} />;
  }

  return (
    <div className="min-h-screen flex flex-col items-center justify-center p-4">

      {/* HUD Header */}
      <div className="fixed top-0 left-0 right-0 p-4 z-50 flex justify-between items-start pointer-events-none">
        <div className="glass-panel px-6 py-3 rounded-2xl pointer-events-auto flex items-center gap-4 animate-float">
          <Anchor className="text-cyan-400" size={24} />
          <div>
            <h1 className="text-xl font-serif font-bold text-white tracking-widest">MAÍGREIFINN</h1>
            <div className="text-[10px] text-cyan-300/70 tracking-[0.2em]">{t.subtitle}</div>
          </div>
        </div>

        <div className="flex gap-4 pointer-events-auto">
           {/* Market Ticker */}
           <div className="glass-panel px-4 py-2 rounded-xl flex gap-6 text-xs font-mono">
              <div className="flex flex-col items-center">
                <div className="text-cyan-400 font-bold flex items-center gap-1"><Fish size={12}/> {t.fish}</div>
                <div>{Math.round(market.fishPrice * 100)}%</div>
              </div>
              <div className="w-px bg-white/10"></div>
              <div className="flex flex-col items-center">
                <div className="text-amber-400 font-bold flex items-center gap-1"><Utensils size={12}/> {t.meat}</div>
                <div>{Math.round(market.meatPrice * 100)}%</div>
              </div>
              <div className="w-px bg-white/10"></div>
              <div className="flex items-center">
                 {market.trend === 'BOOM' && <TrendingUp className="text-green-400" size={20} />}
                 {market.trend === 'CRASH' && <TrendingDown className="text-red-400" size={20} />}
                 {market.trend === 'STABLE' && <span className="text-slate-400 text-[10px] whitespace-pre-line text-center">{t.marketStable}</span>}
              </div>
           </div>

           <button onClick={toggleLang} className="glass-panel w-10 h-10 rounded-xl flex items-center justify-center text-cyan-300 hover:text-white transition-colors">
              <span className="font-bold text-xs">{lang}</span>
           </button>
        </div>
      </div>

      {/* Main Game Area */}
      <div className="w-full max-w-7xl flex flex-col lg:flex-row gap-8 items-center lg:items-start mt-20">

        {/* Left: Player Status */}
        <div className="w-full lg:w-64 space-y-4 order-2 lg:order-1">
           {players.map((p, i) => (
             <div key={p.id} className={`glass-card p-4 rounded-xl border-l-4 transition-all duration-300 ${turn === i ? 'border-cyan-400 scale-105 bg-white/10' : 'border-transparent opacity-70'}`}>
                <div className="flex justify-between items-center mb-2">
                   <div className="font-serif font-bold text-sm truncate">{p.name}</div>
                   {p.isAi && <Bot size={14} className="text-cyan-300"/>}
                </div>
                <div className="flex items-center gap-3 mb-2">
                   <div className={`w-12 h-12 rounded-full ${p.color} flex items-center justify-center text-white shadow-lg overflow-hidden border-2 border-white/20 relative group`}>
                      {p.portraitUrl ? (
                        <img src={p.portraitUrl} alt={p.name} className="w-full h-full object-cover" />
                      ) : (
                        <BoatIcon type={p.boatType} />
                      )}
                      {p.selfieData && !p.portraitUrl && (
                        <div className="absolute inset-0 bg-black/50 flex items-center justify-center">
                          <Sparkles size={16} className="text-cyan-300 animate-pulse" />
                        </div>
                      )}
                      {/* Tooltip for stats */}
                      <div className="absolute inset-0 bg-black/80 flex flex-col items-center justify-center text-[8px] opacity-0 group-hover:opacity-100 transition-opacity p-1 text-center">
                         <div>{p.age}y</div>
                         <div>{p.job}</div>
                      </div>
                   </div>
                   <div className="text-xs space-y-1">
                      <div className="flex items-center gap-1"><Coins size={10} className="text-amber-400"/> {p.money}kr</div>
                      <div className="flex items-center gap-1"><Utensils size={10} className={p.hunger > 8 ? "text-red-400" : "text-green-400"}/> {p.hunger}/{MAX_HUNGER}</div>
                   </div>
                </div>
                {turn === i && <div className="text-[10px] text-cyan-300 italic animate-pulse">
                  {gameState === 'AI_THINKING' ? t.calculating : gameState === 'MOVING' ? t.sailing : t.awaiting}
                </div>}
             </div>
           ))}
        </div>

        {/* Center: The Board */}
        <div className="flex-1 order-1 lg:order-2">
           <RenderBoard board={board} players={players} videoUrl={turnVideoUrl} isGeneratingVideo={isGeneratingVideo} />
        </div>

        {/* Right: Controls & Logs */}
        <div className="w-full lg:w-80 flex flex-col gap-4 order-3 h-[500px]">

           {/* Action Deck */}
           <div className="glass-panel p-6 rounded-2xl min-h-[160px] flex flex-col justify-center relative overflow-hidden group">
              {/* Background accent */}
              <div className="absolute inset-0 bg-gradient-to-br from-cyan-500/10 to-transparent pointer-events-none"></div>

              <div className="relative z-10">
                <div className="text-xs uppercase tracking-widest text-slate-400 mb-2 font-bold">Stjórnborð</div>

                {gameState === 'IDLE' && !currentPlayer.isAi ? (
                  <div className="space-y-3">
                    {board[currentPlayer.position].owner === null && board[currentPlayer.position].price ? (
                      <div className="animate-fade-in">
                        <div className="text-sm mb-2">{t.purchase} <span className="font-bold text-cyan-300">{board[currentPlayer.position].name}</span> {t.for} {board[currentPlayer.position].price}kr?</div>
                        <div className="flex gap-2">
                          <button onClick={() => buyProperty(false)} disabled={currentPlayer.money < (board[currentPlayer.position].price || 0)} className="flex-1 bg-cyan-600 hover:bg-cyan-500 text-white py-2 rounded-lg font-bold transition-all disabled:opacity-50 disabled:grayscale">
                            {t.acquire}
                          </button>
                          <button onClick={() => endTurn(false)} className="flex-1 border border-slate-500 hover:bg-slate-700/50 text-slate-300 py-2 rounded-lg transition-all">
                            {t.pass}
                          </button>
                        </div>
                      </div>
                    ) : (
                      <button onClick={() => handleRoll(false)} className="w-full bg-gradient-to-r from-amber-600 to-amber-500 hover:from-amber-500 hover:to-amber-400 text-white py-4 rounded-xl font-bold shadow-lg shadow-amber-900/20 transform hover:-translate-y-1 transition-all flex items-center justify-center gap-3">
                         <Dice5 size={24}/> {t.rollDice}
                      </button>
                    )}
                  </div>
                ) : (
                  <div className="flex items-center justify-center h-full text-cyan-300/50 italic gap-2">
                    {gameState === 'AI_THINKING' && <Sparkles className="animate-spin" size={16}/>}
                    {gameState === 'MOVING' && <Waves className="animate-bounce" size={16}/>}
                    <span>{currentPlayer.isAi ? t.aiControl : t.systemBusy}</span>
                  </div>
                )}
              </div>
           </div>

           {/* Log Feed */}
           <div className="flex-1 glass-card rounded-2xl p-4 overflow-hidden flex flex-col">
              <div className="text-[10px] uppercase text-slate-500 font-bold mb-2 flex justify-between items-center">
                <span>{t.commsLog}</span>
                <span className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></span>
              </div>
              <div className="flex-1 overflow-y-auto space-y-2 pr-2 scrollbar-hide">
                 {[...logs].reverse().map((log) => (
                   <div key={log.id} className={`text-xs p-2 rounded border-l-2 animate-fade-in ${
                     log.type === 'alert' ? 'border-red-500 bg-red-900/20 text-red-200' : 
                     log.type === 'success' ? 'border-green-500 bg-green-900/20 text-green-200' : 
                     'border-cyan-500 bg-cyan-900/10 text-cyan-100'
                   }`}>
                     {log.text}
                   </div>
                 ))}
              </div>
           </div>

        </div>
      </div>

      {/* Event Overlay */}
      {(currentEvent || aiLoading) && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/80 backdrop-blur-md p-4 animate-fade-in">
          <div className="glass-panel max-w-md w-full rounded-2xl overflow-hidden border border-cyan-500/30 shadow-2xl shadow-cyan-900/50 animate-pop-in">
            {aiLoading ? (
               <div className="h-64 flex flex-col items-center justify-center gap-6">
                 <div className="relative">
                   <div className="w-16 h-16 border-4 border-cyan-500/30 border-t-cyan-400 rounded-full animate-spin"></div>
                   <div className="absolute inset-0 flex items-center justify-center">
                     <Sparkles size={24} className="text-amber-400 animate-pulse" />
                   </div>
                 </div>
                 <div className="text-center">
                   <div className="text-cyan-300 font-serif text-lg">{t.consulting}</div>
                   <div className="text-xs text-cyan-500/70 mt-1">{t.generating}</div>
                 </div>
               </div>
            ) : (
              <>
                <div className="h-64 relative bg-slate-900">
                   {currentEvent?.image ? (
                     <img src={currentEvent.image} className="w-full h-full object-cover" />
                   ) : (
                     <div className="w-full h-full flex items-center justify-center text-slate-700"><Waves size={64}/></div>
                   )}
                   <div className="absolute inset-0 bg-gradient-to-t from-slate-900 via-transparent to-transparent"></div>
                   <div className="absolute bottom-4 left-6 right-6">
                     <h2 className="text-2xl font-serif text-white mb-1">{currentEvent?.title}</h2>
                     <div className={`text-lg font-bold ${currentEvent?.effect! >= 0 ? 'text-green-400' : 'text-red-400'}`}>
                       {currentEvent?.effect! > 0 ? '+' : ''}{currentEvent?.effect} kr
                     </div>
                   </div>
                </div>
                <div className="p-6">
                  <p className="text-slate-300 leading-relaxed mb-6 font-light">{currentEvent?.text}</p>
                  {!currentPlayer.isAi && (
                    <button onClick={() => resolveEvent(false)} className="w-full bg-cyan-600 hover:bg-cyan-500 text-white py-3 rounded-xl font-bold transition-all">
                      {t.accept}
                    </button>
                  )}
                  {currentPlayer.isAi && <div className="text-center text-xs text-slate-500 animate-pulse">{t.processing}</div>}
                </div>
              </>
            )}
          </div>
        </div>
      )}

    </div>
  );
}

// --- Subcomponents ---

const Lobby = ({ players, setPlayers, onStart, lang, onToggleLang }: { players: Player[], setPlayers: React.Dispatch<React.SetStateAction<Player[]>>, onStart: () => void, lang: Lang, onToggleLang: () => void }) => {
  const t = T[lang];
  const [loadingId, setLoadingId] = useState<number | null>(null);
  const [hasKey, setHasKey] = useState(false);

  const updatePlayer = (id: number, updates: Partial<Player>) => {
    setPlayers(prev => prev.map(p => p.id === id ? { ...p, ...updates } : p));
  };

  useEffect(() => {
    const checkKey = async () => {
        const win = window as any;
        if (win.aistudio && win.aistudio.hasSelectedApiKey) {
            const selected = await win.aistudio.hasSelectedApiKey();
            setHasKey(selected);
        } else {
             // In dev environments without the aistudio wrapper, assume key is in env or not needed
             setHasKey(true);
        }
    }
    checkKey();
  }, []);

  const handleSelectKey = async () => {
      const win = window as any;
      if (win.aistudio && win.aistudio.openSelectKey) {
          await win.aistudio.openSelectKey();
          // Assuming selection was good
          setHasKey(true);
      }
  };

  const generateIdentity = async (playerIndex: number) => {
    setLoadingId(playerIndex);
    const player = players[playerIndex];
    try {
        const ai = getAi();
        const parts: any[] = [];

        // Context prompt
        let promptText = `Generate a unique, creative identity for a character in a maritime board game set in Iceland. Return a JSON object with these fields: name, age (number), gender, job (string, nautical theme), personality (one word adjective).`;

        if (player.selfieData) {
            // Include image for analysis
            const base64Data = player.selfieData.split(',')[1];
            parts.push({
                inlineData: { mimeType: 'image/jpeg', data: base64Data }
            });
            promptText += ` Analyze the image to estimate age and gender. Create a fitting nautical persona based on their look.`;
        } else {
             promptText += ` Randomly generate a diverse and interesting Icelandic fisherman/captain character.`;
        }

        parts.push({ text: promptText });

        const response = await withRetry(() => ai.models.generateContent({
            model: 'gemini-3-flash-preview', // Supports multimodal input
            contents: { parts },
            config: { responseMimeType: "application/json" }
        }));

        const data = JSON.parse(response.text || "{}");
        updatePlayer(player.id, {
            name: data.name || player.name,
            age: data.age || 35,
            gender: data.gender || "Unknown",
            job: data.job || "Sailor",
            personality: data.personality || "Stoic"
        });

    } catch (e) {
        console.error("Identity generation failed", e);
    } finally {
        setLoadingId(null);
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>, playerId: number) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        updatePlayer(playerId, { selfieData: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  const addPlayer = () => {
    if (players.length >= 4) return;
    const id = players.length;
    setPlayers([...players, { 
      id, name: `Skipstjóri ${id + 1}`, color: "bg-purple-500", position: 0, money: START_MONEY, hunger: START_HUNGER, isJailed: false, inventory: [], isAi: true, boatType: 'TRAWLER', age: 30, job: "Rookie", personality: "Eager" 
    }]);
  };

  return (
    <div className="min-h-screen flex flex-col items-center justify-center p-4 relative overflow-hidden">
       {/* Background Elements */}
       <div className="absolute inset-0 pointer-events-none">
          <div className="absolute top-1/4 left-1/4 w-96 h-96 bg-cyan-500/10 rounded-full blur-3xl animate-pulse"></div>
          <div className="absolute bottom-1/4 right-1/4 w-96 h-96 bg-amber-500/10 rounded-full blur-3xl animate-pulse" style={{ animationDelay: '1s' }}></div>
       </div>

       <div className="glass-panel p-10 rounded-3xl max-w-6xl w-full relative z-10 border border-white/10 shadow-2xl">
          <div className="absolute top-6 right-6">
             <button onClick={onToggleLang} className="glass-card px-4 py-2 rounded-lg flex items-center gap-2 text-cyan-300 hover:text-white transition-colors">
               <Globe size={16}/> <span className="font-bold text-xs">{lang}</span>
             </button>
          </div>

          <div className="text-center mb-12">
             <h1 className="text-6xl font-serif font-bold text-transparent bg-clip-text bg-gradient-to-r from-cyan-200 to-cyan-500 mb-4">{t.lobbyTitle}</h1>
             <p className="text-slate-400 tracking-[0.3em] uppercase text-sm">{t.lobbySubtitle}</p>
          </div>

          <div className="grid grid-cols-1 xl:grid-cols-2 gap-6 mb-10">
             {players.map(p => (
               <div key={p.id} className="glass-card p-6 rounded-xl flex gap-6 relative group items-start transition-all">

                  {/* Left: Avatar & Controls */}
                  <div className="flex flex-col gap-3 items-center min-w-[100px]">
                      <div className={`w-24 h-24 rounded-2xl ${p.color} flex items-center justify-center text-white shadow-lg group-hover:scale-105 transition-transform overflow-hidden relative`}>
                         {p.selfieData ? (
                           <img src={p.selfieData} alt="Selfie" className="w-full h-full object-cover" />
                         ) : (
                           <BoatIcon type={p.boatType} />
                         )}
                      </div>

                      {!p.isAi && (
                        <label className="flex items-center justify-center gap-1 text-[10px] text-cyan-300 cursor-pointer hover:text-white transition-colors w-full glass-card py-1 rounded">
                          <Camera size={12} />
                          {t.upload_selfie}
                          <input type="file" accept="image/*" className="hidden" onChange={(e) => handleFileChange(e, p.id)} />
                        </label>
                     )}

                     <button 
                        onClick={() => generateIdentity(players.indexOf(p))}
                        disabled={loadingId === players.indexOf(p)}
                        className="flex items-center justify-center gap-1 text-[10px] bg-gradient-to-r from-purple-600 to-indigo-600 text-white cursor-pointer hover:brightness-110 transition-colors w-full py-1.5 rounded shadow disabled:opacity-50"
                     >
                        {loadingId === players.indexOf(p) ? <RefreshCw size={12} className="animate-spin"/> : <Sparkles size={12} />}
                        {t.auto_id}
                     </button>
                  </div>

                  {/* Right: Details Form */}
                  <div className="flex-1 space-y-3">
                     <div className="flex gap-2">
                         <input 
                           className="flex-1 bg-transparent border-b border-white/20 text-white font-serif text-lg focus:border-cyan-400 outline-none pb-1 placeholder-white/30"
                           value={p.name}
                           placeholder="Name"
                           onChange={e => updatePlayer(p.id, { name: e.target.value })}
                         />
                         <select 
                            className="bg-white/5 border border-white/10 rounded text-xs text-slate-300 p-1 outline-none w-24"
                            value={p.isAi ? "AI" : "HUMAN"}
                            onChange={e => updatePlayer(p.id, { isAi: e.target.value === "AI" })}
                         >
                             <option value="HUMAN">{t.human}</option>
                             <option value="AI">{t.ai}</option>
                         </select>
                     </div>

                     <div className="grid grid-cols-2 gap-2">
                        <div className="space-y-1">
                            <label className="text-[9px] text-slate-500 uppercase tracking-wider">{t.age}</label>
                            <input 
                               type="number" 
                               className="w-full bg-white/5 rounded border border-white/10 px-2 py-1 text-xs text-white"
                               value={p.age || ""}
                               placeholder="Age"
                               onChange={e => updatePlayer(p.id, { age: parseInt(e.target.value) })}
                            />
                        </div>
                        <div className="space-y-1">
                             <label className="text-[9px] text-slate-500 uppercase tracking-wider">Kyn</label>
                             <select 
                                className="w-full bg-white/5 rounded border border-white/10 px-2 py-1 text-xs text-white"
                                value={p.gender || ""}
                                onChange={e => updatePlayer(p.id, { gender: e.target.value })}
                             >
                                <option value="">Select...</option>
                                <option value="Male">Male</option>
                                <option value="Female">Female</option>
                                <option value="Non-binary">Non-binary</option>
                             </select>
                        </div>
                     </div>

                     <div className="grid grid-cols-2 gap-2">
                        <div className="space-y-1">
                            <label className="text-[9px] text-slate-500 uppercase tracking-wider">{t.job}</label>
                            <input 
                               className="w-full bg-white/5 rounded border border-white/10 px-2 py-1 text-xs text-white"
                               value={p.job || ""}
                               placeholder="e.g. Fisherman"
                               onChange={e => updatePlayer(p.id, { job: e.target.value })}
                            />
                        </div>
                         <div className="space-y-1">
                            <label className="text-[9px] text-slate-500 uppercase tracking-wider">{t.personality}</label>
                            <input 
                               className="w-full bg-white/5 rounded border border-white/10 px-2 py-1 text-xs text-white"
                               value={p.personality || ""}
                               placeholder="e.g. Grumpy"
                               onChange={e => updatePlayer(p.id, { personality: e.target.value })}
                            />
                        </div>
                     </div>

                     <div className="space-y-1">
                         <label className="text-[9px] text-slate-500 uppercase tracking-wider">Boat</label>
                         <select 
                           className="w-full bg-white/5 border border-white/10 rounded px-2 py-1 text-xs text-slate-300 outline-none"
                           value={p.boatType}
                           onChange={e => updatePlayer(p.id, { boatType: e.target.value as BoatType })}
                         >
                            <option value="TRAWLER">{t.trawler}</option>
                            <option value="SAILBOAT">{t.sailboat}</option>
                            <option value="YACHT">{t.yacht}</option>
                            <option value="DINGHY">{t.dinghy}</option>
                         </select>
                     </div>
                  </div>

                  {players.length > 2 && (
                     <button onClick={() => setPlayers(prev => prev.filter(x => x.id !== p.id))} className="absolute top-2 right-2 text-white/20 hover:text-red-400 transition-colors"><X size={16}/></button>
                  )}
               </div>
             ))}
             {players.length < 4 && (
               <button onClick={addPlayer} className="glass-card p-6 rounded-xl flex flex-col items-center justify-center gap-2 text-slate-400 hover:text-white hover:bg-white/10 border-dashed border-2 border-white/10 hover:border-white/30 transition-all min-h-[250px]">
                  <User size={32}/> <span>{t.addCrew}</span>
               </button>
             )}
          </div>

          {!hasKey ? (
            <div className="w-full flex flex-col items-center justify-center p-4 bg-red-900/20 border border-red-500/30 rounded-xl mb-6">
                <span className="text-red-200 mb-2 flex items-center gap-2"><Key size={16}/> {t.api_key_required}</span>
                <button onClick={handleSelectKey} className="bg-red-600 hover:bg-red-500 px-6 py-2 rounded-lg text-white font-bold transition-all">
                    {t.select_key}
                </button>
            </div>
          ) : (
            <button onClick={onStart} className="w-full py-5 bg-gradient-to-r from-cyan-600 to-blue-600 rounded-xl font-bold text-xl tracking-widest text-white shadow-lg shadow-cyan-900/50 hover:shadow-cyan-500/20 hover:scale-[1.01] transition-all flex items-center justify-center gap-3">
               <Play size={24} fill="currentColor"/> {t.embark}
            </button>
          )}

       </div>
    </div>
  );
};

const BoatIcon = ({ type }: { type: BoatType }) => {
  switch(type) {
    case 'SAILBOAT': return <Sailboat size={24} />;
    case 'DINGHY': return <LifeBuoy size={24} />;
    case 'YACHT': return <Anchor size={24} />;
    default: return <Ship size={24} />;
  }
};

const RenderBoard = ({ board, players, videoUrl, isGeneratingVideo }: { board: BoardSpace[], players: Player[], videoUrl: string | null, isGeneratingVideo: boolean }) => {
    // Board logic remains, but visual presentation is key
    const top = board.slice(0, 5);
    const right = board.slice(5, 8);
    const bottom = [...board.slice(8, 13)].reverse();
    const left = [...board.slice(13, 16)].reverse();

    return (
      <div className="relative glass-panel p-4 rounded-3xl shadow-2xl border border-white/10 aspect-square max-w-2xl mx-auto flex flex-col justify-between overflow-hidden animate-[float_8s_ease-in-out_infinite]">

        {/* Central Hub decoration & Video Player */}
        <div className="absolute inset-0 m-32 border border-white/5 rounded-2xl flex flex-col items-center justify-center pointer-events-none z-0">
           <div className="w-full h-full bg-cyan-900/10 rounded-xl backdrop-blur-sm flex items-center justify-center relative overflow-hidden pointer-events-auto shadow-inner border border-white/10">

              {videoUrl ? (
                 <div className="w-full h-full relative group">
                    <video src={videoUrl} autoPlay loop muted playsInline className="w-full h-full object-cover animate-fade-in" />
                    <div className="absolute top-2 right-2 bg-black/50 px-2 py-1 rounded text-[10px] text-white flex items-center gap-1">
                       <Film size={10} className="animate-pulse text-red-400" /> REC
                    </div>
                 </div>
              ) : isGeneratingVideo ? (
                 <div className="flex flex-col items-center justify-center gap-2 text-cyan-300 animate-pulse">
                    <Loader size={32} className="animate-spin" />
                    <span className="text-[10px] uppercase tracking-widest font-bold">Creating Voyage Log...</span>
                 </div>
              ) : (
                <>
                  <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/cubes.png')] opacity-10"></div>
                  <Anchor size={120} className="text-white/5 animate-pulse" />
                </>
              )}

           </div>
        </div>

        <div className="flex gap-2 h-[15%] z-10 animate-slide-in-top">{top.map(s => <Space key={s.id} space={s} players={players} />)}</div>
        <div className="flex flex-1 py-2 gap-2 z-10">
           <div className="flex flex-col w-[15%] gap-2 animate-slide-in-left">{left.map(s => <Space key={s.id} space={s} players={players} />)}</div>
           <div className="flex-1"></div>
           <div className="flex flex-col w-[15%] gap-2 animate-slide-in-right">{right.map(s => <Space key={s.id} space={s} players={players} />)}</div>
        </div>
        <div className="flex gap-2 h-[15%] z-10 animate-slide-in-bottom">{bottom.map(s => <Space key={s.id} space={s} players={players} />)}</div>

        {/* CSS for Board Animations */}
        <style>{`
          @keyframes slide-in-top { from { transform: translateY(-20px); opacity: 0; } to { transform: translateY(0); opacity: 1; } }
          @keyframes slide-in-bottom { from { transform: translateY(20px); opacity: 0; } to { transform: translateY(0); opacity: 1; } }
          @keyframes slide-in-left { from { transform: translateX(-20px); opacity: 0; } to { transform: translateX(0); opacity: 1; } }
          @keyframes slide-in-right { from { transform: translateX(20px); opacity: 0; } to { transform: translateX(0); opacity: 1; } }
          .animate-slide-in-top { animation: slide-in-top 0.8s ease-out forwards; }
          .animate-slide-in-bottom { animation: slide-in-bottom 0.8s ease-out forwards; animation-delay: 0.2s; }
          .animate-slide-in-left { animation: slide-in-left 0.8s ease-out forwards; animation-delay: 0.4s; }
          .animate-slide-in-right { animation: slide-in-right 0.8s ease-out forwards; animation-delay: 0.6s; }
        `}</style>
      </div>
    );
};

const Space = ({ space, players }: { space: BoardSpace, players: Player[] }) => {
  const [hover, setHover] = useState(false);
  const playersHere = players.filter(p => p.position === space.id);

  // Background styling
  const hasImage = !!space.imageUrl;

  return (
    <div 
      className={`relative flex-1 rounded-xl overflow-hidden transition-all duration-300 group ${hasImage ? 'border-0' : 'border border-white/10 bg-white/5'}`}
      onMouseEnter={() => setHover(true)}
      onMouseLeave={() => setHover(false)}
    >
      {/* Background Image Layer */}
      {hasImage ? (
         <div className="absolute inset-0">
            <img src={space.imageUrl} className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110 filter brightness-75 group-hover:brightness-100" />
            <div className="absolute inset-0 bg-gradient-to-t from-slate-900/90 via-slate-900/40 to-transparent"></div>
         </div>
      ) : (
         <div className="absolute inset-0 flex items-center justify-center opacity-10">
            {space.type === 'BOAT' && <Ship size={32} />}
            {space.type === 'RESTAURANT' && <Utensils size={32} />}
            {space.type === 'START' && <Anchor size={32} />}
            {space.type === 'CHANCE' && <Dice5 size={32} />}
         </div>
      )}

      {/* Content */}
      <div className="absolute inset-0 p-1 flex flex-col justify-between z-10">
         {/* Top Icons */}
         <div className="flex justify-between items-start">
             <div className={`p-1 rounded-full ${hasImage ? 'bg-black/50 backdrop-blur' : 'bg-white/10'}`}>
                {space.type === 'BOAT' && <Ship size={10} className="text-cyan-300"/>}
                {space.type === 'RESTAURANT' && <Utensils size={10} className="text-amber-300"/>}
                {space.type === 'CHANCE' && <Sparkles size={10} className="text-purple-300"/>}
                {space.type === 'START' && <Anchor size={10} className="text-green-300"/>}
                {space.type === 'JAIL' && <AlertTriangle size={10} className="text-red-300"/>}
                {space.type === 'STORM' && <Waves size={10} className="text-blue-300"/>}
             </div>
             {space.owner !== undefined && space.owner !== null && (
               <div className={`w-3 h-3 rounded-full border border-white/50 ${players[space.owner].color}`}></div>
             )}
         </div>

         {/* Players */}
         <div className="flex flex-wrap gap-1 justify-center">
            {playersHere.map(p => (
               <div key={p.id} className={`w-4 h-4 rounded-full ${p.color} border-2 border-white shadow-lg animate-pulse-glow flex items-center justify-center transform hover:scale-150 transition-transform cursor-help z-50`} title={p.name}>
                  {/* Tiny dot for player */}
               </div>
            ))}
         </div>

         {/* Bottom Label */}
         <div className="text-center">
            <div className={`text-[9px] font-bold uppercase tracking-wider truncate ${hasImage ? 'text-white text-shadow' : 'text-slate-300'}`}>{space.name}</div>
            {(space.price && !space.owner) && <div className="text-[8px] text-cyan-300/80">{space.price}kr</div>}
         </div>
      </div>

      {/* Hover Info Card */}
      {hover && (
         <div className="absolute inset-0 z-20 bg-slate-900/95 backdrop-blur-md p-2 flex flex-col justify-center text-center animate-fade-in border border-cyan-500/30">
            <p className="text-[10px] text-cyan-200 font-serif italic leading-tight">{space.description || space.name}</p>
            {space.rent && <p className="text-[9px] text-slate-400 mt-1">Leiga: {space.rent}kr</p>}
         </div>
      )}
    </div>
  );
};

