const getAi = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

async function withRetry<T>(fn: () => Promise<T>, retries = 5, delay = 2000): Promise<T> {
  try {
    return await fn();
  } catch (error: any) {
    // Retry on 503 (Service Unavailable), 429 (Too Many Requests), or internal error
    if (retries > 0 && (error?.status === 503 || error?.status === 429 || error?.message?.includes('503'))) {
      console.warn(`API Error ${error?.status}. Retrying in ${delay}ms... (Attempts left: ${retries})`);
      await new Promise(resolve => setTimeout(resolve, delay));
      return withRetry(fn, retries - 1, delay * 2); // Exponential backoff
    }
    throw error;
  }
}

// Shake Detector Hook
const useShake = (onShake: () => void, enabled: boolean) => {
  useEffect(() => {
    if (!enabled) return;

    let lastX = 0, lastY = 0, lastZ = 0;
    let lastUpdate = 0;
    const threshold = 15;

    const handleMotion = (e: DeviceMotionEvent) => {
      const current = Date.now();
      if ((current - lastUpdate) > 100) {
        const diffTime = current - lastUpdate;
        lastUpdate = current;

        const x = e.accelerationIncludingGravity?.x || 0;
        const y = e.accelerationIncludingGravity?.y || 0;
        const z = e.accelerationIncludingGravity?.z || 0;

        const speed = Math.abs(x + y + z - lastX - lastY - lastZ) / diffTime * 10000;

        if (speed > threshold) {
          onShake();
        }

        lastX = x;
        lastY = y;
        lastZ = z;
      }
    };

    window.addEventListener('devicemotion', handleMotion);
    return () => window.removeEventListener('devicemotion', handleMotion);
  }, [enabled, onShake]);
};

// --- Components ---

function App() {
  const [view, setView] = useState<'LOBBY' | 'GAME'>('LOBBY');
  const [lang, setLang] = useState<Lang>('IS');
  const [players, setPlayers] = useState<Player[]>(DEFAULT_PLAYERS);
  const [board, setBoard] = useState<BoardSpace[]>(INITIAL_BOARD);

  const [turn, setTurn] = useState(0);
  const [round, setRound] = useState(1);
  const [gameState, setGameState] = useState<'IDLE' | 'MOVING' | 'CHOOSING_FATE' | 'GAME_OVER' | 'AI_THINKING'>('IDLE');
  const [logs, setLogs] = useState<GameLog[]>([]);
  const [currentFateOptions, setCurrentFateOptions] = useState<FateOption[]>([]);
  const [fateDescription, setFateDescription] = useState<string>("");
  const [aiLoading, setAiLoading] = useState(false);
  const [market, setMarket] = useState<MarketState>({ fishPrice: 1.0, meatPrice: 1.0, trend: 'STABLE' });

  // Video Generation State
  const [turnVideoUrl, setTurnVideoUrl] = useState<string | null>(null);
  const [isGeneratingVideo, setIsGeneratingVideo] = useState(false);

  const currentPlayer = players[turn];
  const t = T[lang];

  useEffect(() => {
    if (turn === 0 && round > 1) {
      updateMarket();
    }
  }, [round]);

  // AI Turn / Auto-Pilot Handling
  useEffect(() => {
    if (view === 'GAME' && gameState === 'IDLE') {
        const isAi = currentPlayer.isAi;
        const isAfk = currentPlayer.isAfk;

        if (isAi || isAfk) {
            const runAutoTurn = async () => {
                setGameState('AI_THINKING');
                await new Promise(r => setTimeout(r, 1500));
                handleRoll(true); // Treat AFK as AI for movement logic
            };
            runAutoTurn();
        }
    }
  }, [turn, view, gameState, currentPlayer]);

  const addLog = (text: string, type: 'info' | 'alert' | 'success' | 'notification' | 'karma' = 'info') => {
    setLogs(prev => [...prev.slice(-4), { id: Date.now(), text, type }]);
  };

  const updateMarket = () => {
    const r = Math.random();
    let newFish = 1.0;
    let newMeat = 1.0;
    let trend: MarketState['trend'] = 'STABLE';

    if (r > 0.85) {
      trend = 'BOOM';
      newFish = 1.6;
      newMeat = 1.4;
      addLog(t.log_market_boom, 'success');
    } else if (r < 0.15) {
      trend = 'CRASH';
      newFish = 0.5;
      newMeat = 0.6;
      addLog(t.log_market_crash, 'alert');
    } else {
      newFish = 0.8 + Math.random() * 0.4;
      newMeat = 0.8 + Math.random() * 0.4;
    }

    setMarket({ fishPrice: Number(newFish.toFixed(2)), meatPrice: Number(newMeat.toFixed(2)), trend });
  };

  // --- Veo Video Generation ---
  const generateVoyageVideo = async (prompt: string) => {
    if (isGeneratingVideo) return;

    setIsGeneratingVideo(true);
    setTurnVideoUrl(null); 

    try {
      const ai = getAi(); 
      console.log("Starting video generation for:", prompt);

      let operation = await withRetry(() => ai.models.generateVideos({
        model: 'veo-3.1-fast-generate-preview',
        prompt: prompt + ", cinematic, 4k, highly detailed, photorealistic, atmospheric lighting, icelandic nature",
        config: {
          numberOfVideos: 1,
          resolution: '720p',
          aspectRatio: '16:9' 
        }
      }));

      while (!operation.done) {
        await new Promise(resolve => setTimeout(resolve, 5000));
        operation = await withRetry(() => ai.operations.getVideosOperation({operation: operation}));
      }

      const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
      if (downloadLink) {
        const videoUrl = `${downloadLink}&key=${process.env.API_KEY}`;
        setTurnVideoUrl(videoUrl);
      }

    } catch (e) {
      console.error("Video generation failed:", e);
      addLog("Video generation failed (Check Quota)", "alert");
    } finally {
      setIsGeneratingVideo(false);
    }
  };

  const generatePlayerPortrait = async (index: number, player: Player) => {
    try {
      const ai = getAi();
      const parts: any[] = [];

      let characterDesc = `A ${player.age || 40} year old ${player.gender || 'person'} working as a ${player.job || 'Sailor'}. Personality: ${player.personality || 'Stoic'}.`;
      let prompt = `A character portrait of an Icelandic sea captain named "${player.name}". ${characterDesc} Rugged, weathered face, wearing traditional wool sweater (lopapeysa) and rain gear. Digital art style, moody lighting, dark ocean background, close-up.`;

      if (player.selfieData) {
        const base64Data = player.selfieData.split(',')[1];
        parts.push({
          inlineData: { mimeType: 'image/jpeg', data: base64Data }
        });
        prompt = `Transform this person into a rugged Icelandic sea captain named "${player.name}". Maintain their facial structure and likeness but age them slightly to ${player.age} years old. Apply the following traits: ${player.job}, ${player.personality} look. Wearing a wool sweater (lopapeysa) and rain gear. Stormy ocean background. High quality, cinematic character concept art.`;
      }

      parts.push({ text: prompt });

      const response = await withRetry(() => ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: { parts },
        config: { imageConfig: { aspectRatio: "1:1", imageSize: "1K" } }
      }));

      let imageUrl = "";
      for (const part of response.candidates?.[0]?.content?.parts || []) {
        if (part.inlineData) imageUrl = `data:image/png;base64,${part.inlineData.data}`;
      }

      if (imageUrl) {
         setPlayers(prev => prev.map((p, i) => i === index ? { ...p, portraitUrl: imageUrl } : p));
      }
    } catch (e) {
      console.error("Portrait Generation Failed:", e);
    }
  };

  const generatePropertyImage = async (spaceId: number, name: string, type: string) => {
    try {
      const ai = getAi();
      const languagePrompt = lang === 'IS' ? "in Icelandic" : "in English";
      const textResponse = await withRetry(() => ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Write a 10-word noir-style evocative description for a ${type} named "${name}" ${languagePrompt}.`
      }));

      const description = textResponse.text?.trim() || "";
      setBoard(prev => prev.map(s => s.id === spaceId ? { 
        ...s, description: description || s.description, isGenerated: true 
      } : s));
    } catch (e) {
      console.error(e);
    }
  };

  const triggerFateEvent = async () => {
    setAiLoading(true);
    setGameState('CHOOSING_FATE');
    const ai = getAi();

    try {
      const languagePrompt = lang === 'IS' ? "in Icelandic" : "in English";

      // Request 3 distinct choices based on Karma
      const prompt = `Generate a maritime dilemma with 3 distinct choices ${languagePrompt} for a player with Karma level ${currentPlayer.karma}.
      1. Safe: Low risk, small reward.
      2. Risky: High risk, potentially big reward or big loss.
      3. Moral: Affects Karma (positively or negatively), moderate money impact.

      Return JSON format:
      {
        "scenario": "Description of the situation",
        "options": [
          { "text": "Choice title", "description": "What happens", "type": "SAFE", "effect": { "money": 50, "hunger": 0, "karma": 0 } },
          { "text": "Choice title", "description": "What happens", "type": "RISKY", "effect": { "money": 200, "hunger": 2, "karma": -1 } },
          { "text": "Choice title", "description": "What happens", "type": "MORAL", "effect": { "money": -50, "hunger": 0, "karma": 5 } }
        ]
      }`;

      const textResponse = await withRetry(() => ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              scenario: { type: Type.STRING },
              options: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    text: { type: Type.STRING },
                    description: { type: Type.STRING },
                    type: { type: Type.STRING, enum: ["SAFE", "RISKY", "MORAL"] },
                    effect: {
                      type: Type.OBJECT,
                      properties: {
                         money: { type: Type.NUMBER },
                         hunger: { type: Type.NUMBER },
                         karma: { type: Type.NUMBER }
                      }
                    }
                  }
                }
              }
            }
          }
        }
      }));

      const data = JSON.parse(textResponse.text || "{}");
      setFateDescription(data.scenario || "The sea offers you a choice...");
      setCurrentFateOptions(data.options || []);

      // Auto-select for AI/AFK after delay
      if (currentPlayer.isAi || currentPlayer.isAfk) {
         setTimeout(() => {
            const choiceIndex = Math.floor(Math.random() * 3); // Simple random for now, could be smarter
            resolveFate(choiceIndex);
         }, 4000);
      }

    } catch (e) {
      console.error("Fate Generation Failed:", e);
      // Fallback
      setCurrentFateOptions([
        { text: "Safety First", description: "Stay close to shore.", type: "SAFE", effect: { money: 50, hunger: 0, karma: 0 } },
        { text: "Brave the Storm", description: "Risk it all for a big catch.", type: "RISKY", effect: { money: 100, hunger: 2, karma: 0 } },
        { text: "Help Strangers", description: "Share your catch with others.", type: "MORAL", effect: { money: -50, hunger: 0, karma: 5 } }
      ]);
      setFateDescription("The oracle is silent, but you must choose.");
    } finally {
      setAiLoading(false);
    }
  };

  const resolveFate = (index: number) => {
     const option = currentFateOptions[index];
     if (!option) return;

     const p = players[turn];
     updatePlayer(turn, {
        money: Math.max(0, p.money + option.effect.money),
        hunger: Math.max(0, p.hunger + option.effect.hunger),
        karma: Math.max(-10, Math.min(10, p.karma + option.effect.karma))
     });

     addLog(`${p.name} chose: ${option.text}`, 'info');
     if (option.effect.karma !== 0) {
        addLog(`Karma ${option.effect.karma > 0 ? '+' : ''}${option.effect.karma}`, 'karma');
     }
     if (option.effect.money !== 0) {
        addLog(`${option.effect.money > 0 ? '+' : ''}${option.effect.money}kr`, option.effect.money > 0 ? 'success' : 'alert');
     }

     if (p.isAfk) {
       addLog(`${t.notification_sent} "${t.message_from_crew} ${option.text} - ${option.description}"`, 'notification');
     }

     setGameState('IDLE');
     setCurrentFateOptions([]);

     const prompt = `A cinematic scene representing the choice: ${option.description}`;
     endTurn(p.isAi || !!p.isAfk, prompt);
  };

  const handleRoll = async (isAuto = false) => {
    if (gameState !== 'IDLE' && gameState !== 'AI_THINKING') return;
    setGameState('MOVING');

    const roll = Math.floor(Math.random() * 6) + 1;
    await new Promise(r => setTimeout(r, 800));

    let newPos = (currentPlayer.position + roll) % BOARD_SIZE;
    let turnDescription = `sailing to ${board[newPos].name}`;

    if (newPos < currentPlayer.position) {
      addLog(`${currentPlayer.name} ${t.log_dock}. +200kr`, 'success');
      updatePlayer(turn, { money: currentPlayer.money + 200, hunger: Math.max(0, currentPlayer.hunger - 1) });
      if (turn === players.length - 1) setRound(r => r + 1);
    }

    updatePlayer(turn, { position: newPos, hunger: currentPlayer.hunger + 1 });

    if (currentPlayer.hunger + 1 >= MAX_HUNGER) {
      addLog(`${currentPlayer.name} ${t.log_starve}`, 'alert');
      updatePlayer(turn, { position: 0, money: Math.max(0, currentPlayer.money - 100), hunger: 0 });
      newPos = 0;
      turnDescription = "collapsed from starvation and was dragged back to port";
    }

    const space = board[newPos];
    handleLandOnSpace(space, newPos, isAuto, turnDescription);
  };

  const handleLandOnSpace = async (space: BoardSpace, pos: number, isAuto: boolean, moveDesc: string) => {
    if (!space.isGenerated) {
       generatePropertyImage(space.id, space.name, space.type);
    }

    let actionPrompt = "";

    if (space.type === 'CHANCE') {
      await triggerFateEvent();
      return; 
    } else if (space.type === 'STORM') {
      addLog(`${t.log_storm} -50kr`, 'alert');
      updatePlayer(turn, { money: Math.max(0, currentPlayer.money - 50), hunger: currentPlayer.hunger + 1 });
      actionPrompt = "A fishing boat getting hit by a massive wave in a storm.";
      endTurn(isAuto, actionPrompt);
    } else if (space.type === 'JAIL') {
      addLog(`${t.log_jail}`, 'alert');
      actionPrompt = "A boat stuck in a tangle of fishing nets underwater.";
      endTurn(isAuto, actionPrompt);
    } else if (space.type === 'BOAT' || space.type === 'RESTAURANT') {
      if (space.owner === undefined || space.owner === null) {
        if (isAuto) {
           const price = space.price || 0;
           let safetyMargin = 250;

           const strategy = currentPlayer.isAfk ? (currentPlayer.afkStrategy || "") : (currentPlayer.personality || "");
           const stratLower = strategy.toLowerCase();

           if (stratLower.includes("aggressive") || stratLower.includes("buy")) {
             safetyMargin = 0;
           } else if (stratLower.includes("cautious") || stratLower.includes("safe")) {
             safetyMargin = 500;
           }

           if (market.trend === 'BOOM') safetyMargin -= 50; 
           else if (market.trend === 'CRASH') safetyMargin += 200; 

           if (currentPlayer.money >= (price + safetyMargin)) {
             setTimeout(() => buyProperty(true), 1000);
           } else {
             actionPrompt = `A ${currentPlayer.boatType.toLowerCase()} sailing past ${space.name} without stopping.`;
             setTimeout(() => endTurn(true, actionPrompt), 1000);
           }
        } else {
           setGameState('IDLE');
        }
      } else if (space.owner !== turn) {
        const owner = players[space.owner];
        const baseRent = space.rent || 0;
        let finalRent = Math.floor(baseRent * (space.type === 'BOAT' ? market.fishPrice : market.meatPrice));

        // Karma interaction: Good karma can sometimes reduce rent (simulated luck)
        if (currentPlayer.karma > 5 && Math.random() > 0.7) {
            finalRent = Math.floor(finalRent * 0.8);
            addLog("Good Karma reduces rent!", 'karma');
        }

        addLog(`${t.log_rent}: ${finalRent}kr -> ${owner.name}`, 'alert');

        let newHunger = currentPlayer.hunger;
        if (space.type === 'RESTAURANT') {
          newHunger = Math.max(0, newHunger - 3);
          addLog("Maturinn góður. Hungur -3.", 'success');
        }

        updatePlayer(turn, { money: Math.max(0, currentPlayer.money - finalRent), hunger: newHunger });
        updatePlayer(space.owner, { money: owner.money + finalRent });

        actionPrompt = `A captain paying coins to another captain at ${space.name}.`;
        endTurn(isAuto, actionPrompt);
      } else {
         addLog(`${t.log_welcome} ${space.name}.`);
         if (space.type === 'RESTAURANT') updatePlayer(turn, { hunger: Math.max(0, currentPlayer.hunger - 3) });
         actionPrompt = `A captain relaxing at their own property ${space.name}.`;
         endTurn(isAuto, actionPrompt);
      }
    } else {
      actionPrompt = `A boat docking calmly at ${space.name}.`;
      endTurn(isAuto, actionPrompt);
    }
  };

  const buyProperty = (isAuto = false) => {
    const space = board[players[turn].position];
    if (space.price && players[turn].money >= space.price) {
      updatePlayer(turn, { 
        money: players[turn].money - space.price,
        inventory: [...players[turn].inventory, space.id]
      });
      setBoard(prev => prev.map(s => s.id === space.id ? { ...s, owner: turn } : s));
      addLog(`${players[turn].name} ${t.log_buy} ${space.name}`, 'success');

      if (players[turn].isAfk) {
        addLog(`${t.notification_sent} "Bought ${space.name}"`, 'notification');
      }

      const actionPrompt = `A captain shaking hands and buying the deed to ${space.name}, celebrating.`;
      endTurn(isAuto, actionPrompt);
    } else if (!isAuto) {
      addLog(t.log_poor, 'alert');
    }
  };

  const endTurn = (isAuto = false, actionPrompt?: string) => {
    if (gameState === 'GAME_OVER') return;

    if (actionPrompt && !isGeneratingVideo) {
        generateVoyageVideo(actionPrompt);
    }

    const nextIdx = (turn + 1) % players.length;
    setTimeout(() => {
        setGameState('IDLE');
        setTurn(nextIdx);
    }, isAuto ? 1200 : 0);
  };

  const updatePlayer = (idx: number, updates: Partial<Player>) => {
    setPlayers(prev => prev.map((p, i) => i === idx ? { ...p, ...updates } : p));
  };

  const toggleLang = () => {
    setLang(prev => prev === 'IS' ? 'EN' : 'IS');
  };

  const toggleAfk = (idx: number) => {
    const p = players[idx];
    updatePlayer(idx, { isAfk: !p.isAfk });
  };

  const updateAfkStrategy = (idx: number, strategy: string) => {
    updatePlayer(idx, { afkStrategy: strategy });
  };

  const startGame = () => {
    setView('GAME');
    players.forEach((p, index) => {
      generatePlayerPortrait(index, p);
    });
  };

  // --- Views ---

  if (view === 'LOBBY') {
    return <Lobby players={players} setPlayers={setPlayers} onStart={startGame} lang={lang} onToggleLang={toggleLang} />;
  }

  return (
    <div className="min-h-screen flex flex-col items-center justify-center p-4 bg-slate-950 text-slate-100 overflow-hidden relative">

      {/* HUD Header */}
      <div className="fixed top-0 left-0 right-0 p-4 z-50 flex justify-between items-start pointer-events-none">
        <div className="glass-panel px-6 py-3 rounded-2xl pointer-events-auto flex items-center gap-4 animate-float">
          <Anchor className="text-cyan-400" size={24} />
          <div>
            <h1 className="text-xl font-serif font-bold text-white tracking-widest">MAÍGREIFINN</h1>
            <div className="text-[10px] text-cyan-300/70 tracking-[0.2em]">{t.subtitle}</div>
          </div>
        </div>

        <div className="flex gap-4 pointer-events-auto">
           {/* Market Ticker */}
           <div className="glass-panel px-4 py-2 rounded-xl flex gap-6 text-xs font-mono">
              <div className="flex flex-col items-center">
                <div className="text-cyan-400 font-bold flex items-center gap-1"><Fish size={12}/> {t.fish}</div>
                <div>{Math.round(market.fishPrice * 100)}%</div>
              </div>
              <div className="w-px bg-white/10"></div>
              <div className="flex flex-col items-center">
                <div className="text-amber-400 font-bold flex items-center gap-1"><Utensils size={12}/> {t.meat}</div>
                <div>{Math.round(market.meatPrice * 100)}%</div>
              </div>
           </div>

           <button onClick={toggleLang} className="glass-panel w-10 h-10 rounded-xl flex items-center justify-center text-cyan-300 hover:text-white transition-colors">
              <span className="font-bold text-xs">{lang}</span>
           </button>
        </div>
      </div>

      {/* Main Game Layout */}
      <div className="w-full max-w-7xl flex gap-8 items-start mt-20 h-[calc(100vh-120px)]">

        {/* BIG SCREEN: The Board (Left/Center) */}
        <div className="flex-1 h-full flex items-center justify-center">
           <RenderBoard board={board} players={players} videoUrl={turnVideoUrl} isGeneratingVideo={isGeneratingVideo} />
        </div>

        {/* MOBILE CONTROLLER: (Right Sidebar simulated as Phone) */}
        <div className="w-96 flex flex-col gap-4 h-full">

           {/* Controller Card */}
           <div className="glass-panel rounded-3xl p-6 flex flex-col flex-1 border-2 border-slate-700/50 relative overflow-hidden">
              <div className="absolute top-0 left-0 right-0 h-1 bg-gradient-to-r from-cyan-500 to-blue-500"></div>

              {/* Header */}
              <div className="flex justify-between items-center mb-6">
                <div className="text-xs uppercase tracking-widest text-slate-400 font-bold flex items-center gap-2">
                   <Smartphone size={14} /> Captain's Handheld
                </div>
                <div className="flex items-center gap-2">
                   <Wifi size={14} className="text-green-400" />
                   <span className="text-[10px] text-green-400">{t.phone_connected}</span>
                </div>
              </div>

              {/* Active Player Info */}
              <div className="flex items-center gap-4 mb-6">
                  <div className={`w-16 h-16 rounded-full ${currentPlayer.color} border-2 border-white shadow-lg overflow-hidden`}>
                     <img src={currentPlayer.portraitUrl || ""} className="w-full h-full object-cover" />
                  </div>
                  <div>
                    <h2 className="text-xl font-serif font-bold text-white">{currentPlayer.name}</h2>
                    <div className="flex gap-3 text-xs mt-1">
                       <span className="flex items-center gap-1 text-amber-300"><Coins size={12}/> {currentPlayer.money}kr</span>
                       <span className="flex items-center gap-1 text-green-300"><Utensils size={12}/> {currentPlayer.hunger}</span>
                       <span className={`flex items-center gap-1 ${currentPlayer.karma > 0 ? 'text-cyan-300' : 'text-purple-300'}`}>
                         <Heart size={12} fill={currentPlayer.karma > 0 ? "currentColor" : "none"}/> {currentPlayer.karma}
                       </span>
                    </div>
                  </div>
              </div>

              {/* Controls Area */}
              <div className="flex-1 flex flex-col justify-center gap-4 relative">

                 {currentPlayer.isAi || currentPlayer.isAfk ? (
                    <div className="text-center p-8 border border-white/10 rounded-xl bg-white/5 animate-pulse">
                       <Bot size={48} className="mx-auto text-cyan-400 mb-4" />
                       <div className="text-lg font-bold text-cyan-200 mb-2">{t.aiControl}</div>
                       <div className="text-xs text-slate-400">
                          {currentPlayer.isAfk ? `AFK: ${currentPlayer.afkStrategy || "Default"}` : "Neural Network Active"}
                       </div>
                    </div>
                 ) : gameState === 'CHOOSING_FATE' ? (
                    <div className="absolute inset-0 bg-slate-900/90 rounded-xl p-4 overflow-y-auto animate-fade-in flex flex-col">
                       <h3 className="text-center text-cyan-300 font-bold mb-2 font-serif uppercase tracking-widest">{t.fate_choice}</h3>
                       <p className="text-xs text-slate-400 mb-4 text-center italic">{fateDescription}</p>
                       <div className="flex-1 space-y-2">
                         {currentFateOptions.map((opt, idx) => (
                           <button key={idx} onClick={() => resolveFate(idx)} className="w-full text-left p-3 rounded-lg border border-white/10 hover:border-cyan-400 hover:bg-white/5 transition-all group">
                              <div className="flex justify-between mb-1">
                                <span className="font-bold text-sm text-white">{opt.text}</span>
                                <span className={`text-[10px] px-2 rounded-full border ${
                                  opt.type === 'SAFE' ? 'border-green-500 text-green-400' : 
                                  opt.type === 'RISKY' ? 'border-red-500 text-red-400' : 
                                  'border-purple-500 text-purple-400'
                                }`}>
                                  {opt.type === 'SAFE' ? t.option_safe : opt.type === 'RISKY' ? t.option_risky : t.option_moral}
                                </span>
                              </div>
                              <p className="text-[10px] text-slate-400 group-hover:text-slate-300">{opt.description}</p>
                           </button>
                         ))}
                       </div>
                    </div>
                 ) : (
                    <>
                       {/* Contextual Action Buttons */}
                       {gameState === 'IDLE' && board[currentPlayer.position].owner === null && board[currentPlayer.position].price ? (
                          <div className="space-y-3 animate-fade-in">
                             <div className="text-center text-sm mb-2">{t.purchase} <span className="text-cyan-300 font-bold">{board[currentPlayer.position].name}</span>?</div>
                             <button onClick={() => buyProperty(false)} disabled={currentPlayer.money < (board[currentPlayer.position].price || 0)} className="w-full py-4 bg-green-600 hover:bg-green-500 rounded-xl font-bold text-white transition-all disabled:opacity-50">
                                {t.acquire} ({board[currentPlayer.position].price}kr)
                             </button>
                             <button onClick={() => endTurn(false)} className="w-full py-3 border border-slate-600 hover:bg-slate-700 rounded-xl text-slate-300 transition-all">
                                {t.pass}
                             </button>
                          </div>
                       ) : (
                          <ShakeButton onRoll={() => handleRoll(false)} label={t.shakeToRoll} disabled={gameState !== 'IDLE'} />
                       )}
                    </>
                 )}

                 {/* Logs Overlay on Phone (Notification Center) */}
                 <div className="mt-auto h-32 overflow-y-auto bg-black/20 rounded-xl p-3 text-[10px] space-y-2 border border-white/5 font-mono">
                    {logs.slice(-6).reverse().map(log => (
                       <div key={log.id} className={`flex items-start gap-2 ${
                         log.type === 'notification' ? 'text-purple-300 bg-purple-900/10 p-1 rounded' : 
                         log.type === 'karma' ? 'text-cyan-300' : 'text-slate-300'
                       }`}>
                          {log.type === 'notification' ? <MessageSquare size={10} className="mt-0.5 shrink-0" /> : 
                           log.type === 'karma' ? <Heart size={10} className="mt-0.5 shrink-0"/> : 
                           <span className="w-1 h-1 bg-slate-500 rounded-full mt-1.5 shrink-0"></span>}
                          <span>{log.text}</span>
                       </div>
                    ))}
                 </div>

              </div>

              {/* AFK Toggle Footer */}
              <div className="mt-4 pt-4 border-t border-white/10">
                 <div className="flex items-center justify-between">
                    <span className="text-xs text-slate-500">{t.afk_mode}</span>
                    <button onClick={() => toggleAfk(turn)} className={`p-2 rounded-lg transition-colors ${currentPlayer.isAfk ? 'bg-purple-600 text-white' : 'bg-white/5 text-slate-400 hover:text-white'}`}>
                       {currentPlayer.isAfk ? <WifiOff size={16}/> : <Wifi size={16}/>}
                    </button>
                 </div>
                 {!currentPlayer.isAi && (
                   <div className={`overflow-hidden transition-all duration-300 ${currentPlayer.isAfk ? 'max-h-20 mt-2 opacity-100' : 'max-h-0 opacity-0'}`}>
                      <input 
                        type="text" 
                        className="w-full bg-black/30 border border-white/10 rounded px-2 py-1 text-xs text-white" 
                        placeholder={t.afk_prompt}
                        value={currentPlayer.afkStrategy || ""}
                        onChange={(e) => updateAfkStrategy(turn, e.target.value)}
                      />
                      <div className="text-[9px] text-purple-300 mt-1 italic">
                         {t.notification_sent} "Taking over control..."
                      </div>
                   </div>
                 )}
              </div>

           </div>

        </div>
      </div>

      {/* Event Overlay */}
      {(aiLoading) && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/80 backdrop-blur-md p-4 animate-fade-in">
          <div className="glass-panel max-w-md w-full rounded-2xl overflow-hidden border border-cyan-500/30 shadow-2xl shadow-cyan-900/50 animate-pop-in p-8 text-center">
             <Loader size={48} className="text-cyan-400 animate-spin mx-auto mb-4" />
             <div className="text-cyan-300 font-serif text-xl">{t.consulting}</div>
             <p className="text-xs text-slate-500 mt-2">{t.generating}</p>
          </div>
        </div>
      )}

    </div>
  );
}

// --- Subcomponents ---

const ShakeButton = ({ onRoll, label, disabled }: { onRoll: () => void, label: string, disabled: boolean }) => {
  // Only enable shake detection if it's the player's turn (not disabled)
  useShake(onRoll, !disabled);

  return (
    <button 
      onClick={onRoll} 
      disabled={disabled}
      className="w-full h-32 bg-gradient-to-br from-amber-600 to-orange-600 rounded-2xl font-bold text-white shadow-lg shadow-orange-900/30 transform hover:scale-[1.02] active:scale-95 transition-all flex flex-col items-center justify-center gap-2 disabled:opacity-50 disabled:grayscale"
    >
       <div className={`p-4 bg-white/10 rounded-full ${!disabled ? 'animate-bounce' : ''}`}>
          <Smartphone size={32} />
       </div>
       <div className="flex items-center gap-2 text-sm tracking-widest">
          {label}
       </div>
    </button>
  );
};

const Lobby = ({ players, setPlayers, onStart, lang, onToggleLang }: { players: Player[], setPlayers: React.Dispatch<React.SetStateAction<Player[]>>, onStart: () => void, lang: Lang, onToggleLang: () => void }) => {
  const t = T[lang];
  const [loadingId, setLoadingId] = useState<number | null>(null);
  const [hasKey, setHasKey] = useState(false);

  const updatePlayer = (id: number, updates: Partial<Player>) => {
    setPlayers(prev => prev.map(p => p.id === id ? { ...p, ...updates } : p));
  };

  useEffect(() => {
    const checkKey = async () => {
        const win = window as any;
        if (win.aistudio && win.aistudio.hasSelectedApiKey) {
            const selected = await win.aistudio.hasSelectedApiKey();
            setHasKey(selected);
        } else {
             setHasKey(true);
        }
    }
    checkKey();
  }, []);

  const handleSelectKey = async () => {
      const win = window as any;
      if (win.aistudio && win.aistudio.openSelectKey) {
          await win.aistudio.openSelectKey();
          setHasKey(true);
      }
  };

  const generateIdentity = async (playerIndex: number) => {
    setLoadingId(playerIndex);
    const player = players[playerIndex];
    try {
        const ai = getAi();
        const parts: any[] = [];

        let promptText = `Generate a unique, creative identity for a character in a maritime board game set in Iceland. Return a JSON object with these fields: name, age (number), gender, job (string, nautical theme), personality (one word adjective).`;

        if (player.selfieData) {
            const base64Data = player.selfieData.split(',')[1];
            parts.push({
                inlineData: { mimeType: 'image/jpeg', data: base64Data }
            });
            promptText += ` Analyze the image to estimate age and gender. Create a fitting nautical persona based on their look.`;
        } else {
             promptText += ` Randomly generate a diverse and interesting Icelandic fisherman/captain character.`;
        }

        parts.push({ text: promptText });

        const response = await withRetry(() => ai.models.generateContent({
            model: 'gemini-3-flash-preview', 
            contents: { parts },
            config: { responseMimeType: "application/json" }
        }));

        const data = JSON.parse(response.text || "{}");
        updatePlayer(player.id, {
            name: data.name || player.name,
            age: data.age || 35,
            gender: data.gender || "Unknown",
            job: data.job || "Sailor",
            personality: data.personality || "Stoic"
        });

    } catch (e) {
        console.error("Identity generation failed", e);
    } finally {
        setLoadingId(null);
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>, playerId: number) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        updatePlayer(playerId, { selfieData: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  const addPlayer = () => {
    if (players.length >= 4) return;
    const id = players.length;
    setPlayers([...players, { 
      id, name: `Skipstjóri ${id + 1}`, color: "bg-purple-500", position: 0, money: START_MONEY, hunger: START_HUNGER, karma: 0, isJailed: false, inventory: [], isAi: true, boatType: 'TRAWLER', age: 30, job: "Rookie", personality: "Eager" 
    }]);
  };

  return (
    <div className="min-h-screen flex flex-col items-center justify-center p-4 relative overflow-hidden bg-slate-950">
       <div className="absolute inset-0 pointer-events-none">
          <div className="absolute top-1/4 left-1/4 w-96 h-96 bg-cyan-500/10 rounded-full blur-3xl animate-pulse"></div>
          <div className="absolute bottom-1/4 right-1/4 w-96 h-96 bg-amber-500/10 rounded-full blur-3xl animate-pulse" style={{ animationDelay: '1s' }}></div>
       </div>

       <div className="glass-panel p-10 rounded-3xl max-w-6xl w-full relative z-10 border border-white/10 shadow-2xl">
          {/* Header & QR Code Area */}
          <div className="flex flex-col md:flex-row justify-between items-center mb-10 gap-6">
             <div className="text-left">
                <h1 className="text-6xl font-serif font-bold text-transparent bg-clip-text bg-gradient-to-r from-cyan-200 to-cyan-500 mb-2">{t.lobbyTitle}</h1>
                <p className="text-slate-400 tracking-[0.3em] uppercase text-sm">{t.lobbySubtitle}</p>
             </div>

             {/* Simulated QR Code for Joining */}
             <div className="bg-white p-3 rounded-xl shadow-lg transform rotate-3 hover:rotate-0 transition-transform">
                <QrCode size={100} className="text-slate-900" />
                <div className="text-center text-[10px] font-bold text-slate-900 mt-1 uppercase tracking-wider">{t.join_game}</div>
             </div>
          </div>

          <div className="grid grid-cols-1 xl:grid-cols-2 gap-6 mb-10">
             {players.map(p => (
               <div key={p.id} className="glass-card p-6 rounded-xl flex gap-6 relative group items-start transition-all">

                  <div className="flex flex-col gap-3 items-center min-w-[100px]">
                      <div className={`w-24 h-24 rounded-2xl ${p.color} flex items-center justify-center text-white shadow-lg group-hover:scale-105 transition-transform overflow-hidden relative`}>
                         {p.selfieData ? (
                           <img src={p.selfieData} alt="Selfie" className="w-full h-full object-cover" />
                         ) : (
                           <BoatIcon type={p.boatType} />
                         )}
                      </div>

                      {!p.isAi && (
                        <label className="flex items-center justify-center gap-1 text-[10px] text-cyan-300 cursor-pointer hover:text-white transition-colors w-full glass-card py-1 rounded">
                          <Camera size={12} />
                          {t.upload_selfie}
                          <input type="file" accept="image/*" className="hidden" onChange={(e) => handleFileChange(e, p.id)} />
                        </label>
                     )}

                     <button 
                        onClick={() => generateIdentity(players.indexOf(p))}
                        disabled={loadingId === players.indexOf(p)}
                        className="flex items-center justify-center gap-1 text-[10px] bg-gradient-to-r from-purple-600 to-indigo-600 text-white cursor-pointer hover:brightness-110 transition-colors w-full py-1.5 rounded shadow disabled:opacity-50"
                     >
                        {loadingId === players.indexOf(p) ? <RefreshCw size={12} className="animate-spin"/> : <Sparkles size={12} />}
                        {t.auto_id}
                     </button>
                  </div>

                  <div className="flex-1 space-y-3">
                     <div className="flex gap-2">
                         <input 
                           className="flex-1 bg-transparent border-b border-white/20 text-white font-serif text-lg focus:border-cyan-400 outline-none pb-1 placeholder-white/30"
                           value={p.name}
                           placeholder="Name"
                           onChange={e => updatePlayer(p.id, { name: e.target.value })}
                         />
                         <select 
                            className="bg-white/5 border border-white/10 rounded text-xs text-slate-300 p-1 outline-none w-24"
                            value={p.isAi ? "AI" : "HUMAN"}
                            onChange={e => updatePlayer(p.id, { isAi: e.target.value === "AI" })}
                         >
                             <option value="HUMAN">{t.human}</option>
                             <option value="AI">{t.ai}</option>
                         </select>
                     </div>

                     <div className="grid grid-cols-2 gap-2">
                        <div className="space-y-1">
                            <label className="text-[9px] text-slate-500 uppercase tracking-wider">{t.age}</label>
                            <input 
                               type="number" 
                               className="w-full bg-white/5 rounded border border-white/10 px-2 py-1 text-xs text-white"
                               value={p.age || ""}
                               placeholder="Age"
                               onChange={e => updatePlayer(p.id, { age: parseInt(e.target.value) })}
                            />
                        </div>
                        <div className="space-y-1">
                             <label className="text-[9px] text-slate-500 uppercase tracking-wider">Kyn</label>
                             <select 
                                className="w-full bg-white/5 rounded border border-white/10 px-2 py-1 text-xs text-white"
                                value={p.gender || ""}
                                onChange={e => updatePlayer(p.id, { gender: e.target.value })}
                             >
                                <option value="">Select...</option>
                                <option value="Male">Male</option>
                                <option value="Female">Female</option>
                                <option value="Non-binary">Non-binary</option>
                             </select>
                        </div>
                     </div>
                  </div>

                  {players.length > 2 && (
                     <button onClick={() => setPlayers(prev => prev.filter(x => x.id !== p.id))} className="absolute top-2 right-2 text-white/20 hover:text-red-400 transition-colors"><X size={16}/></button>
                  )}
               </div>
             ))}
             {players.length < 4 && (
               <button onClick={addPlayer} className="glass-card p-6 rounded-xl flex flex-col items-center justify-center gap-2 text-slate-400 hover:text-white hover:bg-white/10 border-dashed border-2 border-white/10 hover:border-white/30 transition-all min-h-[250px]">
                  <User size={32}/> <span>{t.addCrew}</span>
               </button>
             )}
          </div>

          {!hasKey ? (
            <div className="w-full flex flex-col items-center justify-center p-4 bg-red-900/20 border border-red-500/30 rounded-xl mb-6">
                <span className="text-red-200 mb-2 flex items-center gap-2"><Key size={16}/> {t.api_key_required}</span>
                <button onClick={handleSelectKey} className="bg-red-600 hover:bg-red-500 px-6 py-2 rounded-lg text-white font-bold transition-all">
                    {t.select_key}
                </button>
            </div>
          ) : (
            <button onClick={onStart} className="w-full py-5 bg-gradient-to-r from-cyan-600 to-blue-600 rounded-xl font-bold text-xl tracking-widest text-white shadow-lg shadow-cyan-900/50 hover:shadow-cyan-500/20 hover:scale-[1.01] transition-all flex items-center justify-center gap-3">
               <Play size={24} fill="currentColor"/> {t.embark}
            </button>
          )}

       </div>
    </div>
  );
};

const BoatIcon = ({ type }: { type: BoatType }) => {
  switch(type) {
    case 'SAILBOAT': return <Sailboat size={24} />;
    case 'DINGHY': return <LifeBuoy size={24} />;
    case 'YACHT': return <Anchor size={24} />;
    default: return <Ship size={24} />;
  }
};

const RenderBoard = ({ board, players, videoUrl, isGeneratingVideo }: { board: BoardSpace[], players: Player[], videoUrl: string | null, isGeneratingVideo: boolean }) => {
    // Board logic remains, but visual presentation is key
    const top = board.slice(0, 5);
    const right = board.slice(5, 8);
    const bottom = [...board.slice(8, 13)].reverse();
    const left = [...board.slice(13, 16)].reverse();

    return (
      <div className="relative glass-panel p-4 rounded-3xl shadow-2xl border border-white/10 aspect-square max-w-2xl w-full flex flex-col justify-between overflow-hidden animate-[float_8s_ease-in-out_infinite]">

        {/* Central Hub decoration & Video Player */}
        <div className="absolute inset-0 m-32 border border-white/5 rounded-2xl flex flex-col items-center justify-center pointer-events-none z-0">
           <div className="w-full h-full bg-cyan-900/10 rounded-xl backdrop-blur-sm flex items-center justify-center relative overflow-hidden pointer-events-auto shadow-inner border border-white/10">

              {videoUrl ? (
                 <div className="w-full h-full relative group">
                    <video src={videoUrl} autoPlay loop muted playsInline className="w-full h-full object-cover animate-fade-in" />
                    <div className="absolute top-2 right-2 bg-black/50 px-2 py-1 rounded text-[10px] text-white flex items-center gap-1">
                       <Film size={10} className="animate-pulse text-red-400" /> REC
                    </div>
                 </div>
              ) : isGeneratingVideo ? (
                 <div className="flex flex-col items-center justify-center gap-2 text-cyan-300 animate-pulse">
                    <Loader size={32} className="animate-spin" />
                    <span className="text-[10px] uppercase tracking-widest font-bold">Creating Voyage Log...</span>
                 </div>
              ) : (
                <>
                  <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/cubes.png')] opacity-10"></div>
                  <Anchor size={120} className="text-white/5 animate-pulse" />
                </>
              )}

           </div>
        </div>

        <div className="flex gap-2 h-[15%] z-10 animate-slide-in-top">{top.map(s => <Space key={s.id} space={s} players={players} />)}</div>
        <div className="flex flex-1 py-2 gap-2 z-10">
           <div className="flex flex-col w-[15%] gap-2 animate-slide-in-left">{left.map(s => <Space key={s.id} space={s} players={players} />)}</div>
           <div className="flex-1"></div>
           <div className="flex flex-col w-[15%] gap-2 animate-slide-in-right">{right.map(s => <Space key={s.id} space={s} players={players} />)}</div>
        </div>
        <div className="flex gap-2 h-[15%] z-10 animate-slide-in-bottom">{bottom.map(s => <Space key={s.id} space={s} players={players} />)}</div>

        <style>{`
          @keyframes slide-in-top { from { transform: translateY(-20px); opacity: 0; } to { transform: translateY(0); opacity: 1; } }
          @keyframes slide-in-bottom { from { transform: translateY(20px); opacity: 0; } to { transform: translateY(0); opacity: 1; } }
          @keyframes slide-in-left { from { transform: translateX(-20px); opacity: 0; } to { transform: translateX(0); opacity: 1; } }
          @keyframes slide-in-right { from { transform: translateX(20px); opacity: 0; } to { transform: translateX(0); opacity: 1; } }
          .animate-slide-in-top { animation: slide-in-top 0.8s ease-out forwards; }
          .animate-slide-in-bottom { animation: slide-in-bottom 0.8s ease-out forwards; animation-delay: 0.2s; }
          .animate-slide-in-left { animation: slide-in-left 0.8s ease-out forwards; animation-delay: 0.4s; }
          .animate-slide-in-right { animation: slide-in-right 0.8s ease-out forwards; animation-delay: 0.6s; }
        `}</style>
      </div>
    );
};

const Space = ({ space, players }: { space: BoardSpace, players: Player[] }) => {
  const [hover, setHover] = useState(false);
  const playersHere = players.filter(p => p.position === space.id);
  const hasImage = !!space.imageUrl;

  return (
    <div 
      className={`relative flex-1 rounded-xl overflow-hidden transition-all duration-300 group ${hasImage ? 'border-0' : 'border border-white/10 bg-white/5'}`}
      onMouseEnter={() => setHover(true)}
      onMouseLeave={() => setHover(false)}
    >
      {hasImage ? (
         <div className="absolute inset-0">
            <img src={space.imageUrl} className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110 filter brightness-75 group-hover:brightness-100" />
            <div className="absolute inset-0 bg-gradient-to-t from-slate-900/90 via-slate-900/40 to-transparent"></div>
         </div>
      ) : (
         <div className="absolute inset-0 flex items-center justify-center opacity-10">
            {space.type === 'BOAT' && <Ship size={32} />}
            {space.type === 'RESTAURANT' && <Utensils size={32} />}
            {space.type === 'START' && <Anchor size={32} />}
            {space.type === 'CHANCE' && <Dice5 size={32} />}
         </div>
      )}

      <div className="absolute inset-0 p-1 flex flex-col justify-between z-10">
         <div className="flex justify-between items-start">
             <div className={`p-1 rounded-full ${hasImage ? 'bg-black/50 backdrop-blur' : 'bg-white/10'}`}>
                {space.type === 'BOAT' && <Ship size={10} className="text-cyan-300"/>}
                {space.type === 'RESTAURANT' && <Utensils size={10} className="text-amber-300"/>}
                {space.type === 'CHANCE' && <Sparkles size={10} className="text-purple-300"/>}
                {space.type === 'START' && <Anchor size={10} className="text-green-300"/>}
                {space.type === 'JAIL' && <AlertTriangle size={10} className="text-red-300"/>}
                {space.type === 'STORM' && <Waves size={10} className="text-blue-300"/>}
             </div>
             {space.owner !== undefined && space.owner !== null && (
               <div className={`w-3 h-3 rounded-full border border-white/50 ${players[space.owner].color}`}></div>
             )}
         </div>

         <div className="flex flex-wrap gap-1 justify-center">
            {playersHere.map(p => (
               <div key={p.id} className={`w-4 h-4 rounded-full ${p.color} border-2 border-white shadow-lg animate-pulse-glow flex items-center justify-center transform hover:scale-150 transition-transform cursor-help z-50`} title={p.name}></div>
            ))}
         </div>

         <div className="text-center">
            <div className={`text-[9px] font-bold uppercase tracking-wider truncate ${hasImage ? 'text-white text-shadow' : 'text-slate-300'}`}>{space.name}</div>
            {(space.price && !space.owner) && <div className="text-[8px] text-cyan-300/80">{space.price}kr</div>}
         </div>
      </div>

      {hover && (
         <div className="absolute inset-0 z-20 bg-slate-900/95 backdrop-blur-md p-2 flex flex-col justify-center text-center animate-fade-in border border-cyan-500/30">
            <p className="text-[10px] text-cyan-200 font-serif italic leading-tight">{space.description || space.name}</p>
            {space.rent && <p className="text-[9px] text-slate-400 mt-1">Leiga: {space.rent}kr</p>}
         </div>
      )}
    </div>
  );
};

const root = createRoot(document.getElementById('root')!);
root.render(<App />);

