// --- Constants & Types ---

const BOARD_SIZE = 16;
const START_MONEY = 1500;
const START_HUNGER = 0;
const MAX_HUNGER = 12;

type SpaceType = 'START' | 'BOAT' | 'RESTAURANT' | 'CHANCE' | 'STORM' | 'JAIL';
type BoatType = 'TRAWLER' | 'SAILBOAT' | 'DINGHY' | 'YACHT';
type Lang = 'IS' | 'EN';

// Standardized placeholders
const PREMADE_IMAGES = {
  START: "https://images.unsplash.com/photo-1534447677768-be436bb09401?w=400&h=400&fit=crop",
  BOAT: "https://images.unsplash.com/photo-1544979590-2c00a307c433?w=400&h=400&fit=crop",
  RESTAURANT: "https://images.unsplash.com/photo-1514933651103-005eec06c04b?w=400&h=400&fit=crop",
  STORM: "https://images.unsplash.com/photo-1454789476662-53eb23ba5907?w=400&h=400&fit=crop",
  CHANCE: "https://images.unsplash.com/photo-1517865288-978fcb780652?w=400&h=400&fit=crop",
  JAIL: "https://images.unsplash.com/photo-1555041469-a586c61ea9bc?w=400&h=400&fit=crop"
};

interface BoardSpace {
  id: number;
  name: string;
  type: SpaceType;
  price?: number;
  rent?: number;
  owner?: number | null;
  imageUrl?: string;
  description?: string;
  isGenerated?: boolean;
}

interface FateOption {
  text: string;
  description: string;
  effect: {
    money: number;
    hunger: number;
    karma: number;
  };
  type: 'SAFE' | 'RISKY' | 'MORAL';
}

interface Player {
  id: number;
  name: string;
  color: string;
  position: number;
  money: number;
  hunger: number;
  karma: number; // New Karma Stat (-10 to 10)
  isJailed: boolean;
  inventory: number[];
  isAi: boolean;
  boatType: BoatType;
  portraitUrl?: string;
  selfieData?: string;

  // Character Details
  age?: number;
  gender?: string;
  job?: string;
  personality?: string;
  bio?: string;

