const getAi = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

async function withRetry<T>(fn: () => Promise<T>, retries = 3, delay = 2000): Promise<T> {
  try {
    return await fn();
  } catch (error: any) {
    const status = error?.status || error?.response?.status;
    const message = error?.message || '';

    // Retry on 503 (Service Unavailable), 429 (Too Many Requests), or 500+
    if (retries > 0 && (status === 503 || status === 429 || status >= 500 || message.includes('503'))) {
      console.warn(`API Error ${status}. Retrying in ${delay}ms... (Attempts left: ${retries})`);
      await new Promise(resolve => setTimeout(resolve, delay));
      return withRetry(fn, retries - 1, delay * 2);
    }
    throw error;
  }
}

// Shake Detector Hook
const useShake = (onShake: () => void, enabled: boolean) => {
  useEffect(() => {
    if (!enabled) return;

    let lastX = 0, lastY = 0, lastZ = 0;
    let lastUpdate = 0;
    const threshold = 15;

    const handleMotion = (e: DeviceMotionEvent) => {
      const current = Date.now();
      if ((current - lastUpdate) > 100) {
        const diffTime = current - lastUpdate;
        lastUpdate = current;

        const x = e.accelerationIncludingGravity?.x || 0;
        const y = e.accelerationIncludingGravity?.y || 0;
        const z = e.accelerationIncludingGravity?.z || 0;

        const speed = Math.abs(x + y + z - lastX - lastY - lastZ) / diffTime * 10000;

        if (speed > threshold) {
          onShake();
        }

        lastX = x;
        lastY = y;
        lastZ = z;
      }
    };

    window.addEventListener('devicemotion', handleMotion);
    return () => window.removeEventListener('devicemotion', handleMotion);
  }, [enabled, onShake]);
};

