const Lobby = ({ players, setPlayers, onStart, lang, onToggleLang }: { players: Player[], setPlayers: React.Dispatch<React.SetStateAction<Player[]>>, onStart: () => void, lang: Lang, onToggleLang: () => void }) => {
  const t = T[lang];
  const [loadingId, setLoadingId] = useState<number | null>(null);
  const [hasKey, setHasKey] = useState(false);

  const updatePlayer = (id: number, updates: Partial<Player>) => {
    setPlayers(prev => prev.map(p => p.id === id ? { ...p, ...updates } : p));
  };

  useEffect(() => {
    const checkKey = async () => {
        const win = window as any;
        if (win.aistudio && win.aistudio.hasSelectedApiKey) {
            const selected = await win.aistudio.hasSelectedApiKey();
            setHasKey(selected);
        } else {
             setHasKey(true);
        }
    }
    checkKey();
  }, []);

  const handleSelectKey = async () => {
      const win = window as any;
      if (win.aistudio && win.aistudio.openSelectKey) {
          await win.aistudio.openSelectKey();
          setHasKey(true);
      }
  };

  const generateIdentity = async (playerIndex: number) => {
    setLoadingId(playerIndex);
    const player = players[playerIndex];
    try {
        const ai = getAi();
        const parts: any[] = [];

        let promptText = `Generate a unique, creative identity for a character in a maritime board game set in Iceland. Return a JSON object with these fields: name, age (number), gender, job (string, nautical theme), personality (one word adjective), boatType (one of: TRAWLER, SAILBOAT, DINGHY, YACHT).`;

        if (player.selfieData) {
            const base64Data = player.selfieData.split(',')[1];
            parts.push({
                inlineData: { mimeType: 'image/jpeg', data: base64Data }
            });
            promptText += ` Analyze the image to estimate age and gender. Create a fitting nautical persona based on their look.`;
        } else {
             promptText += ` Randomly generate a diverse and interesting Icelandic fisherman/captain character.`;
        }

        parts.push({ text: promptText });

        const response = await withRetry(() => ai.models.generateContent({
            model: 'gemini-3-flash-preview', 
            contents: { parts },
            config: { 
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        name: { type: Type.STRING },
                        age: { type: Type.NUMBER },
                        gender: { type: Type.STRING },
                        job: { type: Type.STRING },
                        personality: { type: Type.STRING },
                        boatType: { type: Type.STRING, enum: ["TRAWLER", "SAILBOAT", "DINGHY", "YACHT"] }
                    },
                    required: ["name", "age", "gender", "job", "personality", "boatType"]
                }
            }
        }));

        const data = JSON.parse(response.text || "{}");

        // Ensure boatType is valid, otherwise default to TRAWLER
        // Use functional update to ensure we are updating the latest state list, although updatePlayer handles this by id.
        updatePlayer(player.id, {
            name: data.name || player.name,
            age: data.age || 35,
            gender: data.gender || "Unknown",
            job: data.job || "Sailor",
            personality: data.personality || "Stoic",
            boatType: (data.boatType as BoatType) || "TRAWLER"
        });

    } catch (e) {
        console.error("Identity generation failed", e);
    } finally {
        setLoadingId(null);
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>, playerId: number) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        updatePlayer(playerId, { selfieData: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  const addPlayer = () => {
    if (players.length >= 4) return;
    const id = players.length;
    setPlayers([...players, { 
      id, name: `Skipstjóri ${id + 1}`, color: "bg-purple-500", position: 0, money: START_MONEY, hunger: START_HUNGER, karma: 0, isJailed: false, inventory: [], isAi: true, boatType: 'TRAWLER', age: 30, job: "Rookie", personality: "Eager" 
    }]);
  };

  return (
    <div className="min-h-screen flex flex-col items-center justify-center p-4 relative overflow-hidden bg-slate-950">
       <div className="absolute inset-0 pointer-events-none">
          <div className="absolute top-1/4 left-1/4 w-96 h-96 bg-cyan-500/10 rounded-full blur-3xl animate-pulse"></div>
          <div className="absolute bottom-1/4 right-1/4 w-96 h-96 bg-amber-500/10 rounded-full blur-3xl animate-pulse" style={{ animationDelay: '1s' }}></div>
       </div>

       <div className="glass-panel p-10 rounded-3xl max-w-6xl w-full relative z-10 border border-white/10 shadow-2xl">
          {/* Header & QR Code Area */}
          <div className="flex flex-col md:flex-row justify-between items-center mb-10 gap-6">
             <div className="text-left">
                <h1 className="text-6xl font-serif font-bold text-transparent bg-clip-text bg-gradient-to-r from-cyan-200 to-cyan-500 mb-2">{t.lobbyTitle}</h1>
                <p className="text-slate-400 tracking-[0.3em] uppercase text-sm">{t.lobbySubtitle}</p>
             </div>

             {/* Simulated QR Code for Joining */}
             <div className="bg-white p-3 rounded-xl shadow-lg transform rotate-3 hover:rotate-0 transition-transform">
                <QrCode size={100} className="text-slate-900" />
                <div className="text-center text-[10px] font-bold text-slate-900 mt-1 uppercase tracking-wider">{t.join_game}</div>
             </div>
          </div>

          <div className="grid grid-cols-1 xl:grid-cols-2 gap-6 mb-10">
             {players.map(p => (
               <div key={p.id} className="glass-card p-6 rounded-xl flex gap-6 relative group items-start transition-all">

                  <div className="flex flex-col gap-3 items-center min-w-[100px]">
                      <div className={`w-24 h-24 rounded-2xl ${p.color} flex items-center justify-center text-white shadow-lg group-hover:scale-105 transition-transform overflow-hidden relative`}>
                         {p.selfieData ? (
                           <img src={p.selfieData} alt="Selfie" className="w-full h-full object-cover" />
                         ) : (
                           <BoatIcon type={p.boatType} />
                         )}
                      </div>

                      {!p.isAi && (
                        <label className="flex items-center justify-center gap-1 text-[10px] text-cyan-300 cursor-pointer hover:text-white transition-colors w-full glass-card py-1 rounded">
                          <Camera size={12} />
                          {t.upload_selfie}
                          <input type="file" accept="image/*" className="hidden" onChange={(e) => handleFileChange(e, p.id)} />
                        </label>
                     )}

                     <button 
                        onClick={() => generateIdentity(players.indexOf(p))}
                        disabled={loadingId === players.indexOf(p)}
                        className="flex items-center justify-center gap-1 text-[10px] bg-gradient-to-r from-purple-600 to-indigo-600 text-white cursor-pointer hover:brightness-110 transition-colors w-full py-1.5 rounded shadow disabled:opacity-50"
                     >
                        {loadingId === players.indexOf(p) ? <RefreshCw size={12} className="animate-spin"/> : <Sparkles size={12} />}
                        {t.auto_id}
                     </button>
                  </div>

                  <div className="flex-1 space-y-3">
                     <div className="flex gap-2">
                         <input 
                           className="flex-1 bg-transparent border-b border-white/20 text-white font-serif text-lg focus:border-cyan-400 outline-none pb-1 placeholder-white/30"
                           value={p.name}
                           placeholder="Name"
                           onChange={e => updatePlayer(p.id, { name: e.target.value })}
                         />
                         <select 
                            className="bg-white/5 border border-white/10 rounded text-xs text-slate-300 p-1 outline-none w-24"
                            value={p.isAi ? "AI" : "HUMAN"}
                            onChange={e => {
                                const isAi = e.target.value === "AI";
                                updatePlayer(p.id, { isAi });
                                if (isAi) {
                                    generateIdentity(players.indexOf(p));
                                }
                            }}
                         >
                             <option value="HUMAN">{t.human}</option>
                             <option value="AI">{t.ai}</option>
                         </select>
                     </div>

                     <div className="grid grid-cols-2 gap-2">
                        <div className="space-y-1">
                            <label className="text-[9px] text-slate-500 uppercase tracking-wider">{t.age}</label>
                            <input 
                               type="number" 
                               className="w-full bg-white/5 rounded border border-white/10 px-2 py-1 text-xs text-white"
                               value={p.age || ""}
                               placeholder="Age"
                               onChange={e => updatePlayer(p.id, { age: parseInt(e.target.value) })}
                            />
                        </div>
                        <div className="space-y-1">
                             <label className="text-[9px] text-slate-500 uppercase tracking-wider">Kyn</label>
                             <select 
                                className="w-full bg-white/5 rounded border border-white/10 px-2 py-1 text-xs text-white"
                                value={p.gender || ""}
                                onChange={e => updatePlayer(p.id, { gender: e.target.value })}
                             >
                                <option value="">Select...</option>
                                <option value="Male">Male</option>
                                <option value="Female">Female</option>
                                <option value="Non-binary">Non-binary</option>
                             </select>
                        </div>
                     </div>
                  </div>

                  {players.length > 2 && (
                     <button onClick={() => setPlayers(prev => prev.filter(x => x.id !== p.id))} className="absolute top-2 right-2 text-white/20 hover:text-red-400 transition-colors"><X size={16}/></button>
                  )}
               </div>
             ))}
             {players.length < 4 && (
               <button onClick={addPlayer} className="glass-card p-6 rounded-xl flex flex-col items-center justify-center gap-2 text-slate-400 hover:text-white hover:bg-white/10 border-dashed border-2 border-white/10 hover:border-white/30 transition-all min-h-[250px]">
                  <User size={32}/> <span>{t.addCrew}</span>
               </button>
             )}
          </div>

          {!hasKey ? (
            <div className="w-full flex flex-col items-center justify-center p-4 bg-red-900/20 border border-red-500/30 rounded-xl mb-6">
                <span className="text-red-200 mb-2 flex items-center gap-2"><Key size={16}/> {t.api_key_required}</span>
                <button onClick={handleSelectKey} className="bg-red-600 hover:bg-red-500 px-6 py-2 rounded-lg text-white font-bold transition-all">
                    {t.select_key}
                </button>
            </div>
          ) : (
            <button onClick={onStart} className="w-full py-5 bg-gradient-to-r from-cyan-600 to-blue-600 rounded-xl font-bold text-xl tracking-widest text-white shadow-lg shadow-cyan-900/50 hover:shadow-cyan-500/20 hover:scale-[1.01] transition-all flex items-center justify-center gap-3">
               <Play size={24} fill="currentColor"/> {t.embark}
            </button>
          )}

       </div>
    </div>
  );
};

