      updatePlayer(turn, {
          money: currentPlayer.money + option.effect.money,
          hunger: currentPlayer.hunger + option.effect.hunger,
          karma: currentPlayer.karma + option.effect.karma
      });
      addLog(`${currentPlayer.name} valdi: ${option.text}`, 'info');
      setFateOptions([]);
      setGameState('IDLE');
      setTimeout(() => endTurn(isAuto), 1000);
  };

  const endTurn = (isAuto: boolean) => {
      const nextTurn = (turn + 1) % players.length;
      setGameState('IDLE');
      setTurn(nextTurn);
  };

  const updatePlayer = (id: number, data: Partial<Player>) => {
      setPlayers(prev => prev.map((p, i) => i === id ? { ...p, ...data } : p));
  };

  // --- Generation ---

  const generateDescription = async (space: BoardSpace) => {
      // Async update description
      try {
          const ai = getAi();
          const res = await ai.models.generateContent({
              model: 'gemini-3-flash-preview',
              contents: `Write a 1 sentence description of a ${space.type} named ${space.name} in Iceland.`
          });
          setBoard(prev => prev.map(s => s.id === space.id ? { ...s, description: res.text, isGenerated: true } : s));
      } catch(e) {}
  };

  const generateVoyageVideo = async (prompt: string) => {
      if (isGeneratingVideo) return;
      setIsGeneratingVideo(true);
      try {
          // Placeholder for Veo implementation: Using Image Gen for speed/reliability in this demo context
          // Real app would use generateVideos as per docs
          const ai = getAi();
          const res = await withRetry(() => ai.models.generateContent({
              model: 'gemini-3-pro-image-preview',
              contents: { parts: [{ text: prompt + ", cinematic, icelandic style, photorealistic" }] }
          }));
          const imgData = res.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;

          if (imgData) {
              const chapter: VoyageChapter = {
                  id: Date.now().toString(),
                  url: `data:image/png;base64,${imgData}`,
                  description: prompt,
                  round: round,
                  turnName: currentPlayer.name
              };
              setVoyagePlaylist(prev => [...prev, chapter]);
              setViewingChapter(prev => prev === -1 ? 0 : prev);
          }
      } catch (e) { console.error("Video gen failed", e); }
      finally { setIsGeneratingVideo(false); }
  };

  // --- Render ---

  if (view === 'LOBBY') {
      return <Lobby players={players} setPlayers={setPlayers} onStart={() => setView('GAME')} />;
  }

  const viewingChapterData = voyagePlaylist[viewingChapter];

  return (
