async function withRetry<T>(fn: () => Promise<T>, retries = 2): Promise<T> {
  try {
    return await fn();
  } catch (error) {
    if (retries > 0) {
      await new Promise(resolve => setTimeout(resolve, 1000));
      return withRetry(fn, retries - 1);
    }
    throw error;
  }
}

// --- Components ---

function App() {
  const [view, setView] = useState<'LOBBY' | 'GAME'>('LOBBY');
  const [players, setPlayers] = useState<Player[]>(DEFAULT_PLAYERS);
  const [board, setBoard] = useState<BoardSpace[]>(INITIAL_BOARD);
  const [turn, setTurn] = useState(0);
  const [round, setRound] = useState(1);
  const [market, setMarket] = useState<MarketState>({ fishPrice: 1.0, meatPrice: 1.0, trend: 'STABLE' });
  const [logs, setLogs] = useState<GameLog[]>([]);
  const [gameState, setGameState] = useState<'IDLE' | 'MOVING' | 'CHOOSING_FATE' | 'GAME_OVER' | 'AI_THINKING'>('IDLE');
  const [fateOptions, setFateOptions] = useState<FateOption[]>([]);
  const [bgImage, setBgImage] = useState<string | null>(null);

  // Video/Story State
  const [voyagePlaylist, setVoyagePlaylist] = useState<VoyageChapter[]>([]);
  const [viewingChapter, setViewingChapter] = useState(-1);
  const [isGeneratingVideo, setIsGeneratingVideo] = useState(false);

  // Refs for access in event listeners
  const gameStateRef = useRef(gameState);
  const turnRef = useRef(turn);
  const playersRef = useRef(players);
  const viewRef = useRef(view);

  // Sync refs
  useEffect(() => { gameStateRef.current = gameState; }, [gameState]);
  useEffect(() => { turnRef.current = turn; }, [turn]);
  useEffect(() => { playersRef.current = players; }, [players]);
  useEffect(() => { viewRef.current = view; }, [view]);

  const currentPlayer = players[turn];
  const lang: Lang = 'IS'; // Fixed for now, can be toggled
  const t = T[lang];

  useEffect(() => {
    // Generate background on load
    const loadBg = async () => {
        try {
            const ai = getAi();
            const res = await withRetry(() => ai.models.generateContent({
                model: 'gemini-2.5-flash-image',
                contents: { parts: [{ text: "Cinematic dark moody icelandic ocean storm, northern lights, wide angle, matte painting style" }] }
            }));
             // Extract image
            const imgData = res.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
            if (imgData) setBgImage(`data:image/png;base64,${imgData}`);
        } catch(e) { console.error("BG Gen failed", e); }
    };
    loadBg();
  }, []);

  // Log helper
  const addLog = (text: string, type: GameLog['type'] = 'info') => {
    const time = new Date().toLocaleTimeString('en-GB', { hour: '2-digit', minute: '2-digit' });
    setLogs(prev => [{ id: Date.now(), text, type, timestamp: time }, ...prev].slice(0, 50));
  };

  // --- Shake Detection ---
  useEffect(() => {
      let lastShake = 0;
      const handleMotion = (event: DeviceMotionEvent) => {
          if (viewRef.current !== 'GAME') return;

          const now = Date.now();
          if (now - lastShake < 1000) return; // Debounce

          const accel = event.accelerationIncludingGravity;
          if (!accel) return;

          const { x, y, z } = accel;
          if (!x || !y || !z) return;

          const acceleration = Math.sqrt(x*x + y*y + z*z);
          // Threshold for shake (approx 2G to 2.5G usually works well for intentional shakes)
          if (acceleration > 20) {
              const currentP = playersRef.current[turnRef.current];
              const isHuman = !currentP.isAi && !currentP.isAfk;

              if (gameStateRef.current === 'IDLE' && isHuman) {
                  lastShake = now;
                  addLog(t.shake, 'info');
                  if (navigator.vibrate) navigator.vibrate(200);
                  handleRoll(false);
              }
          }
      };

      if (typeof window !== 'undefined' && window.DeviceMotionEvent) {
          window.addEventListener('devicemotion', handleMotion);
      }
      return () => {
          if (typeof window !== 'undefined' && window.DeviceMotionEvent) {
              window.removeEventListener('devicemotion', handleMotion);
          }
      };
  }, []);

  // AI Turn Logic
  useEffect(() => {
    if (view === 'GAME' && gameState === 'IDLE') {
        const isAi = currentPlayer.isAi || currentPlayer.isAfk;
        if (isAi) {
            const timer = setTimeout(() => {
                handleRoll(true);
            }, AI_THINK_TIME);
            return () => clearTimeout(timer);
        }
    }
  }, [turn, view, gameState, currentPlayer]);

  // --- Game Actions ---

  const handleRoll = useCallback(async (isAuto = false) => {
    if (gameStateRef.current !== 'IDLE') return; // Double check using Ref for callbacks
    setGameState(isAuto ? 'AI_THINKING' : 'MOVING');

    // Simulate dice roll animation time (shorter if auto)
    if (!isAuto) await new Promise(r => setTimeout(r, 600));
    else await new Promise(r => setTimeout(r, 300));

    const roll = Math.floor(Math.random() * 6) + 1;

    // Use functional update to ensure we have latest state
    setPlayers(prevPlayers => {
        const currentP = prevPlayers[turnRef.current];
        let newPos = (currentP.position + roll) % BOARD_SIZE;
        let newMoney = currentP.money;
        let newHunger = currentP.hunger + 1;
        let didPassGo = false;

        // Pass Go
        if (newPos < currentP.position) {
           didPassGo = true;
           newMoney += 200;
           newHunger = Math.max(0, newHunger - 1);
        }

        if (didPassGo) {
             addLog(`${currentP.name} fer yfir byrjunarreit. +200kr`, 'success');
             setRound(r => r + 1);
             // Market Fluctuation
             if (Math.random() > 0.7) {
                const boom = Math.random() > 0.5;
                setMarket({
                   fishPrice: boom ? 1.5 : 0.6,
                   meatPrice: boom ? 1.4 : 0.7,
                   trend: boom ? 'BOOM' : 'CRASH'
                });
                addLog(boom ? "MARKAÐURINN BLÓMSTRAR!" : "MARKAÐSHRUN!", boom ? 'success' : 'alert');
             }
        }

        // Check Hunger
        if (newHunger >= MAX_HUNGER) {
           addLog(`${currentP.name} féll í yfirlið vegna hungurs! (-100kr, Byrjunarreitur)`, 'alert');
           newPos = 0;
           newMoney = Math.max(0, newMoney - 100);
           newHunger = 0;
        }

        const updatedPlayers = [...prevPlayers];
        updatedPlayers[turnRef.current] = {
            ...currentP,
            position: newPos,
            money: newMoney,
            hunger: newHunger
        };
        return updatedPlayers;
    });

    // We need to access the NEW position, so we calculate it again locally or use effect.
    // For simplicity, we calculate local variable to pass to handleLand
    const currentP = playersRef.current[turnRef.current];
    let calculatedPos = (currentP.position + roll) % BOARD_SIZE;
    // Handle Pass go edge case for local var logic
    if(calculatedPos < currentP.position) calculatedPos = calculatedPos; 

    // NOTE: The setPlayers is async, so using the calculated index for handleLand
    setTimeout(() => {
        const space = board[calculatedPos];
        handleLand(space, isAuto, calculatedPos);
    }, 100);

  }, [board, players]);

  const handleLand = async (space: BoardSpace, isAuto: boolean, pos: number) => {
    // Generate text for space if needed
    if (!space.isGenerated) {
        generateDescription(space);
    }

    if (space.type === 'CHANCE') {
        // Simple Fate Logic for now to ensure flow
        setGameState('CHOOSING_FATE');
        const options: FateOption[] = [
            { text: "Stormurinn", description: "Þú siglir í gegnum storm.", type: "RISKY", effect: { money: -50, hunger: 2, karma: 1 } },
            { text: "Góður Afli", description: "Netin eru full.", type: "SAFE", effect: { money: 100, hunger: 0, karma: 0 } },
            { text: "Björgun", description: "Þú bjargar bát í vanda.", type: "MORAL", effect: { money: -20, hunger: 1, karma: 5 } }
        ];
        setFateOptions(options);

        if (isAuto) {
            setTimeout(() => resolveFate(options[Math.floor(Math.random() * options.length)], true), AI_ACTION_DELAY);
        }
    } 
    else if (space.type === 'BOAT' || space.type === 'RESTAURANT') {
        // IMPORTANT: Check owner against updated state or passed var?
        // space.owner comes from board state which is stable
        const currentPName = playersRef.current[turnRef.current].name;
        const currentPMoney = playersRef.current[turnRef.current].money;

        if (space.owner === null || space.owner === undefined) {
            // Can buy?
            if (isAuto) {
                // AI Logic
                const canAfford = currentPMoney >= (space.price || 0);
                // Simple AI: Buy if has money > price + 200 buffer
                const shouldBuy = canAfford && (currentPMoney > ((space.price || 0) + 200));

                if (shouldBuy) {
                    addLog(`${currentPName} ákveður að kaupa ${space.name}.`);
                    setTimeout(() => buyProperty(true), AI_ACTION_DELAY);
                } else {
                    addLog(`${currentPName} siglir framhjá ${space.name}.`);
                    setTimeout(() => endTurn(true), AI_ACTION_DELAY);
                }
            } else {
                setGameState('IDLE'); // Waiting for player input
            }
        } else if (space.owner !== turnRef.current) {
            // Pay Rent
            const rent = Math.floor((space.rent || 0) * (space.type === 'BOAT' ? market.fishPrice : market.meatPrice));
            addLog(`${currentPName} borgar ${rent}kr í leigu til ${playersRef.current[space.owner].name}`, 'alert');

            setPlayers(prev => {
                const copy = [...prev];
                const payer = copy[turnRef.current];
                const receiver = copy[space.owner!];

                payer.money = Math.max(0, payer.money - rent);
                receiver.money += rent;

                if (space.type === 'RESTAURANT') {
                    payer.hunger = Math.max(0, payer.hunger - 3);
                }
                return copy;
            });

            if (space.type === 'RESTAURANT') {
                 addLog(`${currentPName} fær sér að borða. Hungur -3.`, 'success');
            }
            setTimeout(() => endTurn(isAuto), AI_ACTION_DELAY + 400);
        } else {
            addLog(`${currentPName} hvílir sig í eign sinni.`);
             if (space.type === 'RESTAURANT') {
                setPlayers(prev => {
                    const copy = [...prev];
                    copy[turnRef.current].hunger = Math.max(0, copy[turnRef.current].hunger - 3);
                    return copy;
                });
            }
            setTimeout(() => endTurn(isAuto), AI_ACTION_DELAY);
        }
    } else {
        // Start, Storm, Jail
        if (space.type === 'STORM') {
            setPlayers(prev => {
                const copy = [...prev];
                copy[turnRef.current].money = Math.max(0, copy[turnRef.current].money - 50);
                return copy;
            });
            addLog("Stormur! Skemmdir á bátnum. -50kr", 'alert');
        } else if (space.type === 'JAIL') {
             addLog("Sjófangelsið! Þú ert fastur í neti.", 'alert');
        }
        setTimeout(() => endTurn(isAuto), AI_ACTION_DELAY);
    }
  };

  const buyProperty = (isAuto: boolean) => {
      const currentP = playersRef.current[turnRef.current];
      const space = board[currentP.position];
      if (space.price && currentP.money >= space.price) {
          updatePlayer(turnRef.current, { 
              money: currentP.money - space.price,
              inventory: [...currentP.inventory, space.id]
          });
          setBoard(prev => prev.map(s => s.id === space.id ? { ...s, owner: turnRef.current } : s));
          addLog(`${currentP.name} keypti ${space.name}!`, 'success');

          generateVoyageVideo(`A proud captain buying the ${space.name} ${space.type.toLowerCase()}, cinematic`);

          setTimeout(() => endTurn(isAuto), AI_ACTION_DELAY);
      }
  };

  const resolveFate = (option: FateOption, isAuto: boolean) => {
      const currentP = playersRef.current[turnRef.current];
      updatePlayer(turnRef.current, {
          money: currentP.money + option.effect.money,
          hunger: currentP.hunger + option.effect.hunger,
          karma: currentP.karma + option.effect.karma
      });
      addLog(`${currentP.name} valdi: ${option.text}`, 'info');
      setFateOptions([]);
      setGameState('IDLE');
      setTimeout(() => endTurn(isAuto), AI_ACTION_DELAY);
  };

  const endTurn = (isAuto: boolean) => {
      const nextTurn = (turn + 1) % players.length;
      setGameState('IDLE');
      setTurn(nextTurn);
  };

  const updatePlayer = (id: number, data: Partial<Player>) => {
      setPlayers(prev => prev.map((p, i) => i === id ? { ...p, ...data } : p));
  };

  // --- Generation ---

  const generateDescription = async (space: BoardSpace) => {
      // Async update description
      try {
          const ai = getAi();
          const res = await ai.models.generateContent({
              model: 'gemini-3-flash-preview',
              contents: `Write a 1 sentence description of a ${space.type} named ${space.name} in Iceland.`
          });
          setBoard(prev => prev.map(s => s.id === space.id ? { ...s, description: res.text, isGenerated: true } : s));
      } catch(e) {}
  };

  const generateVoyageVideo = async (prompt: string) => {
      if (isGeneratingVideo) return;
      setIsGeneratingVideo(true);
      try {
          // Placeholder for Veo implementation: Using Image Gen for speed/reliability in this demo context
          // Real app would use generateVideos as per docs
          const ai = getAi();
          const res = await withRetry(() => ai.models.generateContent({
              model: 'gemini-3-pro-image-preview',
              contents: { parts: [{ text: prompt + ", cinematic, icelandic style, photorealistic" }] }
          }));
          const imgData = res.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;

          if (imgData) {
              const chapter: VoyageChapter = {
                  id: Date.now().toString(),
                  url: `data:image/png;base64,${imgData}`,
                  description: prompt,
                  round: round,
                  turnName: playersRef.current[turnRef.current].name
              };
              setVoyagePlaylist(prev => [...prev, chapter]);
              setViewingChapter(prev => prev === -1 ? 0 : prev);
          }
      } catch (e) { console.error("Video gen failed", e); }
      finally { setIsGeneratingVideo(false); }
  };

  // --- Render ---

  if (view === 'LOBBY') {
      return <Lobby players={players} setPlayers={setPlayers} onStart={() => setView('GAME')} />;
  }

  const viewingChapterData = voyagePlaylist[viewingChapter];

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 font-sans overflow-hidden relative selection:bg-cyan-500/30">

        {/* Background Layer */}
        <div className="absolute inset-0 z-0 transition-all duration-1000" style={{
            backgroundImage: bgImage ? `url(${bgImage})` : `linear-gradient(to bottom, #0f172a, #1e293b)`,
            backgroundSize: 'cover',
            backgroundPosition: 'center',
            opacity: 0.4
        }}></div>

        {/* --- Main HUD --- */}
        <div className="relative z-10 p-6 h-screen flex gap-6">

            {/* LEFT COLUMN: Players & Feed */}
            <div className="w-1/4 flex flex-col gap-6">

                {/* Players List */}
                <div className="glass-panel rounded-2xl p-4 flex-1 overflow-y-auto">
                    <h2 className="flex items-center gap-2 font-serif font-bold text-cyan-400 mb-4 sticky top-0 bg-slate-900/50 p-2 rounded backdrop-blur-md">
                        <Users size={18}/> {t.players}
                    </h2>
                    <div className="space-y-3">
                        {players.map((p, idx) => (
                            <div key={idx} className={`p-3 rounded-xl border transition-all ${turn === idx ? 'bg-white/10 border-cyan-400 shadow-[0_0_15px_rgba(34,211,238,0.2)]' : 'bg-white/5 border-transparent opacity-80'}`}>
                                <div className="flex items-center gap-3">
                                    <div className={`w-10 h-10 rounded-full ${p.color} border-2 border-white flex items-center justify-center overflow-hidden shrink-0`}>
                                        {p.portraitUrl ? <img src={p.portraitUrl} className="w-full h-full object-cover"/> : <User size={20}/>}
                                    </div>
                                    <div className="min-w-0">
                                        <div className="font-bold text-sm truncate">{p.name}</div>
                                        <div className="flex gap-2 text-[10px] text-slate-300">
                                            <span className="flex items-center"><Coins size={10} className="mr-1 text-amber-300"/>{p.money}</span>
                                            <span className="flex items-center"><Utensils size={10} className="mr-1 text-red-300"/>{p.hunger}</span>
                                        </div>
                                    </div>
                                    {turn === idx && <div className="ml-auto w-2 h-2 rounded-full bg-cyan-400 animate-pulse"></div>}
                                </div>
                            </div>
                        ))}
                    </div>
                </div>

                {/* Voyage Log (Story) */}
                <div className="glass-panel rounded-2xl p-4 h-1/2 flex flex-col">
                    <h2 className="flex items-center gap-2 font-serif font-bold text-amber-400 mb-2">
                        <ScrollText size={18}/> {t.feed}
                    </h2>
                    <div className="flex-1 overflow-y-auto space-y-2 text-xs font-mono pr-2">
                        {logs.map((log) => (
                            <div key={log.id} className="animate-fade-in">
                                <span className="text-slate-500 mr-2">[{log.timestamp}]</span>
                                <span className={
                                    log.type === 'alert' ? 'text-red-300' :
                                    log.type === 'success' ? 'text-green-300' :
                                    log.type === 'karma' ? 'text-purple-300' : 'text-slate-200'
                                }>{log.text}</span>
                            </div>
                        ))}
                    </div>
                </div>
            </div>

            {/* CENTER: Board & Visuals */}
            <div className="flex-1 flex flex-col gap-6">

                {/* Visualizer (Image/Video) */}
                <div className="glass-panel rounded-2xl aspect-video w-full relative overflow-hidden group border border-white/10 shadow-2xl flex items-center justify-center bg-black/40">
                    {viewingChapterData ? (
                        <>
                            <img src={viewingChapterData.url} className="w-full h-full object-cover animate-fade-in" />
                            <div className="absolute bottom-0 inset-x-0 bg-gradient-to-t from-black via-black/50 to-transparent p-6 pt-20">
                                <h3 className="font-serif text-2xl text-white text-shadow">{viewingChapterData.turnName}</h3>
                                <p className="text-slate-200 text-shadow">{viewingChapterData.description}</p>
                            </div>
                        </>
                    ) : (
                         <div className="text-center opacity-30">
                            <Clapperboard size={64} className="mx-auto mb-4"/>
                            <div className="font-serif tracking-widest">AWAITING VOYAGE DATA</div>
                         </div>
                    )}
                </div>

                {/* Game Board */}
                <div className="flex-1 glass-panel rounded-2xl p-4 relative flex flex-col justify-between">
                    <div className="flex gap-2 h-1/5">
                        {board.slice(0, 5).map(s => <BoardCell key={s.id} space={s} players={players} />)}
                    </div>
                    <div className="flex flex-1 py-2 gap-2">
                        <div className="flex flex-col w-1/5 gap-2">
                             {[...board.slice(13, 16)].reverse().map(s => <BoardCell key={s.id} space={s} players={players} />)}
                        </div>
                        <div className="flex-1 flex items-center justify-center">
                            {/* Center Logo / Status */}
                            <div className="text-center">
                                <h1 className="text-4xl font-serif font-bold text-transparent bg-clip-text bg-gradient-to-r from-cyan-300 to-blue-500">{t.title}</h1>
                                <div className="text-xs tracking-[0.3em] text-slate-400 mt-2">{t.subtitle}</div>

                                {/* Market Ticker */}
                                <div className="mt-8 flex gap-8 justify-center">
                                    <div className="text-center">
                                        <div className="text-[10px] uppercase text-slate-500">FISKUR</div>
                                        <div className={`text-xl font-mono font-bold ${market.trend === 'BOOM' ? 'text-green-400' : market.trend === 'CRASH' ? 'text-red-400' : 'text-slate-200'}`}>
                                            {(market.fishPrice * 100).toFixed(0)}%
                                        </div>
                                    </div>
                                    <div className="text-center">
                                        <div className="text-[10px] uppercase text-slate-500">KJÖT</div>
                                        <div className={`text-xl font-mono font-bold ${market.trend === 'BOOM' ? 'text-green-400' : market.trend === 'CRASH' ? 'text-red-400' : 'text-slate-200'}`}>
                                            {(market.meatPrice * 100).toFixed(0)}%
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>
                        <div className="flex flex-col w-1/5 gap-2">
                            {board.slice(5, 8).map(s => <BoardCell key={s.id} space={s} players={players} />)}
                        </div>
                    </div>
                    <div className="flex gap-2 h-1/5">
                        {[...board.slice(8, 13)].reverse().map(s => <BoardCell key={s.id} space={s} players={players} />)}
                    </div>
                </div>

            </div>

            {/* RIGHT COLUMN: Mobile Controller (Interactive) */}
            <div className="w-1/4 max-w-sm flex flex-col relative z-20">
                <div className="glass-panel rounded-[3rem] border-4 border-slate-700 bg-slate-900 p-2 shadow-2xl h-full flex flex-col relative overflow-hidden">
                    {/* Phone Notch */}
                    <div className="absolute top-0 left-1/2 -translate-x-1/2 w-32 h-6 bg-slate-800 rounded-b-xl z-30"></div>

                    {/* Phone Screen */}
                    <div className="flex-1 rounded-[2.5rem] overflow-hidden bg-slate-900 relative flex flex-col">

                        {/* Status Bar */}
                        <div className="bg-slate-800/50 p-4 pt-8 flex justify-between items-center text-[10px] text-slate-400">
                             <span>{new Date().toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
                             <div className="flex gap-2">
                                <Wifi size={12}/>
                                <div className="w-4 h-2 bg-green-500 rounded-sm"></div>
                             </div>
                        </div>

                        {/* Player Header */}
                        <div className="p-6 text-center">
                            <div className={`w-20 h-20 mx-auto rounded-full ${currentPlayer.color} border-4 border-slate-800 shadow-lg mb-3 overflow-hidden`}>
                                <img src={currentPlayer.portraitUrl || `https://api.dicebear.com/7.x/avataaars/svg?seed=${currentPlayer.name}`} className="w-full h-full bg-slate-700" />
                            </div>
                            <h2 className="text-xl font-bold text-white">{currentPlayer.name}</h2>
                            <div className="flex justify-center gap-4 mt-2 text-xs">
                                <span className="bg-amber-500/20 text-amber-300 px-2 py-1 rounded flex items-center gap-1"><Coins size={10}/> {currentPlayer.money}</span>
                                <span className="bg-red-500/20 text-red-300 px-2 py-1 rounded flex items-center gap-1"><Heart size={10}/> {currentPlayer.hunger}</span>
                            </div>
                        </div>

                        {/* Controls Area */}
                        <div className="flex-1 p-6 flex flex-col justify-center">

                            {/* AI / AFK View */}
                            {(currentPlayer.isAi || currentPlayer.isAfk) ? (
                                <div className="text-center animate-pulse">
                                    <Bot size={48} className="mx-auto text-cyan-500 mb-4"/>
                                    <h3 className="text-cyan-300 font-bold mb-2">{t.ai_thinking}</h3>
                                    <div className="h-1 w-24 bg-slate-700 rounded mx-auto overflow-hidden">
                                        <div className="h-full bg-cyan-500 animate-[width_1s_infinite]"></div>
                                    </div>
                                </div>
                            ) : gameState === 'CHOOSING_FATE' ? (
                                <div className="space-y-3">
                                    <h3 className="text-center font-serif text-purple-400 mb-4">{t.fate}</h3>
                                    {fateOptions.map((opt, i) => (
                                        <button key={i} onClick={() => resolveFate(opt, false)} className="w-full text-left p-4 rounded-xl bg-white/5 hover:bg-white/10 border border-white/10 hover:border-purple-400 transition-all">
                                            <div className="font-bold text-sm">{opt.text}</div>
                                            <div className="text-[10px] text-slate-400">{opt.description}</div>
                                        </button>
                                    ))}
                                </div>
                            ) : gameState === 'IDLE' ? (
                                board[currentPlayer.position].owner === null && board[currentPlayer.position].price ? (
                                    <div className="space-y-3 animate-fade-in">
                                        <div className="text-center text-sm mb-4">
                                            <div className="text-xs text-slate-400">Current Location</div>
                                            <div className="font-bold text-lg">{board[currentPlayer.position].name}</div>
                                            <div className="text-amber-300 font-mono mt-1">{board[currentPlayer.position].price} kr</div>
                                        </div>
                                        <button onClick={() => buyProperty(false)} disabled={currentPlayer.money < (board[currentPlayer.position].price || 0)} className="w-full py-4 bg-gradient-to-r from-green-600 to-green-500 rounded-xl font-bold text-white shadow-lg shadow-green-900/50 hover:scale-[1.02] active:scale-95 transition-all disabled:opacity-50">
                                            {t.buy}
                                        </button>
                                        <button onClick={() => endTurn(false)} className="w-full py-3 bg-white/5 hover:bg-white/10 rounded-xl text-slate-300 transition-all">
                                            {t.pass}
                                        </button>
                                    </div>
                                ) : (
                                    <button 
                                        onClick={() => handleRoll(false)}
                                        className="group w-full aspect-square rounded-full bg-gradient-to-br from-cyan-500 to-blue-600 shadow-[0_0_40px_rgba(6,182,212,0.4)] hover:shadow-[0_0_60px_rgba(6,182,212,0.6)] flex flex-col items-center justify-center transition-all transform hover:scale-105 active:scale-95 border-4 border-slate-900/50 relative overflow-hidden"
                                    >
                                        <div className="absolute inset-0 bg-white/10 animate-pulse rounded-full"></div>
                                        <Dice5 size={48} className="text-white mb-2 group-hover:rotate-180 transition-transform duration-500 relative z-10"/>
                                        <span className="font-bold text-white tracking-widest relative z-10">{t.roll}</span>
                                        <span className="text-[9px] text-cyan-100 opacity-70 mt-1 relative z-10 uppercase flex items-center gap-1">
                                            <Vibrate size={10}/> {t.clickToRoll}
                                        </span>
                                    </button>
                                )
                            ) : (
                                <div className="text-center text-slate-500 animate-pulse">
                                    <Ship size={32} className="mx-auto mb-2"/>
                                    Sailing...
                                </div>
                            )}

                        </div>

                        {/* Bottom Nav Simulation */}
                        <div className="h-1 bg-slate-800 mx-auto w-1/3 mb-2 rounded-full"></div>
                    </div>
                </div>
            </div>

        </div>

        <style>{`
          @keyframes width { 0% { width: 0%; } 100% { width: 100%; } }
          .animate-fade-in { animation: fadeIn 0.5s ease-out forwards; }
          @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
        `}</style>
    </div>
  );
}

