    const addPlayer = () => {
        if (players.length >= 4) return;
        setPlayers([...players, {
            id: players.length,
            name: `Player ${players.length + 1}`,
            color: ["bg-green-500", "bg-purple-500", "bg-pink-500"][players.length - 2] || "bg-slate-500",
            position: 0, money: START_MONEY, hunger: 0, karma: 0, isJailed: false, inventory: [], isAi: true, boatType: 'DINGHY'
        }]);
    };

    return (
        <div className="min-h-screen flex items-center justify-center bg-slate-900 p-4">
            <div className="glass-panel p-8 rounded-3xl max-w-4xl w-full">
                <h1 className="text-4xl font-serif text-cyan-400 mb-8 text-center">MAÍGREIFINN LOBBY</h1>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-8">
                    {players.map((p, i) => (
                        <div key={i} className="bg-white/5 p-4 rounded-xl flex items-center gap-4 border border-white/10">
                            <div className={`w-12 h-12 rounded-full ${p.color} flex items-center justify-center`}>
                                <User size={24}/>
                            </div>
                            <div className="flex-1">
                                <input 
                                    value={p.name} 
                                    onChange={(e) => setPlayers(prev => prev.map(pl => pl.id === p.id ? { ...pl, name: e.target.value } : pl))}
                                    className="bg-transparent border-b border-white/20 w-full text-lg focus:outline-none focus:border-cyan-400"
                                />
                                <div className="text-xs text-slate-500 mt-1">{p.isAi ? "AI Controlled" : "Human Player"}</div>
                            </div>
                            <button onClick={() => setPlayers(prev => prev.map(pl => pl.id === p.id ? { ...pl, isAi: !pl.isAi } : pl))} className="p-2 hover:bg-white/10 rounded">
                                {p.isAi ? <Bot size={20}/> : <Smartphone size={20}/>}
                            </button>
                        </div>
                    ))}
                    {players.length < 4 && (
                        <button onClick={addPlayer} className="border-2 border-dashed border-white/10 rounded-xl flex items-center justify-center text-slate-500 hover:text-white hover:border-white/30 transition-all p-4">
                            + Add Captain
                        </button>
                    )}
                </div>
                <button onClick={onStart} className="w-full py-4 bg-cyan-600 hover:bg-cyan-500 rounded-xl font-bold text-white text-xl tracking-widest shadow-lg shadow-cyan-900/50 transition-all">
                    START VOYAGE
                </button>
            </div>
        </div>
    );
};

