const BoardCell = ({ space, players }: { space: BoardSpace, players: Player[] }) => {
    const playersHere = players.filter(p => p.position === space.id);

    // Styling for Corner Squares
    const isCorner = ['START', 'JAIL', 'GO_TO_JAIL', 'FREE_PARKING'].includes(space.type);
    const cornerStyle = isCorner ? "border-2 border-white/30 bg-white/5" : "border border-white/10 bg-black/40";

    return (
        <div className={`relative flex-1 rounded-lg ${cornerStyle} backdrop-blur-sm overflow-hidden group`}>
            {/* Background Image */}
            <div className="absolute inset-0 opacity-50 group-hover:opacity-70 transition-opacity">
                <img 
                    src={space.imageUrl || PREMADE_IMAGES.START} 
                    className="w-full h-full object-cover grayscale group-hover:grayscale-0 transition-all duration-700"
                    onError={(e) => {
                        (e.target as HTMLImageElement).src = PREMADE_IMAGES.START; // Fallback
                    }}
                />
                <div className={`absolute inset-0 bg-gradient-to-t ${isCorner ? 'from-slate-900/80 via-transparent' : 'from-slate-950 via-slate-950/20 to-transparent'}`}></div>
            </div>

            {/* Content */}
            <div className="relative z-10 h-full p-2 flex flex-col justify-between">
                <div className="flex justify-between items-start">
                    <span className={`text-[9px] font-bold px-1.5 py-0.5 rounded bg-black/60 backdrop-blur ${
                        space.type === 'BOAT' ? 'text-cyan-300' : 
                        space.type === 'RESTAURANT' ? 'text-amber-300' : 
                        space.type === 'JAIL' || space.type === 'GO_TO_JAIL' ? 'text-red-400' : 
                        isCorner ? 'text-white' : 'text-slate-300'
                    }`}>{space.name}</span>

                    {space.owner !== undefined && space.owner !== null && (
                        <div className={`w-3 h-3 rounded-full ${players[space.owner].color} border border-white shadow`}></div>
                    )}
                </div>

                {isCorner && (
                    <div className="absolute inset-0 flex items-center justify-center opacity-30 pointer-events-none">
                         {space.type === 'START' && <Anchor size={32}/>}
                         {space.type === 'JAIL' && <AlertTriangle size={32}/>}
                         {space.type === 'FREE_PARKING' && <Waves size={32}/>}
                         {space.type === 'GO_TO_JAIL' && <GavelIcon size={32}/>}
                    </div>
                )}

                {/* Players Grid - ensuring high visibility */}
                <div className="flex flex-wrap gap-1 justify-center items-end min-h-[1.5rem] mt-auto pointer-events-none">
                    {playersHere.map(p => (
                        <div key={p.id} className={`w-8 h-8 rounded-full ${p.color} border-2 border-white shadow-[0_0_10px_rgba(255,255,255,0.5)] flex items-center justify-center transform hover:scale-125 transition-transform z-20 relative -ml-2 first:ml-0 overflow-hidden`}>
                            {p.portraitUrl ? (
                                <img src={p.portraitUrl} className="w-full h-full object-cover" />
                            ) : (
                                <span className="font-bold text-[10px] text-white/90 drop-shadow-md">{p.name.substring(0,2).toUpperCase()}</span>
                            )}
                        </div>
                    ))}
                </div>
            </div>
        </div>
    );
};

