// --- Lobby Component ---

const Lobby = ({ players, setPlayers, onStart, onResume, hasSave, onClearSave }: { players: Player[], setPlayers: React.Dispatch<React.SetStateAction<Player[]>>, onStart: () => void, onResume: () => void, hasSave: boolean, onClearSave: () => void }) => {
    const [generatingIds, setGeneratingIds] = useState<number[]>([]);
    const t = T['IS']; // Use Icelandic default for lobby

    const addPlayer = () => {
        if (players.length >= 4) return;
        setPlayers([...players, {
            id: players.length,
            name: `Player ${players.length + 1}`,
            color: ["bg-green-500", "bg-purple-500", "bg-pink-500"][players.length - 2] || "bg-slate-500",
            position: 0, money: START_MONEY, hunger: 0, karma: 0, isJailed: false, inventory: [], isAi: true, boatType: 'DINGHY'
        }]);
    };

    const generatePortrait = async (player: Player) => {
        if (generatingIds.includes(player.id)) return;

        setGeneratingIds(prev => [...prev, player.id]);
        try {
            const ai = getAi();
            // More aggressive/gritty prompt for cooler avatars
            const prompt = `Hyper-realistic close-up portrait of a gritty Icelandic sea captain named ${player.name}, sitting in a dark ${player.boatType} cabin. 
            Weather-beaten face, intense eyes, traditional wool sweater (lopapeysa), rain droplets on face. 
            Cinematic lighting, Rembrandt style, 8k resolution, highly detailed texture.`;

            // Using flash-image for speed
            const res = await withRetry(() => ai.models.generateContent({
                model: 'gemini-2.5-flash-image',
                contents: { parts: [{ text: prompt }] }
            }));

            const imgData = res.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
            if (imgData) {
                const url = `data:image/png;base64,${imgData}`;
                setPlayers(prev => prev.map(p => p.id === player.id ? { ...p, portraitUrl: url } : p));
            }
        } catch (e) {
            console.error("Portrait gen failed", e);
        } finally {
            setGeneratingIds(prev => prev.filter(id => id !== player.id));
        }
    };

    return (
        <div className="min-h-screen flex items-center justify-center bg-slate-900 p-4 relative overflow-hidden">
             <div className="absolute inset-0 z-0 opacity-20 bg-[url('https://images.unsplash.com/photo-1464660439080-b79116909ce7?w=1200')] bg-cover bg-center"></div>

            <div className="glass-panel p-8 rounded-3xl max-w-4xl w-full relative z-10">
                <h1 className="text-4xl font-serif text-cyan-400 mb-8 text-center tracking-widest">MAÍGREIFINN LOBBY</h1>

                {/* Save Game Controls */}
                {hasSave && (
                    <div className="mb-6 p-4 bg-amber-900/30 border border-amber-500/30 rounded-xl flex items-center justify-between">
                         <div className="flex items-center gap-3">
                             <Save className="text-amber-400" size={20}/>
                             <div>
                                 <div className="font-bold text-amber-200">{t.saved}</div>
                                 <div className="text-xs text-amber-400/70">Previous voyage data found</div>
                             </div>
                         </div>
                         <div className="flex gap-2">
                             <button onClick={onClearSave} className="px-3 py-2 text-xs hover:bg-red-500/20 text-red-300 rounded-lg flex items-center gap-1 transition-colors">
                                 <Trash2 size={14}/> {t.reset_save}
                             </button>
                             <button onClick={onResume} className="px-6 py-2 bg-amber-600 hover:bg-amber-500 text-white font-bold rounded-lg shadow-lg shadow-amber-900/50 flex items-center gap-2 transition-transform hover:scale-105">
                                 <Play size={16} fill="currentColor"/> {t.resume}
                             </button>
                         </div>
                    </div>
                )}

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-8">
                    {players.map((p, i) => (
                        <div key={i} className="bg-white/5 p-4 rounded-xl flex items-center gap-4 border border-white/10 relative group hover:border-cyan-500/30 transition-all">

                            {/* Avatar Section */}
                            <div className="relative">
                                <div className={`w-16 h-16 rounded-full ${p.color} flex items-center justify-center overflow-hidden border-2 border-white/20 shadow-lg`}>
                                    {generatingIds.includes(p.id) ? (
                                        <Loader2 className="animate-spin text-white" size={24}/>
                                    ) : p.portraitUrl ? (
                                        <img src={p.portraitUrl} className="w-full h-full object-cover" />
                                    ) : (
                                        <User size={28} className="text-white/50"/>
                                    )}
                                </div>
                                {/* Generate Button (Magic Wand/Sparkles) */}
                                <button 
                                    onClick={() => generatePortrait(p)}
                                    disabled={generatingIds.includes(p.id)}
                                    className="absolute -bottom-1 -right-1 bg-cyan-500 hover:bg-cyan-400 text-white p-1.5 rounded-full shadow-lg transition-transform hover:scale-110 active:scale-95 disabled:opacity-50"
                                    title="Generate AI Portrait"
                                >
                                    <Sparkles size={12} fill="currentColor" />
                                </button>
                            </div>

                            <div className="flex-1">
                                <input 
                                    value={p.name} 
                                    onChange={(e) => setPlayers(prev => prev.map(pl => pl.id === p.id ? { ...pl, name: e.target.value } : pl))}
                                    className="bg-transparent border-b border-white/20 w-full text-lg focus:outline-none focus:border-cyan-400 font-bold tracking-wide"
                                    placeholder="Captain Name"
                                />
                                <div className="flex items-center gap-2 mt-2">
                                    <button 
                                        onClick={() => setPlayers(prev => prev.map(pl => pl.id === p.id ? { ...pl, isAi: !pl.isAi } : pl))} 
                                        className={`text-xs px-2 py-1 rounded border ${p.isAi ? 'bg-cyan-900/50 border-cyan-500 text-cyan-200' : 'bg-slate-800 border-slate-600 text-slate-400'} flex items-center gap-1 transition-all`}
                                    >
                                        {p.isAi ? <Bot size={12}/> : <Smartphone size={12}/>}
                                        {p.isAi ? "AI AUTOPILOT" : "HUMAN"}
                                    </button>

                                    <select 
                                        value={p.boatType}
                                        onChange={(e) => setPlayers(prev => prev.map(pl => pl.id === p.id ? { ...pl, boatType: e.target.value as BoatType } : pl))}
                                        className="bg-slate-800 text-xs px-2 py-1 rounded border border-slate-600 text-slate-300 outline-none"
                                    >
                                        <option value="TRAWLER">TRAWLER</option>
                                        <option value="SAILBOAT">SAILBOAT</option>
                                        <option value="DINGHY">DINGHY</option>
                                        <option value="YACHT">YACHT</option>
                                    </select>
                                </div>
                            </div>
                        </div>
                    ))}
                    {players.length < 4 && (
                        <button onClick={addPlayer} className="border-2 border-dashed border-white/10 rounded-xl flex items-center justify-center text-slate-500 hover:text-white hover:border-white/30 transition-all p-4 min-h-[100px]">
                            + Add Captain
                        </button>
                    )}
                </div>

                <div className="flex flex-col gap-3">
                    <button onClick={onStart} className="w-full py-4 bg-gradient-to-r from-cyan-600 to-blue-600 hover:from-cyan-500 hover:to-blue-500 rounded-xl font-bold text-white text-xl tracking-[0.2em] shadow-lg shadow-cyan-900/50 transition-all flex items-center justify-center gap-2 group">
                        <Ship size={24} className="group-hover:animate-bounce"/>
                        {t.new_game}
                    </button>
                    {hasSave && (
                        <div className="text-center text-xs text-slate-500">
                            Starting a new game will overwrite existing save data.
                        </div>
                    )}
                </div>

                {/* Note for reviewers/developers */}
                <div className="mt-4 text-center text-[10px] text-slate-500 font-mono">
                    System ready. WebSockets disconnected. Local state active.
                </div>
            </div>
        </div>
    );
};

const root = createRoot(document.getElementById('root')!);
root.render(<App />);

import React, { useState, useEffect, useRef } from 'react';
import { createRoot } from 'react-dom/client';
import { GoogleGenAI } from "@google/genai";
import { Ship, Anchor, Fish, Coins, User, Waves, Bot, Play, Sparkles, AlertTriangle, X, ScrollText, Save, Trash2, ArrowRight, ShoppingCart, Map, DollarSign, Search, Calendar, Briefcase, FileText } from 'lucide-react';

// --- Configuration ---

const START_MONEY = 500000;
const DEPTH_METER_COST = 5000;
const SAVE_KEY = 'maigreifinn_1960_v1';

// Parody Names & Data
const COMPANY_NAMES = [
  "Brimverzlun hf.", "Hafdráttur h/f", "Togglarinn ehf.", "Sjómannafélagið Víkingur",
  "Útgerðarfélag Akureyrar", "Fiskvinnslan Alda", "Norðurljósavinnslan", "Vestfjarða-Skel hf."
];

const SHIP_NAMES = [
  "MS Brimrós", "MS Togglari", "MS Djúpvera", "Guðrún Björg", "Sæljónið", 
  "Haförninn", "Sjöstjarnan", "Kjölurinn", "Aldan", "Vonin"
];

const EVENTS = [
  { id: 'investigation', title: "Rannsóknarnefnd", text: "Hættuspil! Rannsóknarnefnd sjávarútvegsins mætir á svæðið.", effect: { money: 0, rep: -3 }, type: 'BAD' },
  { id: 'bank', title: "Bankinn hringir", text: "Útvegsspils-andi svífur yfir vötnum. Bankastjórinn vill sitt.", effect: { money: -25000, rep: 0 }, type: 'BAD' },
  { id: 'tire', title: "Rallýspil", text: "Dekkið springur á bryggjubílnum! Tafir við löndun.", effect: { money: -5000, rep: 0 }, type: 'BAD' },
  { id: 'play', title: "Aktjóneri", text: "Leikritið í höfninni slær í gegn. Allir kátir.", effect: { money: 5000, rep: 2 }, type: 'GOOD' },
  { id: 'omar', title: "Ómar-style", text: "„Þetta reddast“. Bjartsýni skilar sér í kassan.", effect: { money: 15000, rep: 1 }, type: 'GOOD' }
];

const MARKET_SHIPS = [
  { id: 1, name: "Trilla (Opinn)", type: 'TRILLA', price: 50000, capacity: 5, upkeep: 1000 },
  { id: 2, name: "Kvótakóngur", type: 'TRAWLER', price: 150000, capacity: 15, upkeep: 5000 },
  { id: 3, name: "MS Togglari", type: 'TRAWLER', price: 300000, capacity: 30, upkeep: 10000 },
  { id: 4, name: "Gullskipið", type: 'YACHT', price: 1000000, capacity: 50, upkeep: 25000 },
];

// --- Types ---

type GameView = 'TITLE' | 'HQ' | 'MARKET' | 'FISHING';

interface ShipItem {
  id: string; // Unique ID
  modelId: number;
  name: string;
  type: string;
  condition: number; // 0-100%
  equipped: boolean; // Has depth meter?
}

interface LogEntry {
  id: number;
  season: string;
  year: number;
  text: string;
  type: 'INFO' | 'MONEY' | 'ALERT' | 'EVENT';
}

interface FishingTile {
  id: number;
  status: 'HIDDEN' | 'REVEALED';
  content: 'FISH' | 'EMPTY' | 'DANGER' | 'BIG_CATCH';
  value: number;
}

// --- Helpers ---

const getAi = () => new GoogleGenAI({ apiKey: process.env.API_KEY });
const getRandomSeason = (year: number) => {
    const seasons = ["Vor", "Sumar", "Haust", "Vetur"];
    return `${seasons[Math.floor(Math.random() * seasons.length)]} ${year}`;
};

// --- Main Component ---

function App() {
  // State
  const [view, setView] = useState<GameView>('TITLE');
  const [companyName, setCompanyName] = useState("");
  const [money, setMoney] = useState(START_MONEY);
  const [ships, setShips] = useState<ShipItem[]>([]);
  const [year, setYear] = useState(1955);
  const [logs, setLogs] = useState<LogEntry[]>([]);

  // Fishing State
  const [fishingGrid, setFishingGrid] = useState<FishingTile[]>([]);
  const [selectedShipId, setSelectedShipId] = useState<string | null>(null);
  const [currentCatch, setCurrentCatch] = useState(0);

  // Initialize
  useEffect(() => {
    const saved = localStorage.getItem(SAVE_KEY);
    if (saved) {
      try {
        const data = JSON.parse(saved);
        setCompanyName(data.companyName);
        setMoney(data.money);
        setShips(data.ships);
        setYear(data.year);
        setLogs(data.logs);
        // If we have data, go to HQ, else stay TITLE
        if (data.companyName) setView('HQ');
      } catch(e) {}
    }
  }, []);

  // Autosave
  useEffect(() => {
    if (view !== 'TITLE') {
       const timer = setTimeout(() => {
          localStorage.setItem(SAVE_KEY, JSON.stringify({ companyName, money, ships, year, logs }));
       }, 1000);
       return () => clearTimeout(timer);
    }
  }, [companyName, money, ships, year, logs, view]);

  const addLog = (text: string, type: LogEntry['type'] = 'INFO') => {
      setLogs(prev => [{
          id: Date.now(),
          season: getRandomSeason(year),
          year: year,
          text,
          type
      }, ...prev]);
  };

  const handleStartGame = () => {
      if (!companyName) {
          setCompanyName(COMPANY_NAMES[Math.floor(Math.random() * COMPANY_NAMES.length)]);
      }
      addLog(`Útgerðin ${companyName || 'Nafnlaus'} stofnuð.`, 'INFO');
      setView('HQ');
  };

  const handleBuyShip = (shipModel: typeof MARKET_SHIPS[0]) => {
      if (money >= shipModel.price) {
          setMoney(m => m - shipModel.price);
          const newShip: ShipItem = {
              id: Date.now().toString(),
              modelId: shipModel.id,
              name: SHIP_NAMES[Math.floor(Math.random() * SHIP_NAMES.length)] + ` ${Math.floor(Math.random() * 100)}`,
              type: shipModel.type,
              condition: 100,
              equipped: false
          };
          setShips(prev => [...prev, newShip]);
          addLog(`Keypti ${newShip.name} (${shipModel.name}) fyrir ${shipModel.price.toLocaleString()} kr.`, 'MONEY');
      } else {
          // Shake effect or alert could go here
      }
  };

  const startFishing = (shipId: string) => {
      setSelectedShipId(shipId);
      // Generate Grid
      const newGrid: FishingTile[] = Array(9).fill(null).map((_, i) => {
          const rand = Math.random();
          let content: FishingTile['content'] = 'EMPTY';
          let value = 0;

          if (rand > 0.7) { content = 'FISH'; value = 50000; }
          else if (rand > 0.9) { content = 'BIG_CATCH'; value = 150000; }
          else if (rand < 0.1) { content = 'DANGER'; value = -10000; }

          return { id: i, status: 'HIDDEN', content, value };
      });
      setFishingGrid(newGrid);
      setCurrentCatch(0);
      setView('FISHING');
      addLog(`Hélt til veiða á ${ships.find(s => s.id === shipId)?.name}.`, 'INFO');
  };

  const useDepthMeter = () => {
      if (money >= DEPTH_METER_COST) {
          setMoney(m => m - DEPTH_METER_COST);
          // Find unrevealed tiles
          const hidden = fishingGrid.filter(t => t.status === 'HIDDEN');
          if (hidden.length > 0) {
              const target = hidden[Math.floor(Math.random() * hidden.length)];
              setFishingGrid(prev => prev.map(t => t.id === target.id ? { ...t, status: 'REVEALED' } : t));
          }
      }
  };

  const fishTile = (tile: FishingTile) => {
      if (tile.status === 'REVEALED' && (tile.content === 'EMPTY' || tile.content === 'DANGER')) {
          // Already known bad tile, do nothing or force fish? 
          // Let's assume you click to fish.
      }

      const updatedGrid = fishingGrid.map(t => t.id === tile.id ? { ...t, status: 'REVEALED' as const } : t);
      setFishingGrid(updatedGrid);

      if (tile.content === 'DANGER') {
          addLog("Hætta! Netin festust eða veður versnaði.", 'ALERT');
          setCurrentCatch(c => c - 5000);
      } else if (tile.content === 'FISH' || tile.content === 'BIG_CATCH') {
          setCurrentCatch(c => c + tile.value);
      }

      // Check if all fished? Or just end manually.
  };

  const endFishing = () => {
      // Payout
      setMoney(m => m + currentCatch);
      addLog(`Löndun: ${currentCatch.toLocaleString()} kr. komu í kassann.`, 'MONEY');

      // 20% Chance of Event
      if (Math.random() < 0.2) {
          const event = EVENTS[Math.floor(Math.random() * EVENTS.length)];
          addLog(event.text, 'EVENT');
          setMoney(m => m + event.effect.money);
          // Could handle reputation later
      }

      setYear(y => y + 1); // Time passes
      setView('HQ');
  };

  // --- Views ---

  if (view === 'TITLE') {
      return (
          <div className="min-h-screen flex flex-col items-center justify-center p-4 bg-[#f6f1e1] relative">
              <div className="absolute inset-0 border-[20px] border-[#3e2723] opacity-10 pointer-events-none"></div>

              <div className="max-w-lg w-full text-center space-y-8">
                  <div className="space-y-2">
                      <h1 className="text-6xl font-header text-[#3e2723] tracking-widest drop-shadow-sm">MAÍ GREIFINN</h1>
                      <div className="text-xl font-serif italic text-[#5d4037]">- Útvegsspilið 1960 -</div>
                  </div>

                  <div className="paper-card p-8 rounded-sm transform rotate-1">
                      <label className="block text-left font-bold text-[#3e2723] mb-2 font-header">NAFN ÚTGERÐAR</label>
                      <input 
                          type="text" 
                          value={companyName}
                          onChange={(e) => setCompanyName(e.target.value)}
                          placeholder="t.d. Brimverzlun hf."
                          className="w-full bg-[#f0ebe0] border-b-2 border-[#3e2723] p-2 font-typewriter text-xl focus:outline-none placeholder-[#a1887f]"
                      />
                      <div className="text-left mt-2 text-xs text-[#5d4037] font-serif italic">
                          Ábending: Prófaðu nöfn eins og „Hafdráttur h/f“ eða „Ísbjörninn“.
                      </div>
                  </div>

                  <button 
                      onClick={handleStartGame}
                      className="btn-paper px-8 py-4 text-xl w-full hover:scale-[1.02] transition-transform flex items-center justify-center gap-3"
                  >
                      <Anchor size={24}/> Hefja Útgerð
                  </button>
              </div>
          </div>
      );
  }

  // HEADER COMPONENT (Shared)
  const Header = () => (
      <header className="bg-[#3e2723] text-[#f6f1e1] p-4 border-b-4 border-[#8d6e63] shadow-lg sticky top-0 z-50 flex justify-between items-center">
          <div className="flex items-center gap-4">
              <div className="w-12 h-12 bg-[#f6f1e1] rounded-full flex items-center justify-center text-[#3e2723] border-2 border-[#8d6e63]">
                  <Anchor size={24}/>
              </div>
              <div>
                  <h2 className="font-header text-xl tracking-wide leading-none">{companyName}</h2>
                  <div className="text-xs text-[#d7ccc8] font-typewriter mt-1">Stofnað 1955</div>
              </div>
          </div>
          <div className="flex items-center gap-6">
              <div className="text-right">
                  <div className="text-xs text-[#a1887f] uppercase">Sjóður</div>
                  <div className="font-typewriter text-xl text-[#ffecb3]">{money.toLocaleString()} kr.</div>
              </div>
              <div className="text-right hidden sm:block">
                  <div className="text-xs text-[#a1887f] uppercase">Ár</div>
                  <div className="font-header text-xl">{year}</div>
              </div>
          </div>
      </header>
  );

  if (view === 'HQ') {
      return (
          <div className="min-h-screen pb-12">
              <Header />

              <main className="max-w-6xl mx-auto p-6 grid grid-cols-1 md:grid-cols-3 gap-6">

                  {/* Left Column: Fleet */}
                  <div className="md:col-span-2 space-y-6">
                      <div className="flex justify-between items-end border-b-2 border-[#3e2723] pb-2 mb-4">
                          <h3 className="font-header text-2xl text-[#3e2723] flex items-center gap-2">
                              <Ship className="text-[#5d4037]"/> Flotinn
                          </h3>
                          <button onClick={() => setView('MARKET')} className="btn-paper px-4 py-2 text-sm flex items-center gap-2 bg-[#e3f2fd] border-[#1e88e5] text-[#0d47a1]">
                              <ShoppingCart size={14}/> Skipamarkaður
                          </button>
                      </div>

                      {ships.length === 0 ? (
                          <div className="paper-card p-8 text-center text-[#8d6e63] italic">
                              Engin skip í flota. Farðu á markaðinn til að hefja rekstur.
                          </div>
                      ) : (
                          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                              {ships.map(ship => (
                                  <div key={ship.id} className="paper-card p-4 relative group">
                                      <div className="absolute top-2 right-2 text-xs font-bold text-[#8d6e63] font-typewriter">
                                          {ship.type}
                                      </div>
                                      <h4 className="font-header text-lg font-bold text-[#3e2723] mb-1">{ship.name}</h4>
                                      <div className="h-px bg-[#d7ccc8] w-full mb-3"></div>

                                      <div className="flex justify-between items-center mt-4">
                                          <div className="text-xs text-[#5d4037]">Ástand: {ship.condition}%</div>
                                          <button 
                                              onClick={() => startFishing(ship.id)}
                                              className="btn-paper px-3 py-1.5 text-xs bg-[#e8f5e9] border-[#2e7d32] text-[#1b5e20] flex items-center gap-1 hover:scale-105 transition-transform"
                                          >
                                              <Waves size={12}/> Fara á sjó
                                          </button>
                                      </div>
                                  </div>
                              ))}
                          </div>
                      )}
                  </div>

                  {/* Right Column: Logbook */}
                  <div className="space-y-4">
                       <div className="flex items-center justify-between border-b-2 border-[#3e2723] pb-2">
                          <h3 className="font-header text-xl text-[#3e2723] flex items-center gap-2">
                              <FileText className="text-[#5d4037]"/> Dagbók
                          </h3>
                       </div>

                       <div className="paper-card p-4 min-h-[400px] max-h-[600px] overflow-y-auto font-typewriter text-sm space-y-4 bg-[#fffdf5]">
                           {logs.length === 0 && <div className="text-center opacity-50 italic pt-10">Bókin er auð...</div>}
                           {logs.map(log => (
                               <div key={log.id} className="border-b border-[#ece0d1] pb-2 last:border-0">
                                   <div className="text-[10px] text-[#8d6e63] uppercase tracking-wider mb-1">
                                       {log.season}
                                   </div>
                                   <div className={`${
                                       log.type === 'MONEY' ? 'text-[#1b5e20]' : 
                                       log.type === 'ALERT' ? 'text-[#b71c1c]' : 
                                       log.type === 'EVENT' ? 'text-[#e65100] font-bold' : 'text-[#3e2723]'
                                   }`}>
                                       {log.text}
                                   </div>
                               </div>
                           ))}
                       </div>
                  </div>

              </main>
          </div>
      );
  }

  if (view === 'MARKET') {
      return (
          <div className="min-h-screen pb-12">
              <Header />
              <main className="max-w-4xl mx-auto p-6">
                  <div className="flex items-center gap-4 mb-6">
                      <button onClick={() => setView('HQ')} className="btn-paper p-2 rounded-full">
                          <ArrowRight className="rotate-180" size={20}/>
                      </button>
                      <h2 className="font-header text-3xl text-[#0d47a1]">SKIPAMARKAÐUR</h2>
                  </div>

                  <div className="space-y-4">
                      {MARKET_SHIPS.map(model => (
                          <div key={model.id} className="paper-card p-6 flex flex-col sm:flex-row items-center gap-6">
                              <div className="w-32 h-24 bg-[#e3f2fd] border border-[#90caf9] flex items-center justify-center text-[#1565c0]">
                                  <Ship size={48} strokeWidth={1}/>
                              </div>
                              <div className="flex-1 text-center sm:text-left">
                                  <h3 className="font-header text-xl font-bold">{model.name}</h3>
                                  <div className="text-sm text-[#5d4037] font-typewriter mt-1">
                                      Burðargeta: {model.capacity} tonn | Viðhald: {model.upkeep} kr/ár
                                  </div>
                              </div>
                              <div className="text-right">
                                  <div className="font-header text-2xl text-[#3e2723] mb-2">{model.price.toLocaleString()} kr.</div>
                                  <button 
                                      onClick={() => handleBuyShip(model)}
                                      disabled={money < model.price}
                                      className="btn-paper w-full py-2 bg-[#0d47a1] text-white border-[#002171] disabled:opacity-50 disabled:cursor-not-allowed"
                                  >
                                      KAUPA
                                  </button>
                              </div>
                          </div>
                      ))}
                  </div>
              </main>
          </div>
      );
  }

  if (view === 'FISHING') {
      return (
          <div className="min-h-screen bg-[#001020] relative text-[#f6f1e1]">
              <div className="absolute inset-0 opacity-20 bg-[url('https://www.transparenttextures.com/patterns/nautical-leather.png')]"></div>

              <div className="relative z-10 max-w-2xl mx-auto p-6 flex flex-col h-screen">

                  {/* Fishing Header */}
                  <div className="flex justify-between items-center mb-8 bg-[#3e2723] p-4 border-2 border-[#8d6e63] rounded-sm shadow-xl">
                      <div>
                          <h2 className="font-header text-xl text-[#ffecb3]">Á VEIÐUM</h2>
                          <div className="text-xs text-[#d7ccc8]">{ships.find(s => s.id === selectedShipId)?.name}</div>
                      </div>
                      <div className="text-right">
                          <div className="text-xs text-[#a1887f]">Afli í lest</div>
                          <div className="font-typewriter text-2xl text-[#81c784]">{currentCatch.toLocaleString()} kr.</div>
                      </div>
                  </div>

                  {/* Grid */}
                  <div className="flex-1 flex items-center justify-center">
                      <div className="grid grid-cols-3 gap-3 w-full max-w-md aspect-square">
                          {fishingGrid.map((tile) => (
                              <button
                                  key={tile.id}
                                  onClick={() => fishTile(tile)}
                                  disabled={tile.status === 'REVEALED'}
                                  className={`relative rounded-sm border-2 transition-all duration-500 overflow-hidden ${
                                      tile.status === 'HIDDEN' 
                                      ? 'bg-[#0d47a1] border-[#1565c0] hover:bg-[#1565c0]' 
                                      : 'bg-[#f6f1e1] border-[#8d6e63]'
                                  }`}
                              >
                                  {tile.status === 'HIDDEN' ? (
                                      <div className="absolute inset-0 flex items-center justify-center opacity-20">
                                          <Waves size={32} className="text-white animate-pulse"/>
                                      </div>
                                  ) : (
                                      <div className="flex flex-col items-center justify-center h-full animate-[fadeIn_0.5s]">
                                          {tile.content === 'EMPTY' && <div className="text-[#a1887f] font-typewriter text-xs">Tómt</div>}
                                          {tile.content === 'FISH' && <Fish size={32} className="text-[#1b5e20] mb-1"/>}
                                          {tile.content === 'BIG_CATCH' && <div className="text-[#f57f17]"><Fish size={40}/><Sparkles size={16} className="absolute top-2 right-2"/></div>}
                                          {tile.content === 'DANGER' && <AlertTriangle size={32} className="text-[#b71c1c]"/>}

                                          {tile.value !== 0 && (
                                              <div className={`text-xs font-bold mt-1 ${tile.value > 0 ? 'text-[#1b5e20]' : 'text-[#b71c1c]'}`}>
                                                  {tile.value > 0 ? '+' : ''}{tile.value.toLocaleString()}
                                              </div>
                                          )}
                                      </div>
                                  )}
                              </button>
                          ))}
                      </div>
                  </div>

                  {/* Controls */}
                  <div className="mt-8 space-y-4">
                      <div className="flex gap-4">
                          <button 
                              onClick={useDepthMeter}
                              disabled={money < DEPTH_METER_COST}
                              className="flex-1 btn-paper py-4 bg-[#263238] border-[#37474f] text-[#eceff1] flex flex-col items-center justify-center gap-1 hover:bg-[#37474f] disabled:opacity-50"
                          >
                              <div className="flex items-center gap-2">
                                  <Search size={18} /> DÝPTARMÆLIR
                              </div>
                              <div className="text-[10px] text-[#b0bec5]">-5.000 kr. / notkun</div>
                          </button>

                          <button 
                              onClick={endFishing}
                              className="flex-1 btn-paper py-4 bg-[#1b5e20] border-[#2e7d32] text-white flex flex-col items-center justify-center gap-1 hover:bg-[#2e7d32]"
                          >
                              <div className="flex items-center gap-2">
                                  <Anchor size={18} /> LANDA & HEIM
                              </div>
                              <div className="text-[10px] text-[#a5d6a7]">Ljúka veiðiferð</div>
                          </button>
                      </div>
                  </div>

              </div>
          </div>
      );
  }

  return null;
}

const root = createRoot(document.getElementById('root')!);
root.render(<App />);

import React, { useState, useEffect, useRef } from 'react';
import { createRoot } from 'react-dom/client';
import { Ship, Anchor, Fish, Coins, User, Waves, Bot, Play, Sparkles, AlertTriangle, X, ScrollText, Save, Trash2, ArrowRight, ShoppingCart, Map, DollarSign, Search, Calendar, Briefcase, FileText, Wrench } from 'lucide-react';

// --- Configuration ---

const START_MONEY = 500000;
const DEPTH_METER_COST = 5000;
const SAVE_KEY = 'maigreifinn_1960_v2';
const SEASONS = ["Vor", "Sumar", "Haust", "Vetur"];

// Parody Names & Data
const COMPANY_NAMES = [
  "Brimverzlun hf.", "Hafdráttur h/f", "Togglarinn ehf.", "Sjómannafélagið Víkingur",
  "Útgerðarfélag Akureyrar", "Fiskvinnslan Alda", "Norðurljósavinnslan", "Vestfjarða-Skel hf.",
  "Ísbjörninn hf.", "Skeljungur Útgerð"
];

const SHIP_NAMES = [
  "MS Brimrós", "MS Togglari", "MS Djúpvera", "Guðrún Björg", "Sæljónið", 
  "Haförninn", "Sjöstjarnan", "Kjölurinn", "Aldan", "Vonin"
];

type EventType = {
  id: string;
  title: string;
  text: string;
  type: 'BAD' | 'GOOD';
  effect: {
    money: number;
    rep: number;
    conditionDamage?: number; // New: Damage to random ship
  }
};

const EVENTS: EventType[] = [
  { id: 'investigation', title: "Rannsóknarnefnd", text: "☠️ Hættuspil! Rannsóknarnefnd sjávarútvegsins mætir á svæðið.", effect: { money: 0, rep: -3 }, type: 'BAD' },
  { id: 'bank', title: "Bankinn hringir", text: "🏦 Útvegsspils-andi svífur yfir vötnum. Bankastjórinn vill sitt.", effect: { money: -25000, rep: 0 }, type: 'BAD' },
  { id: 'tire', title: "Rallýspil", text: "🏁 Rallýspil! Dekkið springur á bryggjubílnum og varahlutir tefjast.", effect: { money: 0, rep: 0, conditionDamage: 10 }, type: 'BAD' },
  { id: 'play', title: "Aktjóneri", text: "🎭 Leikritið í höfninni slær í gegn. Allir kátir.", effect: { money: 5000, rep: 2 }, type: 'GOOD' },
  { id: 'omar', title: "Ómar-style", text: "📻 „Þetta reddast“. Bjartsýni skilar sér í kassan.", effect: { money: 15000, rep: 1 }, type: 'GOOD' }
];

const MARKET_SHIPS = [
  { id: 1, name: "Trilla (Opinn)", type: 'TRILLA', price: 50000, capacity: 5, upkeep: 1000 },
  { id: 2, name: "Kvótakóngur", type: 'TRAWLER', price: 150000, capacity: 15, upkeep: 5000 },
  { id: 3, name: "MS Togglari", type: 'TRAWLER', price: 300000, capacity: 30, upkeep: 10000 },
  { id: 4, name: "Gullskipið", type: 'YACHT', price: 1000000, capacity: 50, upkeep: 25000 },
];

// --- Types ---

type GameView = 'TITLE' | 'HQ' | 'MARKET' | 'FISHING';

interface ShipItem {
  id: string; // Unique ID
  modelId: number;
  name: string;
  type: string;
  condition: number; // 0-100%
  equipped: boolean; // Has depth meter?
}

interface LogEntry {
  id: number;
  timestamp: string; // "Vor 1955"
  text: string;
  type: 'INFO' | 'MONEY' | 'ALERT' | 'EVENT';
}

interface FishingTile {
  id: number;
  status: 'HIDDEN' | 'REVEALED';
  content: 'FISH' | 'EMPTY' | 'DANGER' | 'BIG_CATCH';
  value: number;
}

// --- Main Component ---

function App() {
  // State
  const [view, setView] = useState<GameView>('TITLE');
  const [companyName, setCompanyName] = useState("");
  const [money, setMoney] = useState(START_MONEY);
  const [ships, setShips] = useState<ShipItem[]>([]);

  // Time System
  const [year, setYear] = useState(1960);
  const [seasonIndex, setSeasonIndex] = useState(0); // 0=Vor, 1=Sumar, 2=Haust, 3=Vetur

  const [logs, setLogs] = useState<LogEntry[]>([]);

  // Fishing State
  const [fishingGrid, setFishingGrid] = useState<FishingTile[]>([]);
  const [selectedShipId, setSelectedShipId] = useState<string | null>(null);
  const [currentCatch, setCurrentCatch] = useState(0);

  // UI State
  const [randomHint, setRandomHint] = useState("");

  // Initialize
  useEffect(() => {
    setRandomHint(COMPANY_NAMES[Math.floor(Math.random() * COMPANY_NAMES.length)]);

    const saved = localStorage.getItem(SAVE_KEY);
    if (saved) {
      try {
        const data = JSON.parse(saved);
        setCompanyName(data.companyName);
        setMoney(data.money);
        setShips(data.ships);
        setYear(data.year);
        setSeasonIndex(data.seasonIndex || 0);
        setLogs(data.logs);
        if (data.companyName) setView('HQ');
      } catch(e) {}
    }
  }, []);

  // Autosave
  useEffect(() => {
    if (view !== 'TITLE') {
       const timer = setTimeout(() => {
          localStorage.setItem(SAVE_KEY, JSON.stringify({ companyName, money, ships, year, seasonIndex, logs }));
       }, 1000);
       return () => clearTimeout(timer);
    }
  }, [companyName, money, ships, year, seasonIndex, logs, view]);

  const getCurrentTimestamp = () => `${SEASONS[seasonIndex]} ${year}`;

  const addLog = (text: string, type: LogEntry['type'] = 'INFO') => {
      setLogs(prev => [{
          id: Date.now(),
          timestamp: getCurrentTimestamp(),
          text,
          type
      }, ...prev]);
  };

  const advanceTime = () => {
      setSeasonIndex(prev => {
          const next = prev + 1;
          if (next >= SEASONS.length) {
              setYear(y => y + 1);
              return 0;
          }
          return next;
      });
  };

  const handleStartGame = () => {
      if (!companyName) {
          setCompanyName(randomHint);
      }
      addLog(`Útgerðin ${companyName || randomHint} stofnuð.`, 'INFO');
      setView('HQ');
  };

  const handleBuyShip = (shipModel: typeof MARKET_SHIPS[0]) => {
      if (money >= shipModel.price) {
          setMoney(m => m - shipModel.price);
          const newShip: ShipItem = {
              id: Date.now().toString(),
              modelId: shipModel.id,
              name: SHIP_NAMES[Math.floor(Math.random() * SHIP_NAMES.length)] + ` ${Math.floor(Math.random() * 100)}`,
              type: shipModel.type,
              condition: 100,
              equipped: false
          };
          setShips(prev => [...prev, newShip]);
          addLog(`Keypti ${newShip.name} (${shipModel.name}) fyrir ${shipModel.price.toLocaleString()} kr.`, 'MONEY');
      }
  };

  const repairShip = (shipId: string) => {
      const ship = ships.find(s => s.id === shipId);
      if (!ship || ship.condition >= 100) return;

      const cost = (100 - ship.condition) * 500; // 500kr per 1%
      if (money >= cost) {
          setMoney(m => m - cost);
          setShips(prev => prev.map(s => s.id === shipId ? { ...s, condition: 100 } : s));
          addLog(`Gerði við ${ship.name} fyrir ${cost.toLocaleString()} kr.`, 'MONEY');
      }
  };

  const startFishing = (shipId: string) => {
      const ship = ships.find(s => s.id === shipId);
      if (ship && ship.condition < 20) {
          alert("Skip er í of slæmu ástandi til að fara á sjó! Gerðu við það fyrst.");
          return;
      }

      setSelectedShipId(shipId);
      // Generate Grid
      const newGrid: FishingTile[] = Array(9).fill(null).map((_, i) => {
          const rand = Math.random();
          let content: FishingTile['content'] = 'EMPTY';
          let value = 0;

          if (rand > 0.7) { content = 'FISH'; value = 50000; }
          else if (rand > 0.9) { content = 'BIG_CATCH'; value = 150000; }
          else if (rand < 0.1) { content = 'DANGER'; value = -10000; }

          return { id: i, status: 'HIDDEN', content, value };
      });
      setFishingGrid(newGrid);
      setCurrentCatch(0);
      setView('FISHING');
      addLog(`Hélt til veiða á ${ship?.name}.`, 'INFO');
  };

  const useDepthMeter = () => {
      if (money >= DEPTH_METER_COST) {
          setMoney(m => m - DEPTH_METER_COST);
          // Find unrevealed tiles
          const hidden = fishingGrid.filter(t => t.status === 'HIDDEN');
          if (hidden.length > 0) {
              const target = hidden[Math.floor(Math.random() * hidden.length)];
              setFishingGrid(prev => prev.map(t => t.id === target.id ? { ...t, status: 'REVEALED' } : t));
          }
      }
  };

  const fishTile = (tile: FishingTile) => {
      if (tile.status === 'REVEALED' && (tile.content === 'EMPTY' || tile.content === 'DANGER')) {
         // User decision to fish bad tiles usually results in nothing or damage
      }

      const updatedGrid = fishingGrid.map(t => t.id === tile.id ? { ...t, status: 'REVEALED' as const } : t);
      setFishingGrid(updatedGrid);

      if (tile.content === 'DANGER') {
          addLog("Hætta! Netin festust eða veður versnaði.", 'ALERT');
          setCurrentCatch(c => c - 5000);
          // Small damage on danger tiles
          setShips(prev => prev.map(s => s.id === selectedShipId ? { ...s, condition: Math.max(0, s.condition - 5) } : s));
      } else if (tile.content === 'FISH' || tile.content === 'BIG_CATCH') {
          setCurrentCatch(c => c + tile.value);
      }
  };

  const endFishing = () => {
      // Payout
      setMoney(m => m + currentCatch);
      addLog(`Löndun: ${currentCatch.toLocaleString()} kr. komu í kassann.`, 'MONEY');

      // Wear and tear (normal)
      setShips(prev => prev.map(s => s.id === selectedShipId ? { ...s, condition: Math.max(0, s.condition - 2) } : s));

      // 20% Chance of Event
      if (Math.random() < 0.2) {
          const event = EVENTS[Math.floor(Math.random() * EVENTS.length)];
          addLog(`${event.title}: ${event.text}`, 'EVENT');

          // Apply Money Effect
          if (event.effect.money !== 0) {
              setMoney(m => m + event.effect.money);
          }

          // Apply Condition Damage (Rallýspil)
          if (event.effect.conditionDamage && selectedShipId) {
              setShips(prev => prev.map(s => s.id === selectedShipId ? { 
                  ...s, 
                  condition: Math.max(0, s.condition - event.effect.conditionDamage!) 
              } : s));
          }
      }

      advanceTime();
      setView('HQ');
  };

  // --- Views ---

  if (view === 'TITLE') {
      return (
          <div className="min-h-screen flex flex-col items-center justify-center p-4 bg-[#f6f1e1] relative">
              <div className="absolute inset-0 border-[20px] border-[#3e2723] opacity-10 pointer-events-none"></div>

              <div className="max-w-lg w-full text-center space-y-8">
                  <div className="space-y-2">
                      <h1 className="text-6xl font-header text-[#3e2723] tracking-widest drop-shadow-sm">MAÍ GREIFINN</h1>
                      <div className="text-xl font-serif italic text-[#5d4037]">- Útvegsspilið 1960 -</div>
                  </div>

                  <div className="paper-card p-8 rounded-sm transform rotate-1">
                      <label className="block text-left font-bold text-[#3e2723] mb-2 font-header">NAFN ÚTGERÐAR</label>
                      <input 
                          type="text" 
                          value={companyName}
                          onChange={(e) => setCompanyName(e.target.value)}
                          placeholder={`t.d. ${randomHint}`}
                          className="w-full bg-[#f0ebe0] border-b-2 border-[#3e2723] p-2 font-typewriter text-xl focus:outline-none placeholder-[#a1887f] placeholder-opacity-50"
                      />
                      <div className="text-left mt-2 text-xs text-[#5d4037] font-serif italic">
                          Ábending: Prófaðu nöfn eins og „{randomHint}“.
                      </div>
                  </div>

                  <button 
                      onClick={handleStartGame}
                      className="btn-paper px-8 py-4 text-xl w-full hover:scale-[1.02] transition-transform flex items-center justify-center gap-3"
                  >
                      <Anchor size={24}/> Hefja Útgerð
                  </button>
              </div>
          </div>
      );
  }

  // HEADER COMPONENT (Shared)
  const Header = () => (
      <header className="bg-[#3e2723] text-[#f6f1e1] p-4 border-b-4 border-[#8d6e63] shadow-lg sticky top-0 z-50 flex justify-between items-center">
          <div className="flex items-center gap-4">
              <div className="w-12 h-12 bg-[#f6f1e1] rounded-full flex items-center justify-center text-[#3e2723] border-2 border-[#8d6e63]">
                  <Anchor size={24}/>
              </div>
              <div>
                  <h2 className="font-header text-xl tracking-wide leading-none">{companyName}</h2>
                  <div className="text-xs text-[#d7ccc8] font-typewriter mt-1">Stofnað 1960</div>
              </div>
          </div>
          <div className="flex items-center gap-6">
              <div className="text-right">
                  <div className="text-xs text-[#a1887f] uppercase">Sjóður</div>
                  <div className="font-typewriter text-xl text-[#ffecb3]">{money.toLocaleString()} kr.</div>
              </div>
              <div className="text-right hidden sm:block">
                  <div className="text-xs text-[#a1887f] uppercase">Tími</div>
                  <div className="font-header text-xl capitalize">{getCurrentTimestamp()}</div>
              </div>
          </div>
      </header>
  );

  if (view === 'HQ') {
      return (
          <div className="min-h-screen pb-12">
              <Header />

              <main className="max-w-6xl mx-auto p-6 grid grid-cols-1 md:grid-cols-3 gap-6">

                  {/* Left Column: Fleet */}
                  <div className="md:col-span-2 space-y-6">
                      <div className="flex justify-between items-end border-b-2 border-[#3e2723] pb-2 mb-4">
                          <h3 className="font-header text-2xl text-[#3e2723] flex items-center gap-2">
                              <Ship className="text-[#5d4037]"/> Flotinn
                          </h3>
                          <button onClick={() => setView('MARKET')} className="btn-paper px-4 py-2 text-sm flex items-center gap-2 bg-[#e3f2fd] border-[#1e88e5] text-[#0d47a1]">
                              <ShoppingCart size={14}/> Skipamarkaður
                          </button>
                      </div>

                      {ships.length === 0 ? (
                          <div className="paper-card p-8 text-center text-[#8d6e63] italic">
                              Engin skip í flota. Farðu á markaðinn til að hefja rekstur.
                          </div>
                      ) : (
                          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                              {ships.map(ship => (
                                  <div key={ship.id} className="paper-card p-4 relative group">
                                      <div className="absolute top-2 right-2 text-xs font-bold text-[#8d6e63] font-typewriter">
                                          {ship.type}
                                      </div>
                                      <h4 className="font-header text-lg font-bold text-[#3e2723] mb-1">{ship.name}</h4>
                                      <div className="h-px bg-[#d7ccc8] w-full mb-3"></div>

                                      <div className="flex justify-between items-center mt-4">
                                          <div className={`text-xs ${ship.condition < 50 ? 'text-[#b71c1c] font-bold' : 'text-[#5d4037]'}`}>
                                              Ástand: {ship.condition}%
                                          </div>
                                          {ship.condition < 100 && (
                                              <button onClick={() => repairShip(ship.id)} className="text-[10px] underline text-[#0d47a1] ml-2">
                                                  Gera við
                                              </button>
                                          )}

                                          <button 
                                              onClick={() => startFishing(ship.id)}
                                              className="btn-paper px-3 py-1.5 text-xs bg-[#e8f5e9] border-[#2e7d32] text-[#1b5e20] flex items-center gap-1 hover:scale-105 transition-transform ml-auto"
                                          >
                                              <Waves size={12}/> Fara á sjó
                                          </button>
                                      </div>
                                  </div>
                              ))}
                          </div>
                      )}
                  </div>

                  {/* Right Column: Logbook */}
                  <div className="space-y-4">
                       <div className="flex items-center justify-between border-b-2 border-[#3e2723] pb-2">
                          <h3 className="font-header text-xl text-[#3e2723] flex items-center gap-2">
                              <FileText className="text-[#5d4037]"/> Dagbók
                          </h3>
                       </div>

                       <div className="paper-card p-4 min-h-[400px] max-h-[600px] overflow-y-auto font-typewriter text-sm space-y-4 bg-[#fffdf5]">
                           {logs.length === 0 && <div className="text-center opacity-50 italic pt-10">Bókin er auð...</div>}
                           {logs.map(log => (
                               <div key={log.id} className="border-b border-[#ece0d1] pb-2 last:border-0">
                                   <div className="text-[10px] text-[#8d6e63] uppercase tracking-wider mb-1 flex items-center gap-2">
                                       <span>{log.timestamp}</span>
                                       <div className="h-px flex-1 bg-[#d7ccc8]"></div>
                                   </div>
                                   <div className={`${
                                       log.type === 'MONEY' ? 'text-[#1b5e20]' : 
                                       log.type === 'ALERT' ? 'text-[#b71c1c]' : 
                                       log.type === 'EVENT' ? 'text-[#e65100] font-bold' : 'text-[#3e2723]'
                                   }`}>
                                       {log.text}
                                   </div>
                               </div>
                           ))}
                       </div>
                  </div>

              </main>
          </div>
      );
  }

  if (view === 'MARKET') {
      return (
          <div className="min-h-screen pb-12">
              <Header />
              <main className="max-w-4xl mx-auto p-6">
                  <div className="flex items-center gap-4 mb-6">
                      <button onClick={() => setView('HQ')} className="btn-paper p-2 rounded-full">
                          <ArrowRight className="rotate-180" size={20}/>
                      </button>
                      <h2 className="font-header text-3xl text-[#0d47a1]">SKIPAMARKAÐUR</h2>
                  </div>

                  <div className="space-y-4">
                      {MARKET_SHIPS.map(model => (
                          <div key={model.id} className="paper-card p-6 flex flex-col sm:flex-row items-center gap-6">
                              <div className="w-32 h-24 bg-[#e3f2fd] border border-[#90caf9] flex items-center justify-center text-[#1565c0]">
                                  <Ship size={48} strokeWidth={1}/>
                              </div>
                              <div className="flex-1 text-center sm:text-left">
                                  <h3 className="font-header text-xl font-bold">{model.name}</h3>
                                  <div className="text-sm text-[#5d4037] font-typewriter mt-1">
                                      Burðargeta: {model.capacity} tonn | Viðhald: {model.upkeep} kr/ár
                                  </div>
                              </div>
                              <div className="text-right">
                                  <div className="font-header text-2xl text-[#3e2723] mb-2">{model.price.toLocaleString()} kr.</div>
                                  <button 
                                      onClick={() => handleBuyShip(model)}
                                      disabled={money < model.price}
                                      className="btn-paper w-full py-2 bg-[#0d47a1] text-white border-[#002171] disabled:opacity-50 disabled:cursor-not-allowed"
                                  >
                                      KAUPA
                                  </button>
                              </div>
                          </div>
                      ))}
                  </div>
              </main>
          </div>
      );
  }

  if (view === 'FISHING') {
      return (
          <div className="min-h-screen bg-[#001020] relative text-[#f6f1e1]">
              <div className="absolute inset-0 opacity-20 bg-[url('https://www.transparenttextures.com/patterns/nautical-leather.png')]"></div>

              <div className="relative z-10 max-w-2xl mx-auto p-6 flex flex-col h-screen">

                  {/* Fishing Header */}
                  <div className="flex justify-between items-center mb-8 bg-[#3e2723] p-4 border-2 border-[#8d6e63] rounded-sm shadow-xl">
                      <div>
                          <h2 className="font-header text-xl text-[#ffecb3]">Á VEIÐUM</h2>
                          <div className="text-xs text-[#d7ccc8]">{ships.find(s => s.id === selectedShipId)?.name}</div>
                      </div>
                      <div className="text-right">
                          <div className="text-xs text-[#a1887f]">Afli í lest</div>
                          <div className="font-typewriter text-2xl text-[#81c784]">{currentCatch.toLocaleString()} kr.</div>
                      </div>
                  </div>

                  {/* Grid */}
                  <div className="flex-1 flex items-center justify-center">
                      <div className="grid grid-cols-3 gap-3 w-full max-w-md aspect-square">
                          {fishingGrid.map((tile) => (
                              <button
                                  key={tile.id}
                                  onClick={() => fishTile(tile)}
                                  disabled={tile.status === 'REVEALED'}
                                  className={`relative rounded-sm border-2 transition-all duration-500 overflow-hidden ${
                                      tile.status === 'HIDDEN' 
                                      ? 'bg-[#0d47a1] border-[#1565c0] hover:bg-[#1565c0]' 
                                      : 'bg-[#f6f1e1] border-[#8d6e63]'
                                  }`}
                              >
                                  {tile.status === 'HIDDEN' ? (
                                      <div className="absolute inset-0 flex items-center justify-center opacity-20">
                                          <Waves size={32} className="text-white animate-pulse"/>
                                      </div>
                                  ) : (
                                      <div className="flex flex-col items-center justify-center h-full animate-[fadeIn_0.5s]">
                                          {tile.content === 'EMPTY' && <div className="text-[#a1887f] font-typewriter text-xs">Tómt</div>}
                                          {tile.content === 'FISH' && <Fish size={32} className="text-[#1b5e20] mb-1"/>}
                                          {tile.content === 'BIG_CATCH' && <div className="text-[#f57f17]"><Fish size={40}/><Sparkles size={16} className="absolute top-2 right-2"/></div>}
                                          {tile.content === 'DANGER' && <AlertTriangle size={32} className="text-[#b71c1c]"/>}

                                          {tile.value !== 0 && (
                                              <div className={`text-xs font-bold mt-1 ${tile.value > 0 ? 'text-[#1b5e20]' : 'text-[#b71c1c]'}`}>
                                                  {tile.value > 0 ? '+' : ''}{tile.value.toLocaleString()}
                                              </div>
                                          )}
                                      </div>
                                  )}
                              </button>
                          ))}
                      </div>
                  </div>

                  {/* Controls */}
                  <div className="mt-8 space-y-4">
                      <div className="flex gap-4">
                          <button 
                              onClick={useDepthMeter}
                              disabled={money < DEPTH_METER_COST}
                              className="flex-1 btn-paper py-4 bg-[#263238] border-[#37474f] text-[#eceff1] flex flex-col items-center justify-center gap-1 hover:bg-[#37474f] disabled:opacity-50"
                          >
                              <div className="flex items-center gap-2">
                                  <Search size={18} /> DÝPTARMÆLIR
                              </div>
                              <div className="text-[10px] text-[#b0bec5]">-5.000 kr. / notkun</div>
                          </button>

                          <button 
                              onClick={endFishing}
                              className="flex-1 btn-paper py-4 bg-[#1b5e20] border-[#2e7d32] text-white flex flex-col items-center justify-center gap-1 hover:bg-[#2e7d32]"
                          >
                              <div className="flex items-center gap-2">
                                  <Anchor size={18} /> LANDA & HEIM
                              </div>
                              <div className="text-[10px] text-[#a5d6a7]">Ljúka veiðiferð</div>
                          </button>
                      </div>
                  </div>

              </div>
          </div>
      );
  }

  return null;
}

const root = createRoot(document.getElementById('root')!);
root.render(<App />);

import React, { useState, useEffect, useRef } from 'react';
import { createRoot } from 'react-dom/client';
import { Ship, Anchor, Fish, Coins, User, Waves, Bot, Play, Sparkles, AlertTriangle, X, ScrollText, Save, Trash2, ArrowRight, ShoppingCart, Map, DollarSign, Search, Calendar, Briefcase, FileText, Wrench } from 'lucide-react';

// --- Configuration ---

const START_MONEY = 500000;
const DEPTH_METER_COST = 5000;
const SAVE_KEY = 'maigreifinn_1960_v3';
const SEASONS = ["Vor", "Sumar", "Haust", "Vetur"];

// Parody Names & Data
const COMPANY_NAMES = [
  "Brimverzlun hf.", "Hafdráttur h/f", "Togglarinn ehf.", "Sjómannafélagið Víkingur",
  "Útgerðarfélag Akureyrar", "Fiskvinnslan Alda", "Norðurljósavinnslan", "Vestfjarða-Skel hf.",
  "Ísbjörninn hf.", "Skeljungur Útgerð"
];

const SHIP_NAMES = [
  "MS Brimrós", "MS Togglari", "MS Djúpvera", "Guðrún Björg", "Sæljónið", 
  "Haförninn", "Sjöstjarnan", "Kjölurinn", "Aldan", "Vonin"
];

type EventType = {
  id: string;
  title: string;
  text: string;
  type: 'BAD' | 'GOOD';
  effect: {
    money: number;
    rep: number;
    conditionDamage?: number; // Damage to the active ship
  }
};

const EVENTS: EventType[] = [
  { id: 'investigation', title: "Rannsóknarnefnd", text: "☠️ Hættuspil! Rannsóknarnefnd sjávarútvegsins mætir á svæðið.", effect: { money: 0, rep: -3 }, type: 'BAD' },
  { id: 'bank', title: "Bankinn hringir", text: "🏦 Útvegsspils-andi svífur yfir vötnum. Bankastjórinn vill sitt.", effect: { money: -25000, rep: 0 }, type: 'BAD' },
  { id: 'tire', title: "Rallýspil", text: "🏁 Rallýspil! Dekkið springur á bryggjubílnum og varahlutir tefjast. Skipið fær slæma meðferð.", effect: { money: 0, rep: 0, conditionDamage: 10 }, type: 'BAD' },
  { id: 'play', title: "Aktjóneri", text: "🎭 Leikritið í höfninni slær í gegn. Allir kátir.", effect: { money: 5000, rep: 2 }, type: 'GOOD' },
  { id: 'omar', title: "Ómar-style", text: "📻 „Þetta reddast“. Bjartsýni skilar sér í kassan.", effect: { money: 15000, rep: 1 }, type: 'GOOD' }
];

const MARKET_SHIPS = [
  { id: 1, name: "Trilla (Opinn)", type: 'TRILLA', price: 50000, capacity: 5, upkeep: 1000 },
  { id: 2, name: "Kvótakóngur", type: 'TRAWLER', price: 150000, capacity: 15, upkeep: 5000 },
  { id: 3, name: "MS Togglari", type: 'TRAWLER', price: 300000, capacity: 30, upkeep: 10000 },
  { id: 4, name: "Gullskipið", type: 'YACHT', price: 1000000, capacity: 50, upkeep: 25000 },
];

// --- Types ---

type GameView = 'TITLE' | 'HQ' | 'MARKET' | 'FISHING';

interface ShipItem {
  id: string; // Unique ID
  modelId: number;
  name: string;
  type: string;
  condition: number; // 0-100%
  equipped: boolean; // Has depth meter?
}

interface LogEntry {
  id: number;
  timestamp: string; // "Vor 1955"
  text: string;
  type: 'INFO' | 'MONEY' | 'ALERT' | 'EVENT';
}

interface FishingTile {
  id: number;
  status: 'HIDDEN' | 'REVEALED';
  content: 'FISH' | 'EMPTY' | 'DANGER' | 'BIG_CATCH';
  value: number;
}

// --- Main Component ---

function App() {
  // State
  const [view, setView] = useState<GameView>('TITLE');
  const [companyName, setCompanyName] = useState("");
  const [money, setMoney] = useState(START_MONEY);
  const [ships, setShips] = useState<ShipItem[]>([]);

  // Time System
  const [year, setYear] = useState(1960);
  const [seasonIndex, setSeasonIndex] = useState(0); // 0=Vor, 1=Sumar, 2=Haust, 3=Vetur

  const [logs, setLogs] = useState<LogEntry[]>([]);

  // Fishing State
  const [fishingGrid, setFishingGrid] = useState<FishingTile[]>([]);
  const [selectedShipId, setSelectedShipId] = useState<string | null>(null);
  const [currentCatch, setCurrentCatch] = useState(0);

  // UI State
  const [randomHint, setRandomHint] = useState("");

  // Initialize
  useEffect(() => {
    setRandomHint(COMPANY_NAMES[Math.floor(Math.random() * COMPANY_NAMES.length)]);

    const saved = localStorage.getItem(SAVE_KEY);
    if (saved) {
      try {
        const data = JSON.parse(saved);
        setCompanyName(data.companyName);
        setMoney(data.money);
        setShips(data.ships);
        setYear(data.year);
        setSeasonIndex(data.seasonIndex || 0);
        setLogs(data.logs);
        // Don't auto-navigate if name is missing
        if (data.companyName) setView('HQ');
      } catch(e) {}
    }
  }, []);

  // Autosave
  useEffect(() => {
    if (view !== 'TITLE') {
       const timer = setTimeout(() => {
          localStorage.setItem(SAVE_KEY, JSON.stringify({ companyName, money, ships, year, seasonIndex, logs }));
       }, 1000);
       return () => clearTimeout(timer);
    }
  }, [companyName, money, ships, year, seasonIndex, logs, view]);

  const getCurrentTimestamp = () => `${SEASONS[seasonIndex]} ${year}`;

  const addLog = (text: string, type: LogEntry['type'] = 'INFO') => {
      setLogs(prev => [{
          id: Date.now(),
          timestamp: getCurrentTimestamp(),
          text,
          type
      }, ...prev]);
  };

  const advanceTime = () => {
      setSeasonIndex(prev => {
          const next = prev + 1;
          if (next >= SEASONS.length) {
              setYear(y => y + 1);
              return 0;
          }
          return next;
      });
  };

  const handleStartGame = () => {
      const finalName = companyName || randomHint;
      setCompanyName(finalName);
      addLog(`Útgerðin ${finalName} stofnuð.`, 'INFO');
      setView('HQ');
  };

  const handleBuyShip = (shipModel: typeof MARKET_SHIPS[0]) => {
      if (money >= shipModel.price) {
          setMoney(m => m - shipModel.price);
          const newShip: ShipItem = {
              id: Date.now().toString(),
              modelId: shipModel.id,
              name: SHIP_NAMES[Math.floor(Math.random() * SHIP_NAMES.length)] + ` ${Math.floor(Math.random() * 100)}`,
              type: shipModel.type,
              condition: 100,
              equipped: false
          };
          setShips(prev => [...prev, newShip]);
          addLog(`Keypti ${newShip.name} (${shipModel.name}) fyrir ${shipModel.price.toLocaleString()} kr.`, 'MONEY');
      }
  };

  const repairShip = (shipId: string) => {
      const ship = ships.find(s => s.id === shipId);
      if (!ship || ship.condition >= 100) return;

      const cost = Math.floor((100 - ship.condition) * 500); // 500kr per 1%
      if (money >= cost) {
          setMoney(m => m - cost);
          setShips(prev => prev.map(s => s.id === shipId ? { ...s, condition: 100 } : s));
          addLog(`Gerði við ${ship.name} fyrir ${cost.toLocaleString()} kr.`, 'MONEY');
      }
  };

  const startFishing = (shipId: string) => {
      const ship = ships.find(s => s.id === shipId);
      if (ship && ship.condition < 20) {
          alert("Skip er í of slæmu ástandi til að fara á sjó! Gerðu við það fyrst.");
          return;
      }

      setSelectedShipId(shipId);
      // Generate Grid
      const newGrid: FishingTile[] = Array(9).fill(null).map((_, i) => {
          const rand = Math.random();
          let content: FishingTile['content'] = 'EMPTY';
          let value = 0;

          if (rand > 0.7) { content = 'FISH'; value = 50000; }
          else if (rand > 0.9) { content = 'BIG_CATCH'; value = 150000; }
          else if (rand < 0.1) { content = 'DANGER'; value = -10000; }

          return { id: i, status: 'HIDDEN', content, value };
      });
      setFishingGrid(newGrid);
      setCurrentCatch(0);
      setView('FISHING');
      addLog(`Hélt til veiða á ${ship?.name}.`, 'INFO');
  };

  const useDepthMeter = () => {
      if (money >= DEPTH_METER_COST) {
          setMoney(m => m - DEPTH_METER_COST);
          // Find unrevealed tiles
          const hidden = fishingGrid.filter(t => t.status === 'HIDDEN');
          if (hidden.length > 0) {
              const target = hidden[Math.floor(Math.random() * hidden.length)];
              setFishingGrid(prev => prev.map(t => t.id === target.id ? { ...t, status: 'REVEALED' } : t));
          }
      }
  };

  const fishTile = (tile: FishingTile) => {
      if (tile.status === 'REVEALED' && (tile.content === 'EMPTY' || tile.content === 'DANGER')) {
         // Fishing revealed bad tiles is allowed but usually has no gain or is bad
      }

      const updatedGrid = fishingGrid.map(t => t.id === tile.id ? { ...t, status: 'REVEALED' as const } : t);
      setFishingGrid(updatedGrid);

      if (tile.content === 'DANGER') {
          addLog("Hætta! Netin festust eða veður versnaði.", 'ALERT');
          setCurrentCatch(c => c - 5000);
          // Small immediate damage on danger tiles
          if (selectedShipId) {
             setShips(prev => prev.map(s => s.id === selectedShipId ? { ...s, condition: Math.max(0, s.condition - 5) } : s));
          }
      } else if (tile.content === 'FISH' || tile.content === 'BIG_CATCH') {
          setCurrentCatch(c => c + tile.value);
      }
  };

  const endFishing = () => {
      // Payout
      setMoney(m => m + currentCatch);
      addLog(`Löndun: ${currentCatch.toLocaleString()} kr. komu í kassann.`, 'MONEY');

      // Wear and tear (normal)
      if (selectedShipId) {
          setShips(prev => prev.map(s => s.id === selectedShipId ? { ...s, condition: Math.max(0, s.condition - 2) } : s));
      }

      // 20% Chance of Event
      if (Math.random() < 0.2) {
          const event = EVENTS[Math.floor(Math.random() * EVENTS.length)];
          addLog(`${event.title}: ${event.text}`, 'EVENT');

          // Apply Money Effect
          if (event.effect.money !== 0) {
              setMoney(m => m + event.effect.money);
          }

          // Apply Condition Damage (Rallýspil)
          if (event.effect.conditionDamage && selectedShipId) {
              setShips(prev => prev.map(s => s.id === selectedShipId ? { 
                  ...s, 
                  condition: Math.max(0, s.condition - event.effect.conditionDamage!) 
              } : s));
          }
      }

      advanceTime();
      setView('HQ');
  };

  // --- Views ---

  if (view === 'TITLE') {
      return (
          <div className="min-h-screen flex flex-col items-center justify-center p-4 bg-[#f6f1e1] relative">
              <div className="absolute inset-0 border-[20px] border-[#3e2723] opacity-10 pointer-events-none"></div>

              <div className="max-w-lg w-full text-center space-y-8">
                  <div className="space-y-2">
                      <h1 className="text-6xl font-header text-[#3e2723] tracking-widest drop-shadow-sm">MAÍ GREIFINN</h1>
                      <div className="text-xl font-serif italic text-[#5d4037]">- Útvegsspilið 1960 -</div>
                  </div>

                  <div className="paper-card p-8 rounded-sm transform rotate-1">
                      <label className="block text-left font-bold text-[#3e2723] mb-2 font-header">NAFN ÚTGERÐAR</label>
                      <input 
                          type="text" 
                          value={companyName}
                          onChange={(e) => setCompanyName(e.target.value)}
                          placeholder={`t.d. ${randomHint}`}
                          className="w-full bg-[#f0ebe0] border-b-2 border-[#3e2723] p-2 font-typewriter text-xl focus:outline-none placeholder-[#a1887f] placeholder-opacity-50"
                      />
                      <div className="text-left mt-2 text-xs text-[#5d4037] font-serif italic">
                          Ábending: Prófaðu nöfn eins og „{randomHint}“.
                      </div>
                  </div>

                  <button 
                      onClick={handleStartGame}
                      className="btn-paper px-8 py-4 text-xl w-full hover:scale-[1.02] transition-transform flex items-center justify-center gap-3"
                  >
                      <Anchor size={24}/> Hefja Útgerð
                  </button>
              </div>
          </div>
      );
  }

  // HEADER COMPONENT (Shared)
  const Header = () => (
      <header className="bg-[#3e2723] text-[#f6f1e1] p-4 border-b-4 border-[#8d6e63] shadow-lg sticky top-0 z-50 flex justify-between items-center">
          <div className="flex items-center gap-4">
              <div className="w-12 h-12 bg-[#f6f1e1] rounded-full flex items-center justify-center text-[#3e2723] border-2 border-[#8d6e63]">
                  <Anchor size={24}/>
              </div>
              <div>
                  <h2 className="font-header text-xl tracking-wide leading-none">{companyName}</h2>
                  <div className="text-xs text-[#d7ccc8] font-typewriter mt-1">Stofnað 1960</div>
              </div>
          </div>
          <div className="flex items-center gap-6">
              <div className="text-right">
                  <div className="text-xs text-[#a1887f] uppercase">Sjóður</div>
                  <div className="font-typewriter text-xl text-[#ffecb3]">{money.toLocaleString()} kr.</div>
              </div>
              <div className="text-right hidden sm:block">
                  <div className="text-xs text-[#a1887f] uppercase">Tími</div>
                  <div className="font-header text-xl capitalize">{getCurrentTimestamp()}</div>
              </div>
          </div>
      </header>
  );

  if (view === 'HQ') {
      return (
          <div className="min-h-screen pb-12">
              <Header />

              <main className="max-w-6xl mx-auto p-6 grid grid-cols-1 md:grid-cols-3 gap-6">

                  {/* Left Column: Fleet */}
                  <div className="md:col-span-2 space-y-6">
                      <div className="flex justify-between items-end border-b-2 border-[#3e2723] pb-2 mb-4">
                          <h3 className="font-header text-2xl text-[#3e2723] flex items-center gap-2">
                              <Ship className="text-[#5d4037]"/> Flotinn
                          </h3>
                          <button onClick={() => setView('MARKET')} className="btn-paper px-4 py-2 text-sm flex items-center gap-2 bg-[#e3f2fd] border-[#1e88e5] text-[#0d47a1]">
                              <ShoppingCart size={14}/> Skipamarkaður
                          </button>
                      </div>

                      {ships.length === 0 ? (
                          <div className="paper-card p-8 text-center text-[#8d6e63] italic">
                              Engin skip í flota. Farðu á markaðinn til að hefja rekstur.
                          </div>
                      ) : (
                          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                              {ships.map(ship => (
                                  <div key={ship.id} className="paper-card p-4 relative group">
                                      <div className="absolute top-2 right-2 text-xs font-bold text-[#8d6e63] font-typewriter">
                                          {ship.type}
                                      </div>
                                      <h4 className="font-header text-lg font-bold text-[#3e2723] mb-1">{ship.name}</h4>
                                      <div className="h-px bg-[#d7ccc8] w-full mb-3"></div>

                                      <div className="flex justify-between items-center mt-4">
                                          <div className={`text-xs ${ship.condition < 50 ? 'text-[#b71c1c] font-bold' : 'text-[#5d4037]'}`}>
                                              Ástand: {ship.condition}%
                                          </div>
                                          {ship.condition < 100 && (
                                              <button onClick={() => repairShip(ship.id)} className="text-[10px] underline text-[#0d47a1] ml-2 hover:text-[#1565c0]">
                                                  Gera við ({( (100-ship.condition)*500 ).toLocaleString()}kr)
                                              </button>
                                          )}

                                          <button 
                                              onClick={() => startFishing(ship.id)}
                                              className="btn-paper px-3 py-1.5 text-xs bg-[#e8f5e9] border-[#2e7d32] text-[#1b5e20] flex items-center gap-1 hover:scale-105 transition-transform ml-auto"
                                          >
                                              <Waves size={12}/> Fara á sjó
                                          </button>
                                      </div>
                                  </div>
                              ))}
                          </div>
                      )}
                  </div>

                  {/* Right Column: Logbook */}
                  <div className="space-y-4">
                       <div className="flex items-center justify-between border-b-2 border-[#3e2723] pb-2">
                          <h3 className="font-header text-xl text-[#3e2723] flex items-center gap-2">
                              <FileText className="text-[#5d4037]"/> Dagbók
                          </h3>
                       </div>

                       <div className="paper-card p-4 min-h-[400px] max-h-[600px] overflow-y-auto font-typewriter text-sm space-y-4 bg-[#fffdf5]">
                           {logs.length === 0 && <div className="text-center opacity-50 italic pt-10">Bókin er auð...</div>}
                           {logs.map(log => (
                               <div key={log.id} className="border-b border-[#ece0d1] pb-2 last:border-0">
                                   <div className="text-[10px] text-[#8d6e63] uppercase tracking-wider mb-1 flex items-center gap-2">
                                       <span>{log.timestamp}</span>
                                       <div className="h-px flex-1 bg-[#d7ccc8]"></div>
                                   </div>
                                   <div className={`${
                                       log.type === 'MONEY' ? 'text-[#1b5e20]' : 
                                       log.type === 'ALERT' ? 'text-[#b71c1c]' : 
                                       log.type === 'EVENT' ? 'text-[#e65100] font-bold' : 'text-[#3e2723]'
                                   }`}>
                                       {log.text}
                                   </div>
                               </div>
                           ))}
                       </div>
                  </div>

              </main>
          </div>
      );
  }

  if (view === 'MARKET') {
      return (
          <div className="min-h-screen pb-12">
              <Header />
              <main className="max-w-4xl mx-auto p-6">
                  <div className="flex items-center gap-4 mb-6">
                      <button onClick={() => setView('HQ')} className="btn-paper p-2 rounded-full">
                          <ArrowRight className="rotate-180" size={20}/>
                      </button>
                      <h2 className="font-header text-3xl text-[#0d47a1]">SKIPAMARKAÐUR</h2>
                  </div>

                  <div className="space-y-4">
                      {MARKET_SHIPS.map(model => (
                          <div key={model.id} className="paper-card p-6 flex flex-col sm:flex-row items-center gap-6">
                              <div className="w-32 h-24 bg-[#e3f2fd] border border-[#90caf9] flex items-center justify-center text-[#1565c0]">
                                  <Ship size={48} strokeWidth={1}/>
                              </div>
                              <div className="flex-1 text-center sm:text-left">
                                  <h3 className="font-header text-xl font-bold">{model.name}</h3>
                                  <div className="text-sm text-[#5d4037] font-typewriter mt-1">
                                      Burðargeta: {model.capacity} tonn | Viðhald: {model.upkeep} kr/ár
                                  </div>
                              </div>
                              <div className="text-right">
                                  <div className="font-header text-2xl text-[#3e2723] mb-2">{model.price.toLocaleString()} kr.</div>
                                  <button 
                                      onClick={() => handleBuyShip(model)}
                                      disabled={money < model.price}
                                      className="btn-paper w-full py-2 bg-[#0d47a1] text-white border-[#002171] disabled:opacity-50 disabled:cursor-not-allowed"
                                  >
                                      KAUPA
                                  </button>
                              </div>
                          </div>
                      ))}
                  </div>
              </main>
          </div>
      );
  }

  if (view === 'FISHING') {
      return (
          <div className="min-h-screen bg-[#001020] relative text-[#f6f1e1]">
              <div className="absolute inset-0 opacity-20 bg-[url('https://www.transparenttextures.com/patterns/nautical-leather.png')]"></div>

              <div className="relative z-10 max-w-2xl mx-auto p-6 flex flex-col h-screen">

                  {/* Fishing Header */}
                  <div className="flex justify-between items-center mb-8 bg-[#3e2723] p-4 border-2 border-[#8d6e63] rounded-sm shadow-xl">
                      <div>
                          <h2 className="font-header text-xl text-[#ffecb3]">Á VEIÐUM</h2>
                          <div className="text-xs text-[#d7ccc8]">{ships.find(s => s.id === selectedShipId)?.name}</div>
                      </div>
                      <div className="text-right">
                          <div className="text-xs text-[#a1887f]">Afli í lest</div>
                          <div className="font-typewriter text-2xl text-[#81c784]">{currentCatch.toLocaleString()} kr.</div>
                      </div>
                  </div>

                  {/* Grid */}
                  <div className="flex-1 flex items-center justify-center">
                      <div className="grid grid-cols-3 gap-3 w-full max-w-md aspect-square">
                          {fishingGrid.map((tile) => (
                              <button
                                  key={tile.id}
                                  onClick={() => fishTile(tile)}
                                  disabled={tile.status === 'REVEALED'}
                                  className={`relative rounded-sm border-2 transition-all duration-500 overflow-hidden ${
                                      tile.status === 'HIDDEN' 
                                      ? 'bg-[#0d47a1] border-[#1565c0] hover:bg-[#1565c0]' 
                                      : 'bg-[#f6f1e1] border-[#8d6e63]'
                                  }`}
                              >
                                  {tile.status === 'HIDDEN' ? (
                                      <div className="absolute inset-0 flex items-center justify-center opacity-20">
                                          <Waves size={32} className="text-white animate-pulse"/>
                                      </div>
                                  ) : (
                                      <div className="flex flex-col items-center justify-center h-full animate-[fadeIn_0.5s]">
                                          {tile.content === 'EMPTY' && <div className="text-[#a1887f] font-typewriter text-xs">Tómt</div>}
                                          {tile.content === 'FISH' && <Fish size={32} className="text-[#1b5e20] mb-1"/>}
                                          {tile.content === 'BIG_CATCH' && <div className="text-[#f57f17]"><Fish size={40}/><Sparkles size={16} className="absolute top-2 right-2"/></div>}
                                          {tile.content === 'DANGER' && <AlertTriangle size={32} className="text-[#b71c1c]"/>}

                                          {tile.value !== 0 && (
                                              <div className={`text-xs font-bold mt-1 ${tile.value > 0 ? 'text-[#1b5e20]' : 'text-[#b71c1c]'}`}>
                                                  {tile.value > 0 ? '+' : ''}{tile.value.toLocaleString()}
                                              </div>
                                          )}
                                      </div>
                                  )}
                              </button>
                          ))}
                      </div>
                  </div>

                  {/* Controls */}
                  <div className="mt-8 space-y-4">
                      <div className="flex gap-4">
                          <button 
                              onClick={useDepthMeter}
                              disabled={money < DEPTH_METER_COST}
                              className="flex-1 btn-paper py-4 bg-[#263238] border-[#37474f] text-[#eceff1] flex flex-col items-center justify-center gap-1 hover:bg-[#37474f] disabled:opacity-50"
                          >
                              <div className="flex items-center gap-2">
                                  <Search size={18} /> DÝPTARMÆLIR
                              </div>
                              <div className="text-[10px] text-[#b0bec5]">-5.000 kr. / notkun</div>
                          </button>

                          <button 
                              onClick={endFishing}
                              className="flex-1 btn-paper py-4 bg-[#1b5e20] border-[#2e7d32] text-white flex flex-col items-center justify-center gap-1 hover:bg-[#2e7d32]"
                          >
                              <div className="flex items-center gap-2">
                                  <Anchor size={18} /> LANDA & HEIM
                              </div>
                              <div className="text-[10px] text-[#a5d6a7]">Ljúka veiðiferð</div>
                          </button>
                      </div>
                  </div>

              </div>
          </div>
      );
  }

  return null;
}

const root = createRoot(document.getElementById('root')!);
root.render(<App />);

import React, { useState, useEffect, useRef } from 'react';
import { createRoot } from 'react-dom/client';
import { Ship, Anchor, Fish, Coins, User, Waves, Bot, Play, Sparkles, AlertTriangle, X, ScrollText, Save, Trash2, ArrowRight, ShoppingCart, Map, DollarSign, Search, Calendar, Briefcase, FileText, Wrench, Clock, Battery } from 'lucide-react';

// --- Configuration ---

const START_MONEY = 500000;
const DEPTH_METER_COST = 5000;
const SAVE_KEY = 'maigreifinn_split_v1';
const SEASONS = ["Vor", "Sumar", "Haust", "Vetur"];

// Parody Names & Data
const COMPANY_NAMES = [
  "Brimverzlun hf.", "Hafdráttur h/f", "Togglarinn ehf.", "Sjómannafélagið Víkingur",
  "Útgerðarfélag Akureyrar", "Fiskvinnslan Alda", "Norðurljósavinnslan", "Vestfjarða-Skel hf.",
  "Ísbjörninn hf.", "Skeljungur Útgerð", "IceFresh Seafood", "Arctic Catch"
];

const SHIP_NAMES = [
  "MS Brimrós", "MS Togglari", "MS Djúpvera", "Guðrún Björg", "Sæljónið", 
  "Haförninn", "Sjöstjarnan", "Kjölurinn", "Aldan", "Vonin", "Víkingur", "Stormur"
];

type EventType = {
  id: string;
  title: string;
  text: string;
  type: 'BAD' | 'GOOD';
  effect: {
    money: number;
    rep: number;
    conditionDamage?: number; // Damage to the active ship
  }
};

const EVENTS: EventType[] = [
  { id: 'investigation', title: "Rannsóknarnefnd", text: "☠️ Hættuspil! Rannsóknarnefnd sjávarútvegsins mætir á svæðið.", effect: { money: 0, rep: -3 }, type: 'BAD' },
  { id: 'bank', title: "Bankinn hringir", text: "🏦 Útvegsspils-andi svífur yfir vötnum. Bankastjórinn vill sitt.", effect: { money: -25000, rep: 0 }, type: 'BAD' },
  { id: 'tire', title: "Rallýspil", text: "🏁 Rallýspil! Dekkið springur á bryggjubílnum og varahlutir tefjast. Skipið fær slæma meðferð.", effect: { money: 0, rep: 0, conditionDamage: 10 }, type: 'BAD' },
  { id: 'play', title: "Aktjóneri", text: "🎭 Leikritið í höfninni slær í gegn. Allir kátir.", effect: { money: 5000, rep: 2 }, type: 'GOOD' },
  { id: 'omar', title: "Ómar-style", text: "📻 „Þetta reddast“. Bjartsýni skilar sér í kassan.", effect: { money: 15000, rep: 1 }, type: 'GOOD' }
];

const MARKET_SHIPS = [
  { id: 1, name: "Trilla (Opinn)", type: 'TRILLA', price: 50000, capacity: 5, upkeep: 1000 },
  { id: 2, name: "Kvótakóngur", type: 'TRAWLER', price: 150000, capacity: 15, upkeep: 5000 },
  { id: 3, name: "MS Togglari", type: 'TRAWLER', price: 300000, capacity: 30, upkeep: 10000 },
  { id: 4, name: "Gullskipið", type: 'YACHT', price: 1000000, capacity: 50, upkeep: 25000 },
];

// --- Types ---

type GameView = 'SPLIT' | 'TITLE' | 'HQ' | 'MARKET' | 'FISHING';
type Era = '1920' | '2020';

interface ShipItem {
  id: string; // Unique ID
  modelId: number;
  name: string;
  type: string;
  condition: number; // 0-100%
  equipped: boolean; // Has depth meter?
}

interface LogEntry {
  id: number;
  timestamp: string; // "Vor 1955"
  text: string;
  type: 'INFO' | 'MONEY' | 'ALERT' | 'EVENT';
}

interface FishingTile {
  id: number;
  status: 'HIDDEN' | 'REVEALED';
  content: 'FISH' | 'EMPTY' | 'DANGER' | 'BIG_CATCH';
  value: number;
}

// --- Main Component ---

function App() {
  // State
  const [view, setView] = useState<GameView>('SPLIT');
  const [era, setEra] = useState<Era>('1920');
  const [companyName, setCompanyName] = useState("");
  const [money, setMoney] = useState(START_MONEY);
  const [ships, setShips] = useState<ShipItem[]>([]);

  // Time System
  const [year, setYear] = useState(1920);
  const [seasonIndex, setSeasonIndex] = useState(0); // 0=Vor, 1=Sumar, 2=Haust, 3=Vetur

  const [logs, setLogs] = useState<LogEntry[]>([]);

  // Fishing State
  const [fishingGrid, setFishingGrid] = useState<FishingTile[]>([]);
  const [selectedShipId, setSelectedShipId] = useState<string | null>(null);
  const [currentCatch, setCurrentCatch] = useState(0);

  // UI State
  const [randomHint, setRandomHint] = useState("");

  // Initialize
  useEffect(() => {
    setRandomHint(COMPANY_NAMES[Math.floor(Math.random() * COMPANY_NAMES.length)]);

    const saved = localStorage.getItem(SAVE_KEY);
    if (saved) {
      try {
        const data = JSON.parse(saved);
        if (data.companyName) {
            setCompanyName(data.companyName);
            setMoney(data.money);
            setShips(data.ships);
            setYear(data.year);
            setSeasonIndex(data.seasonIndex || 0);
            setLogs(data.logs);
            setEra(data.era || '1920');
            setView('HQ');
        }
      } catch(e) {}
    }
  }, []);

  // Autosave
  useEffect(() => {
    if (view !== 'SPLIT' && view !== 'TITLE') {
       const timer = setTimeout(() => {
          localStorage.setItem(SAVE_KEY, JSON.stringify({ companyName, money, ships, year, seasonIndex, logs, era }));
       }, 1000);
       return () => clearTimeout(timer);
    }
  }, [companyName, money, ships, year, seasonIndex, logs, view, era]);

  const getCurrentTimestamp = () => `${SEASONS[seasonIndex]} ${year}`;

  const addLog = (text: string, type: LogEntry['type'] = 'INFO') => {
      setLogs(prev => [{
          id: Date.now(),
          timestamp: getCurrentTimestamp(),
          text,
          type
      }, ...prev]);
  };

  const advanceTime = () => {
      setSeasonIndex(prev => {
          const next = prev + 1;
          if (next >= SEASONS.length) {
              setYear(y => y + 1);
              return 0;
          }
          return next;
      });
  };

  const handleSelectEra = (selectedEra: Era) => {
      setEra(selectedEra);
      setYear(parseInt(selectedEra));
      setView('TITLE');
  };

  const handleStartGame = () => {
      const finalName = companyName || randomHint;
      setCompanyName(finalName);
      addLog(`Útgerðin ${finalName} stofnuð (${era}).`, 'INFO');
      setView('HQ');
  };

  const handleBuyShip = (shipModel: typeof MARKET_SHIPS[0]) => {
      if (money >= shipModel.price) {
          setMoney(m => m - shipModel.price);
          const newShip: ShipItem = {
              id: Date.now().toString(),
              modelId: shipModel.id,
              name: SHIP_NAMES[Math.floor(Math.random() * SHIP_NAMES.length)] + ` ${Math.floor(Math.random() * 100)}`,
              type: shipModel.type,
              condition: 100,
              equipped: false
          };
          setShips(prev => [...prev, newShip]);
          addLog(`Keypti ${newShip.name} (${shipModel.name}) fyrir ${shipModel.price.toLocaleString()} kr.`, 'MONEY');
      }
  };

  const repairShip = (shipId: string) => {
      const ship = ships.find(s => s.id === shipId);
      if (!ship || ship.condition >= 100) return;

      const cost = Math.floor((100 - ship.condition) * 500); // 500kr per 1%
      if (money >= cost) {
          setMoney(m => m - cost);
          setShips(prev => prev.map(s => s.id === shipId ? { ...s, condition: 100 } : s));
          addLog(`Gerði við ${ship.name} fyrir ${cost.toLocaleString()} kr.`, 'MONEY');
      }
  };

  const startFishing = (shipId: string) => {
      const ship = ships.find(s => s.id === shipId);
      if (ship && ship.condition < 20) {
          alert("Skip er í of slæmu ástandi til að fara á sjó! Gerðu við það fyrst.");
          return;
      }

      setSelectedShipId(shipId);
      // Generate Grid
      const newGrid: FishingTile[] = Array(9).fill(null).map((_, i) => {
          const rand = Math.random();
          let content: FishingTile['content'] = 'EMPTY';
          let value = 0;

          if (rand > 0.7) { content = 'FISH'; value = 50000; }
          else if (rand > 0.9) { content = 'BIG_CATCH'; value = 150000; }
          else if (rand < 0.1) { content = 'DANGER'; value = -10000; }

          return { id: i, status: 'HIDDEN', content, value };
      });
      setFishingGrid(newGrid);
      setCurrentCatch(0);
      setView('FISHING');
      addLog(`Hélt til veiða á ${ship?.name}.`, 'INFO');
  };

  const useDepthMeter = () => {
      if (money >= DEPTH_METER_COST) {
          setMoney(m => m - DEPTH_METER_COST);
          // Find unrevealed tiles
          const hidden = fishingGrid.filter(t => t.status === 'HIDDEN');
          if (hidden.length > 0) {
              const target = hidden[Math.floor(Math.random() * hidden.length)];
              setFishingGrid(prev => prev.map(t => t.id === target.id ? { ...t, status: 'REVEALED' } : t));
          }
      }
  };

  const fishTile = (tile: FishingTile) => {
      if (tile.status === 'REVEALED' && (tile.content === 'EMPTY' || tile.content === 'DANGER')) {
         // Fishing revealed bad tiles is allowed but usually has no gain or is bad
      }

      const updatedGrid = fishingGrid.map(t => t.id === tile.id ? { ...t, status: 'REVEALED' as const } : t);
      setFishingGrid(updatedGrid);

      if (tile.content === 'DANGER') {
          addLog("Hætta! Netin festust eða veður versnaði.", 'ALERT');
          setCurrentCatch(c => c - 5000);
          // Small immediate damage on danger tiles
          if (selectedShipId) {
             setShips(prev => prev.map(s => s.id === selectedShipId ? { ...s, condition: Math.max(0, s.condition - 5) } : s));
          }
      } else if (tile.content === 'FISH' || tile.content === 'BIG_CATCH') {
          setCurrentCatch(c => c + tile.value);
      }
  };

  const endFishing = () => {
      // Payout
      setMoney(m => m + currentCatch);
      addLog(`Löndun: ${currentCatch.toLocaleString()} kr. komu í kassann.`, 'MONEY');

      // Wear and tear (normal)
      if (selectedShipId) {
          setShips(prev => prev.map(s => s.id === selectedShipId ? { ...s, condition: Math.max(0, s.condition - 2) } : s));
      }

      // 20% Chance of Event
      if (Math.random() < 0.2) {
          const event = EVENTS[Math.floor(Math.random() * EVENTS.length)];
          addLog(`${event.title}: ${event.text}`, 'EVENT');

          // Apply Money Effect
          if (event.effect.money !== 0) {
              setMoney(m => m + event.effect.money);
          }

          // Apply Condition Damage (Rallýspil)
          if (event.effect.conditionDamage && selectedShipId) {
              setShips(prev => prev.map(s => s.id === selectedShipId ? { 
                  ...s, 
                  condition: Math.max(0, s.condition - event.effect.conditionDamage!) 
              } : s));
          }
      }

      advanceTime();
      setView('HQ');
  };

  // --- Theme Wrapper ---
  // We wrap the entire app output in the specific theme class
  const themeClass = era === '2020' ? 'theme-modern' : 'theme-vintage';

  const GameWrapper = ({ children }: { children: React.ReactNode }) => (
      <div className={themeClass}>
          {children}
      </div>
  );

  // --- Views ---

  if (view === 'SPLIT') {
      return (
          <div className="flex h-screen w-full overflow-hidden">
              {/* 1920 Side */}
              <div 
                  className="w-1/2 h-full bg-[#f6f1e1] text-[#2c1810] flex flex-col items-center justify-center p-8 relative cursor-pointer hover:bg-[#eaddcf] transition-colors group border-r-4 border-[#3e2723]"
                  onClick={() => handleSelectEra('1920')}
                  style={{ fontFamily: "'Playfair Display', serif" }}
              >
                  <div className="absolute inset-0 opacity-10 bg-[url('https://www.transparenttextures.com/patterns/aged-paper.png')]"></div>
                  <h1 className="text-6xl mb-4 font-bold tracking-widest group-hover:scale-110 transition-transform">1920</h1>
                  <h2 className="text-2xl italic mb-8">Upphaf Útgerðar</h2>
                  <Anchor size={64} className="text-[#3e2723] opacity-80" />
                  <div className="mt-8 text-sm uppercase tracking-widest border-t border-b border-[#3e2723] py-2">Smelltu til að velja</div>
              </div>

              {/* 2020 Side */}
              <div 
                  className="w-1/2 h-full bg-[#0f172a] text-white flex flex-col items-center justify-center p-8 relative cursor-pointer hover:bg-[#1e293b] transition-colors group"
                  onClick={() => handleSelectEra('2020')}
                  style={{ fontFamily: "ui-sans-serif, system-ui, sans-serif" }}
              >
                  <h1 className="text-6xl mb-4 font-extrabold tracking-tight text-blue-400 group-hover:scale-110 transition-transform">2020</h1>
                  <h2 className="text-2xl font-light mb-8 text-slate-300">Nútíma Tækni</h2>
                  <Bot size={64} className="text-blue-500 opacity-80" />
                  <div className="mt-8 text-sm uppercase tracking-widest text-slate-400 border-t border-b border-slate-700 py-2">Smelltu til að velja</div>
              </div>
          </div>
      );
  }

  if (view === 'TITLE') {
      return (
          <GameWrapper>
              <div className="min-h-screen flex flex-col items-center justify-center p-4 relative">
                  <div className="absolute inset-0 opacity-5 pointer-events-none bg-current"></div>

                  <div className="max-w-lg w-full text-center space-y-8 relative z-10">
                      <div className="space-y-2">
                          <h1 className="text-6xl font-header tracking-widest drop-shadow-sm">MAÍ GREIFINN</h1>
                          <div className="text-xl font-serif italic opacity-75">- Útvegsspilið {era} -</div>
                      </div>

                      <div className="paper-card p-8 rounded-sm transform rotate-1">
                          <label className="block text-left font-bold mb-2 font-header opacity-80">NAFN ÚTGERÐAR</label>
                          <input 
                              type="text" 
                              value={companyName}
                              onChange={(e) => setCompanyName(e.target.value)}
                              placeholder={`t.d. ${randomHint}`}
                              className="w-full bg-transparent border-b-2 border-current p-2 font-typewriter text-xl focus:outline-none placeholder-opacity-50"
                          />
                          <div className="text-left mt-2 text-xs opacity-60 font-serif italic">
                              Ábending: Prófaðu nöfn eins og „{randomHint}“.
                          </div>
                      </div>

                      <button 
                          onClick={handleStartGame}
                          className="btn-paper px-8 py-4 text-xl w-full hover:scale-[1.02] transition-transform flex items-center justify-center gap-3"
                      >
                          <Anchor size={24}/> Hefja Útgerð
                      </button>

                      <button 
                          onClick={() => setView('SPLIT')}
                          className="text-xs uppercase tracking-widest opacity-50 hover:opacity-100 hover:underline"
                      >
                          ← Breyta Tímabili
                      </button>
                  </div>
              </div>
          </GameWrapper>
      );
  }

  // HEADER COMPONENT (Shared)
  const Header = () => (
      <header className="bg-header p-4 shadow-lg sticky top-0 z-50 flex justify-between items-center transition-colors duration-300">
          <div className="flex items-center gap-4">
              <div className="w-12 h-12 bg-white/20 rounded-full flex items-center justify-center border-2 border-current">
                  <Anchor size={24}/>
              </div>
              <div>
                  <h2 className="font-header text-xl tracking-wide leading-none">{companyName}</h2>
                  <div className="text-xs opacity-70 font-typewriter mt-1">Stofnað {era}</div>
              </div>
          </div>
          <div className="flex items-center gap-6">
              <div className="text-right">
                  <div className="text-xs opacity-60 uppercase">Sjóður</div>
                  <div className="font-typewriter text-xl text-money">{money.toLocaleString()} kr.</div>
              </div>
              <div className="text-right hidden sm:block">
                  <div className="text-xs opacity-60 uppercase">Tími</div>
                  <div className="font-header text-xl capitalize">{getCurrentTimestamp()}</div>
              </div>
          </div>
      </header>
  );

  if (view === 'HQ') {
      return (
          <GameWrapper>
              <div className="min-h-screen pb-12">
                  <Header />

                  <main className="max-w-6xl mx-auto p-6 grid grid-cols-1 md:grid-cols-3 gap-6">

                      {/* Left Column: Fleet */}
                      <div className="md:col-span-2 space-y-6">
                          <div className="flex justify-between items-end border-b-2 border-current pb-2 mb-4 opacity-80">
                              <h3 className="font-header text-2xl flex items-center gap-2">
                                  <Ship className="text-accent"/> Flotinn
                              </h3>
                              <button onClick={() => setView('MARKET')} className="btn-paper px-4 py-2 text-sm flex items-center gap-2">
                                  <ShoppingCart size={14}/> Skipamarkaður
                              </button>
                          </div>

                          {ships.length === 0 ? (
                              <div className="paper-card p-8 text-center opacity-70 italic">
                                  Engin skip í flota. Farðu á markaðinn til að hefja rekstur.
                              </div>
                          ) : (
                              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                                  {ships.map(ship => (
                                      <div key={ship.id} className="paper-card p-5 relative group flex flex-col">
                                          {/* Document Header Line (Visual only for 1920 theme mostly via CSS) */}
                                          <div className="flex justify-between items-start mb-2 border-b border-gray-300/50 pb-2">
                                              <div className="text-xs font-bold opacity-50 font-typewriter uppercase tracking-wider">
                                                  SKJAL # {ship.id.slice(-4)}
                                              </div>
                                              <div className="text-xs font-bold text-accent font-typewriter bg-gray-100/50 px-2 py-0.5 rounded">
                                                  {ship.type}
                                              </div>
                                          </div>

                                          <h4 className="font-header text-xl font-bold mb-1 truncate">{ship.name}</h4>

                                          {/* Stats Block */}
                                          <div className="bg-black/5 p-3 rounded my-2 text-sm space-y-1 font-typewriter">
                                              <div className="flex justify-between">
                                                  <span className="opacity-70">Ástand:</span>
                                                  <span className={ship.condition < 50 ? 'text-red-600 font-bold' : ''}>
                                                      {ship.condition}%
                                                  </span>
                                              </div>
                                              <div className="flex justify-between">
                                                   <span className="opacity-70">Tæki:</span>
                                                   <span>{era === '2020' ? 'GPS / Sonar' : 'Dýptarmælir'}</span>
                                              </div>
                                          </div>

                                          <div className="mt-auto pt-2 flex items-center justify-between gap-2">
                                              {ship.condition < 100 && (
                                                  <button 
                                                      onClick={() => repairShip(ship.id)} 
                                                      className="text-xs underline text-blue-600 hover:text-blue-800 flex items-center gap-1"
                                                  >
                                                      <Wrench size={10} /> Viðgerð
                                                  </button>
                                              )}

                                              <button 
                                                  onClick={() => startFishing(ship.id)}
                                                  className="btn-paper px-3 py-1.5 text-xs flex items-center gap-1 ml-auto"
                                              >
                                                  <Waves size={12}/> {era === '2020' ? 'Hefja Veiðar' : 'Fara á Sjó'}
                                              </button>
                                          </div>
                                      </div>
                                  ))}
                              </div>
                          )}
                      </div>

                      {/* Right Column: Logbook */}
                      <div className="space-y-4">
                           <div className="flex items-center justify-between border-b-2 border-current pb-2 opacity-80">
                              <h3 className="font-header text-xl flex items-center gap-2">
                                  <FileText className="text-accent"/> Dagbók
                              </h3>
                           </div>

                           <div className="paper-card p-4 min-h-[400px] max-h-[600px] overflow-y-auto font-typewriter text-sm space-y-4">
                               {logs.length === 0 && <div className="text-center opacity-50 italic pt-10">Bókin er auð...</div>}
                               {logs.map(log => (
                                   <div key={log.id} className="border-b border-black/10 pb-2 last:border-0">
                                       <div className="text-[10px] opacity-60 uppercase tracking-wider mb-1 flex items-center gap-2">
                                           <span>{log.timestamp}</span>
                                           <div className="h-px flex-1 bg-current opacity-20"></div>
                                       </div>
                                       <div className={`${
                                           log.type === 'MONEY' ? 'text-money font-bold' : 
                                           log.type === 'ALERT' ? 'text-red-600 font-bold' : 
                                           log.type === 'EVENT' ? 'text-orange-600 font-bold' : ''
                                       }`}>
                                           {log.text}
                                       </div>
                                   </div>
                               ))}
                           </div>
                      </div>

                  </main>
              </div>
          </GameWrapper>
      );
  }

  if (view === 'MARKET') {
      return (
          <GameWrapper>
              <div className="min-h-screen pb-12">
                  <Header />
                  <main className="max-w-4xl mx-auto p-6">
                      <div className="flex items-center gap-4 mb-6">
                          <button onClick={() => setView('HQ')} className="btn-paper p-2 rounded-full">
                              <ArrowRight className="rotate-180" size={20}/>
                          </button>
                          <h2 className="font-header text-3xl text-accent">SKIPAMARKAÐUR</h2>
                      </div>

                      <div className="space-y-4">
                          {MARKET_SHIPS.map(model => (
                              <div key={model.id} className="paper-card p-6 flex flex-col sm:flex-row items-center gap-6">
                                  <div className="w-32 h-24 bg-black/5 border border-black/10 flex items-center justify-center text-accent">
                                      <Ship size={48} strokeWidth={1}/>
                                  </div>
                                  <div className="flex-1 text-center sm:text-left">
                                      <h3 className="font-header text-xl font-bold">{model.name}</h3>
                                      <div className="text-sm opacity-70 font-typewriter mt-1">
                                          Burðargeta: {model.capacity} tonn | Viðhald: {model.upkeep} kr/ár
                                      </div>
                                  </div>
                                  <div className="text-right">
                                      <div className="font-header text-2xl mb-2">{model.price.toLocaleString()} kr.</div>
                                      <button 
                                          onClick={() => handleBuyShip(model)}
                                          disabled={money < model.price}
                                          className="btn-paper w-full py-2 disabled:opacity-50 disabled:cursor-not-allowed"
                                      >
                                          KAUPA
                                      </button>
                                  </div>
                              </div>
                          ))}
                      </div>
                  </main>
              </div>
          </GameWrapper>
      );
  }

  if (view === 'FISHING') {
      return (
          <GameWrapper>
            <div className={`min-h-screen relative text-white ${era === '2020' ? 'bg-slate-900' : 'bg-[#001020]'}`}>
                  <div className="absolute inset-0 opacity-20 bg-[url('https://www.transparenttextures.com/patterns/nautical-leather.png')]"></div>

                  <div className="relative z-10 max-w-2xl mx-auto p-6 flex flex-col h-screen">

                      {/* Fishing Header */}
                      <div className="flex justify-between items-center mb-8 bg-black/40 backdrop-blur p-4 border border-white/20 rounded-sm shadow-xl">
                          <div>
                              <h2 className="font-header text-xl text-yellow-100">Á VEIÐUM</h2>
                              <div className="text-xs text-white/70">{ships.find(s => s.id === selectedShipId)?.name}</div>
                          </div>
                          <div className="text-right">
                              <div className="text-xs text-white/70">Afli í lest</div>
                              <div className="font-typewriter text-2xl text-green-400">{currentCatch.toLocaleString()} kr.</div>
                          </div>
                      </div>

                      {/* Grid */}
                      <div className="flex-1 flex items-center justify-center">
                          <div className="grid grid-cols-3 gap-3 w-full max-w-md aspect-square">
                              {fishingGrid.map((tile) => (
                                  <button
                                      key={tile.id}
                                      onClick={() => fishTile(tile)}
                                      disabled={tile.status === 'REVEALED'}
                                      className={`relative rounded-sm border-2 transition-all duration-500 overflow-hidden ${
                                          tile.status === 'HIDDEN' 
                                          ? (era === '2020' ? 'bg-blue-600 border-blue-500 hover:bg-blue-500' : 'bg-[#0d47a1] border-[#1565c0] hover:bg-[#1565c0]') 
                                          : 'bg-[#f6f1e1] border-[#8d6e63]'
                                      }`}
                                  >
                                      {tile.status === 'HIDDEN' ? (
                                          <div className="absolute inset-0 flex items-center justify-center opacity-20">
                                              <Waves size={32} className="text-white animate-pulse"/>
                                          </div>
                                      ) : (
                                          <div className="flex flex-col items-center justify-center h-full animate-[fadeIn_0.5s] text-slate-900">
                                              {tile.content === 'EMPTY' && <div className="text-[#a1887f] font-typewriter text-xs">Tómt</div>}
                                              {tile.content === 'FISH' && <Fish size={32} className="text-[#1b5e20] mb-1"/>}
                                              {tile.content === 'BIG_CATCH' && <div className="text-[#f57f17]"><Fish size={40}/><Sparkles size={16} className="absolute top-2 right-2"/></div>}
                                              {tile.content === 'DANGER' && <AlertTriangle size={32} className="text-[#b71c1c]"/>}

                                              {tile.value !== 0 && (
                                                  <div className={`text-xs font-bold mt-1 ${tile.value > 0 ? 'text-[#1b5e20]' : 'text-[#b71c1c]'}`}>
                                                      {tile.value > 0 ? '+' : ''}{tile.value.toLocaleString()}
                                                  </div>
                                              )}
                                          </div>
                                      )}
                                  </button>
                              ))}
                          </div>
                      </div>

                      {/* Controls */}
                      <div className="mt-8 space-y-4">
                          <div className="flex gap-4">
                              <button 
                                  onClick={useDepthMeter}
                                  disabled={money < DEPTH_METER_COST}
                                  className="flex-1 btn-paper py-4 bg-slate-800 border-slate-700 text-slate-200 flex flex-col items-center justify-center gap-1 hover:bg-slate-700 disabled:opacity-50"
                              >
                                  <div className="flex items-center gap-2">
                                      <Search size={18} /> {era === '2020' ? 'SONAR SKANNI' : 'DÝPTARMÆLIR'}
                                  </div>
                                  <div className="text-[10px] text-slate-400">-5.000 kr. / notkun</div>
                              </button>

                              <button 
                                  onClick={endFishing}
                                  className="flex-1 btn-paper py-4 bg-green-900 border-green-800 text-white flex flex-col items-center justify-center gap-1 hover:bg-green-800"
                              >
                                  <div className="flex items-center gap-2">
                                      <Anchor size={18} /> LANDA & HEIM
                                  </div>
                                  <div className="text-[10px] text-green-300">Ljúka veiðiferð</div>
                              </button>
                          </div>
                      </div>

                  </div>
              </div>
          </GameWrapper>
      );
  }

  return null;
}

const root = createRoot(document.getElementById('root')!);
root.render(<App />);

import React, { useState, useEffect, useRef } from 'react';
import { createRoot } from 'react-dom/client';
import { Ship, Anchor, Fish, Coins, User, Waves, Bot, Play, Sparkles, AlertTriangle, X, ScrollText, Save, Trash2, ArrowRight, ShoppingCart, Map, DollarSign, Search, Calendar, Briefcase, FileText, Wrench, Clock, Battery } from 'lucide-react';

// --- Configuration ---

const START_MONEY = 500000;
const DEPTH_METER_COST = 5000;
const SAVE_KEY = 'maigreifinn_split_v1';
const SEASONS = ["Vor", "Sumar", "Haust", "Vetur"];

// Parody Names & Data
const COMPANY_NAMES = [
  "Brimverzlun hf.", "Hafdráttur h/f", "Togglarinn ehf.", "Sjómannafélagið Víkingur",
  "Útgerðarfélag Akureyrar", "Fiskvinnslan Alda", "Norðurljósavinnslan", "Vestfjarða-Skel hf.",
  "Ísbjörninn hf.", "Skeljungur Útgerð", "IceFresh Seafood", "Arctic Catch"
];

const SHIP_NAMES = [
  "MS Brimrós", "MS Togglari", "MS Djúpvera", "Guðrún Björg", "Sæljónið", 
  "Haförninn", "Sjöstjarnan", "Kjölurinn", "Aldan", "Vonin", "Víkingur", "Stormur"
];

type EventType = {
  id: string;
  title: string;
  text: string;
  type: 'BAD' | 'GOOD';
  effect: {
    money: number;
    rep: number;
    conditionDamage?: number; // Damage to the active ship
  }
};

const EVENTS: EventType[] = [
  { id: 'investigation', title: "Rannsóknarnefnd", text: "☠️ Hættuspil! Rannsóknarnefnd sjávarútvegsins mætir á svæðið.", effect: { money: 0, rep: -3 }, type: 'BAD' },
  { id: 'bank', title: "Bankinn hringir", text: "🏦 Útvegsspils-andi svífur yfir vötnum. Bankastjórinn vill sitt.", effect: { money: -25000, rep: 0 }, type: 'BAD' },
  { id: 'tire', title: "Rallýspil", text: "🏁 Rallýspil! Dekkið springur á bryggjubílnum og varahlutir tefjast. Skipið fær slæma meðferð.", effect: { money: 0, rep: 0, conditionDamage: 10 }, type: 'BAD' },
  { id: 'play', title: "Aktjóneri", text: "🎭 Leikritið í höfninni slær í gegn. Allir kátir.", effect: { money: 5000, rep: 2 }, type: 'GOOD' },
  { id: 'omar', title: "Ómar-style", text: "📻 „Þetta reddast“. Bjartsýni skilar sér í kassan.", effect: { money: 15000, rep: 1 }, type: 'GOOD' }
];

const MARKET_SHIPS = [
  { id: 1, name: "Trilla (Opinn)", type: 'TRILLA', price: 50000, capacity: 5, upkeep: 1000 },
  { id: 2, name: "Kvótakóngur", type: 'TRAWLER', price: 150000, capacity: 15, upkeep: 5000 },
  { id: 3, name: "MS Togglari", type: 'TRAWLER', price: 300000, capacity: 30, upkeep: 10000 },
  { id: 4, name: "Gullskipið", type: 'YACHT', price: 1000000, capacity: 50, upkeep: 25000 },
];

// --- Types ---

type GameView = 'SPLIT' | 'TITLE' | 'HQ' | 'MARKET' | 'FISHING';
type Era = '1920' | '2020';

interface ShipItem {
  id: string; // Unique ID
  modelId: number;
  name: string;
  type: string;
  condition: number; // 0-100%
  equipped: boolean; // Has depth meter?
}

interface LogEntry {
  id: number;
  timestamp: string; // "Vor 1955"
  text: string;
  type: 'INFO' | 'MONEY' | 'ALERT' | 'EVENT';
}

interface FishingTile {
  id: number;
  status: 'HIDDEN' | 'REVEALED';
  content: 'FISH' | 'EMPTY' | 'DANGER' | 'BIG_CATCH';
  value: number;
}

// --- Helper Components ---

const GameWrapper = ({ children, era }: { children: React.ReactNode; era: Era }) => {
  const themeClass = era === '2020' ? 'theme-modern' : 'theme-vintage';
  return (
      <div className={themeClass}>
          {children}
      </div>
  );
};

// --- Main Component ---

function App() {
  // State
  const [view, setView] = useState<GameView>('SPLIT');
  const [era, setEra] = useState<Era>('1920');
  const [companyName, setCompanyName] = useState("");
  const [money, setMoney] = useState(START_MONEY);
  const [ships, setShips] = useState<ShipItem[]>([]);

  // Time System
  const [year, setYear] = useState(1920);
  const [seasonIndex, setSeasonIndex] = useState(0); // 0=Vor, 1=Sumar, 2=Haust, 3=Vetur

  const [logs, setLogs] = useState<LogEntry[]>([]);

  // Fishing State
  const [fishingGrid, setFishingGrid] = useState<FishingTile[]>([]);
  const [selectedShipId, setSelectedShipId] = useState<string | null>(null);
  const [currentCatch, setCurrentCatch] = useState(0);

  // UI State
  const [randomHint, setRandomHint] = useState("");

  // Initialize
  useEffect(() => {
    setRandomHint(COMPANY_NAMES[Math.floor(Math.random() * COMPANY_NAMES.length)]);

    const saved = localStorage.getItem(SAVE_KEY);
    if (saved) {
      try {
        const data = JSON.parse(saved);
        if (data.companyName) {
            setCompanyName(data.companyName);
            setMoney(data.money);
            setShips(data.ships);
            setYear(data.year);
            setSeasonIndex(data.seasonIndex || 0);
            setLogs(data.logs);
            setEra(data.era || '1920');
            setView('HQ');
        }
      } catch(e) {}
    }
  }, []);

  // Autosave
  useEffect(() => {
    if (view !== 'SPLIT' && view !== 'TITLE') {
       const timer = setTimeout(() => {
          localStorage.setItem(SAVE_KEY, JSON.stringify({ companyName, money, ships, year, seasonIndex, logs, era }));
       }, 1000);
       return () => clearTimeout(timer);
    }
  }, [companyName, money, ships, year, seasonIndex, logs, view, era]);

  const getCurrentTimestamp = () => `${SEASONS[seasonIndex]} ${year}`;

  const addLog = (text: string, type: LogEntry['type'] = 'INFO') => {
      setLogs(prev => [{
          id: Date.now(),
          timestamp: getCurrentTimestamp(),
          text,
          type
      }, ...prev]);
  };

  const advanceTime = () => {
      setSeasonIndex(prev => {
          const next = prev + 1;
          if (next >= SEASONS.length) {
              setYear(y => y + 1);
              return 0;
          }
          return next;
      });
  };

  const handleSelectEra = (selectedEra: Era) => {
      setEra(selectedEra);
      setYear(parseInt(selectedEra));
      setView('TITLE');
  };

  const handleStartGame = () => {
      const finalName = companyName || randomHint;
      setCompanyName(finalName);
      addLog(`Útgerðin ${finalName} stofnuð (${era}).`, 'INFO');
      setView('HQ');
  };

  const handleBuyShip = (shipModel: typeof MARKET_SHIPS[0]) => {
      if (money >= shipModel.price) {
          setMoney(m => m - shipModel.price);
          const newShip: ShipItem = {
              id: Date.now().toString(),
              modelId: shipModel.id,
              name: SHIP_NAMES[Math.floor(Math.random() * SHIP_NAMES.length)] + ` ${Math.floor(Math.random() * 100)}`,
              type: shipModel.type,
              condition: 100,
              equipped: false
          };
          setShips(prev => [...prev, newShip]);
          addLog(`Keypti ${newShip.name} (${shipModel.name}) fyrir ${shipModel.price.toLocaleString()} kr.`, 'MONEY');
      }
  };

  const repairShip = (shipId: string) => {
      const ship = ships.find(s => s.id === shipId);
      if (!ship || ship.condition >= 100) return;

      const cost = Math.floor((100 - ship.condition) * 500); // 500kr per 1%
      if (money >= cost) {
          setMoney(m => m - cost);
          setShips(prev => prev.map(s => s.id === shipId ? { ...s, condition: 100 } : s));
          addLog(`Gerði við ${ship.name} fyrir ${cost.toLocaleString()} kr.`, 'MONEY');
      }
  };

  const startFishing = (shipId: string) => {
      const ship = ships.find(s => s.id === shipId);
      if (ship && ship.condition < 20) {
          alert("Skip er í of slæmu ástandi til að fara á sjó! Gerðu við það fyrst.");
          return;
      }

      setSelectedShipId(shipId);
      // Generate Grid
      const newGrid: FishingTile[] = Array(9).fill(null).map((_, i) => {
          const rand = Math.random();
          let content: FishingTile['content'] = 'EMPTY';
          let value = 0;

          if (rand > 0.7) { content = 'FISH'; value = 50000; }
          else if (rand > 0.9) { content = 'BIG_CATCH'; value = 150000; }
          else if (rand < 0.1) { content = 'DANGER'; value = -10000; }

          return { id: i, status: 'HIDDEN', content, value };
      });
      setFishingGrid(newGrid);
      setCurrentCatch(0);
      setView('FISHING');
      addLog(`Hélt til veiða á ${ship?.name}.`, 'INFO');
  };

  const useDepthMeter = () => {
      if (money >= DEPTH_METER_COST) {
          setMoney(m => m - DEPTH_METER_COST);
          // Find unrevealed tiles
          const hidden = fishingGrid.filter(t => t.status === 'HIDDEN');
          if (hidden.length > 0) {
              const target = hidden[Math.floor(Math.random() * hidden.length)];
              setFishingGrid(prev => prev.map(t => t.id === target.id ? { ...t, status: 'REVEALED' } : t));
          }
      }
  };

  const fishTile = (tile: FishingTile) => {
      if (tile.status === 'REVEALED' && (tile.content === 'EMPTY' || tile.content === 'DANGER')) {
         // Fishing revealed bad tiles is allowed but usually has no gain or is bad
      }

      const updatedGrid = fishingGrid.map(t => t.id === tile.id ? { ...t, status: 'REVEALED' as const } : t);
      setFishingGrid(updatedGrid);

      if (tile.content === 'DANGER') {
          addLog("Hætta! Netin festust eða veður versnaði.", 'ALERT');
          setCurrentCatch(c => c - 5000);
          // Small immediate damage on danger tiles
          if (selectedShipId) {
             setShips(prev => prev.map(s => s.id === selectedShipId ? { ...s, condition: Math.max(0, s.condition - 5) } : s));
          }
      } else if (tile.content === 'FISH' || tile.content === 'BIG_CATCH') {
          setCurrentCatch(c => c + tile.value);
      }
  };

  const endFishing = () => {
      // Payout
      setMoney(m => m + currentCatch);
      addLog(`Löndun: ${currentCatch.toLocaleString()} kr. komu í kassann.`, 'MONEY');

      // Wear and tear (normal)
      if (selectedShipId) {
          setShips(prev => prev.map(s => s.id === selectedShipId ? { ...s, condition: Math.max(0, s.condition - 2) } : s));
      }

      // 20% Chance of Event
      if (Math.random() < 0.2) {
          const event = EVENTS[Math.floor(Math.random() * EVENTS.length)];
          addLog(`${event.title}: ${event.text}`, 'EVENT');

          // Apply Money Effect
          if (event.effect.money !== 0) {
              setMoney(m => m + event.effect.money);
          }

          // Apply Condition Damage (Rallýspil)
          if (event.effect.conditionDamage && selectedShipId) {
              setShips(prev => prev.map(s => s.id === selectedShipId ? { 
                  ...s, 
                  condition: Math.max(0, s.condition - event.effect.conditionDamage!) 
              } : s));
          }
      }

      advanceTime();
      setView('HQ');
  };

  // --- Views ---

  if (view === 'SPLIT') {
      return (
          <div className="flex h-screen w-full overflow-hidden">
              {/* 1920 Side */}
              <div 
                  className="w-1/2 h-full bg-[#f6f1e1] text-[#2c1810] flex flex-col items-center justify-center p-8 relative cursor-pointer hover:bg-[#eaddcf] transition-colors group border-r-4 border-[#3e2723]"
                  onClick={() => handleSelectEra('1920')}
                  style={{ fontFamily: "'Playfair Display', serif" }}
              >
                  <div className="absolute inset-0 opacity-10 bg-[url('https://www.transparenttextures.com/patterns/aged-paper.png')]"></div>
                  <h1 className="text-6xl mb-4 font-bold tracking-widest group-hover:scale-110 transition-transform">1920</h1>
                  <h2 className="text-2xl italic mb-8">Upphaf Útgerðar</h2>
                  <Anchor size={64} className="text-[#3e2723] opacity-80" />
                  <div className="mt-8 text-sm uppercase tracking-widest border-t border-b border-[#3e2723] py-2">Smelltu til að velja</div>
              </div>

              {/* 2020 Side */}
              <div 
                  className="w-1/2 h-full bg-[#0f172a] text-white flex flex-col items-center justify-center p-8 relative cursor-pointer hover:bg-[#1e293b] transition-colors group"
                  onClick={() => handleSelectEra('2020')}
                  style={{ fontFamily: "ui-sans-serif, system-ui, sans-serif" }}
              >
                  <h1 className="text-6xl mb-4 font-extrabold tracking-tight text-blue-400 group-hover:scale-110 transition-transform">2020</h1>
                  <h2 className="text-2xl font-light mb-8 text-slate-300">Nútíma Tækni</h2>
                  <Bot size={64} className="text-blue-500 opacity-80" />
                  <div className="mt-8 text-sm uppercase tracking-widest text-slate-400 border-t border-b border-slate-700 py-2">Smelltu til að velja</div>
              </div>
          </div>
      );
  }

  if (view === 'TITLE') {
      return (
          <GameWrapper era={era}>
              <div className="min-h-screen flex flex-col items-center justify-center p-4 relative">
                  <div className="absolute inset-0 opacity-5 pointer-events-none bg-current"></div>

                  <div className="max-w-lg w-full text-center space-y-8 relative z-10">
                      <div className="space-y-2">
                          <h1 className="text-6xl font-header tracking-widest drop-shadow-sm">MAÍ GREIFINN</h1>
                          <div className="text-xl font-serif italic opacity-75">- Útvegsspilið {era} -</div>
                      </div>

                      <div className="paper-card p-8 rounded-sm transform rotate-1">
                          <label className="block text-left font-bold mb-2 font-header opacity-80">NAFN ÚTGERÐAR</label>
                          <input 
                              type="text" 
                              value={companyName}
                              onChange={(e) => setCompanyName(e.target.value)}
                              placeholder={`t.d. ${randomHint}`}
                              className="w-full bg-transparent border-b-2 border-current p-2 font-typewriter text-xl focus:outline-none placeholder-opacity-50"
                          />
                          <div className="text-left mt-2 text-xs opacity-60 font-serif italic">
                              Ábending: Prófaðu nöfn eins og „{randomHint}“.
                          </div>
                      </div>

                      <button 
                          onClick={handleStartGame}
                          className="btn-paper px-8 py-4 text-xl w-full hover:scale-[1.02] transition-transform flex items-center justify-center gap-3"
                      >
                          <Anchor size={24}/> Hefja Útgerð
                      </button>

                      <button 
                          onClick={() => setView('SPLIT')}
                          className="text-xs uppercase tracking-widest opacity-50 hover:opacity-100 hover:underline"
                      >
                          ← Breyta Tímabili
                      </button>
                  </div>
              </div>
          </GameWrapper>
      );
  }

  // HEADER COMPONENT (Shared)
  const Header = () => (
      <header className="bg-header p-4 shadow-lg sticky top-0 z-50 flex justify-between items-center transition-colors duration-300">
          <div className="flex items-center gap-4">
              <div className="w-12 h-12 bg-white/20 rounded-full flex items-center justify-center border-2 border-current">
                  <Anchor size={24}/>
              </div>
              <div>
                  <h2 className="font-header text-xl tracking-wide leading-none">{companyName}</h2>
                  <div className="text-xs opacity-70 font-typewriter mt-1">Stofnað {era}</div>
              </div>
          </div>
          <div className="flex items-center gap-6">
              <div className="text-right">
                  <div className="text-xs opacity-60 uppercase">Sjóður</div>
                  <div className="font-typewriter text-xl text-money">{money.toLocaleString()} kr.</div>
              </div>
              <div className="text-right hidden sm:block">
                  <div className="text-xs opacity-60 uppercase">Tími</div>
                  <div className="font-header text-xl capitalize">{getCurrentTimestamp()}</div>
              </div>
          </div>
      </header>
  );

  if (view === 'HQ') {
      return (
          <GameWrapper era={era}>
              <div className="min-h-screen pb-12">
                  <Header />

                  <main className="max-w-6xl mx-auto p-6 grid grid-cols-1 md:grid-cols-3 gap-6">

                      {/* Left Column: Fleet */}
                      <div className="md:col-span-2 space-y-6">
                          <div className="flex justify-between items-end border-b-2 border-current pb-2 mb-4 opacity-80">
                              <h3 className="font-header text-2xl flex items-center gap-2">
                                  <Ship className="text-accent"/> Flotinn
                              </h3>
                              <button onClick={() => setView('MARKET')} className="btn-paper px-4 py-2 text-sm flex items-center gap-2">
                                  <ShoppingCart size={14}/> Skipamarkaður
                              </button>
                          </div>

                          {ships.length === 0 ? (
                              <div className="paper-card p-8 text-center opacity-70 italic">
                                  Engin skip í flota. Farðu á markaðinn til að hefja rekstur.
                              </div>
                          ) : (
                              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                                  {ships.map(ship => (
                                      <div key={ship.id} className="paper-card p-5 relative group flex flex-col">
                                          {/* Document Header Line (Visual only for 1920 theme mostly via CSS) */}
                                          <div className="flex justify-between items-start mb-2 border-b border-gray-300/50 pb-2">
                                              <div className="text-xs font-bold opacity-50 font-typewriter uppercase tracking-wider">
                                                  SKJAL # {ship.id.slice(-4)}
                                              </div>
                                              <div className="text-xs font-bold text-accent font-typewriter bg-gray-100/50 px-2 py-0.5 rounded">
                                                  {ship.type}
                                              </div>
                                          </div>

                                          <h4 className="font-header text-xl font-bold mb-1 truncate">{ship.name}</h4>

                                          {/* Stats Block */}
                                          <div className="bg-black/5 p-3 rounded my-2 text-sm space-y-1 font-typewriter">
                                              <div className="flex justify-between">
                                                  <span className="opacity-70">Ástand:</span>
                                                  <span className={ship.condition < 50 ? 'text-red-600 font-bold' : ''}>
                                                      {ship.condition}%
                                                  </span>
                                              </div>
                                              <div className="flex justify-between">
                                                   <span className="opacity-70">Tæki:</span>
                                                   <span>{era === '2020' ? 'GPS / Sonar' : 'Dýptarmælir'}</span>
                                              </div>
                                          </div>

                                          <div className="mt-auto pt-2 flex items-center justify-between gap-2">
                                              {ship.condition < 100 && (
                                                  <button 
                                                      onClick={() => repairShip(ship.id)} 
                                                      className="text-xs underline text-blue-600 hover:text-blue-800 flex items-center gap-1"
                                                  >
                                                      <Wrench size={10} /> Viðgerð
                                                  </button>
                                              )}

                                              <button 
                                                  onClick={() => startFishing(ship.id)}
                                                  className="btn-paper px-3 py-1.5 text-xs flex items-center gap-1 ml-auto"
                                              >
                                                  <Waves size={12}/> {era === '2020' ? 'Hefja Veiðar' : 'Fara á Sjó'}
                                              </button>
                                          </div>
                                      </div>
                                  ))}
                              </div>
                          )}
                      </div>

                      {/* Right Column: Logbook */}
                      <div className="space-y-4">
                           <div className="flex items-center justify-between border-b-2 border-current pb-2 opacity-80">
                              <h3 className="font-header text-xl flex items-center gap-2">
                                  <FileText className="text-accent"/> Dagbók
                              </h3>
                           </div>

                           <div className="paper-card p-4 min-h-[400px] max-h-[600px] overflow-y-auto font-typewriter text-sm space-y-4">
                               {logs.length === 0 && <div className="text-center opacity-50 italic pt-10">Bókin er auð...</div>}
                               {logs.map(log => (
                                   <div key={log.id} className="border-b border-black/10 pb-2 last:border-0">
                                       <div className="text-[10px] opacity-60 uppercase tracking-wider mb-1 flex items-center gap-2">
                                           <span>{log.timestamp}</span>
                                           <div className="h-px flex-1 bg-current opacity-20"></div>
                                       </div>
                                       <div className={`${
                                           log.type === 'MONEY' ? 'text-money font-bold' : 
                                           log.type === 'ALERT' ? 'text-red-600 font-bold' : 
                                           log.type === 'EVENT' ? 'text-orange-600 font-bold' : ''
                                       }`}>
                                           {log.text}
                                       </div>
                                   </div>
                               ))}
                           </div>
                      </div>

                  </main>
              </div>
          </GameWrapper>
      );
  }

  if (view === 'MARKET') {
      return (
          <GameWrapper era={era}>
              <div className="min-h-screen pb-12">
                  <Header />
                  <main className="max-w-4xl mx-auto p-6">
                      <div className="flex items-center gap-4 mb-6">
                          <button onClick={() => setView('HQ')} className="btn-paper p-2 rounded-full">
                              <ArrowRight className="rotate-180" size={20}/>
                          </button>
                          <h2 className="font-header text-3xl text-accent">SKIPAMARKAÐUR</h2>
                      </div>

                      <div className="space-y-4">
                          {MARKET_SHIPS.map(model => (
                              <div key={model.id} className="paper-card p-6 flex flex-col sm:flex-row items-center gap-6">
                                  <div className="w-32 h-24 bg-black/5 border border-black/10 flex items-center justify-center text-accent">
                                      <Ship size={48} strokeWidth={1}/>
                                  </div>
                                  <div className="flex-1 text-center sm:text-left">
                                      <h3 className="font-header text-xl font-bold">{model.name}</h3>
                                      <div className="text-sm opacity-70 font-typewriter mt-1">
                                          Burðargeta: {model.capacity} tonn | Viðhald: {model.upkeep} kr/ár
                                      </div>
                                  </div>
                                  <div className="text-right">
                                      <div className="font-header text-2xl mb-2">{model.price.toLocaleString()} kr.</div>
                                      <button 
                                          onClick={() => handleBuyShip(model)}
                                          disabled={money < model.price}
                                          className="btn-paper w-full py-2 disabled:opacity-50 disabled:cursor-not-allowed"
                                      >
                                          KAUPA
                                      </button>
                                  </div>
                              </div>
                          ))}
                      </div>
                  </main>
              </div>
          </GameWrapper>
      );
  }

  if (view === 'FISHING') {
      return (
          <GameWrapper era={era}>
            <div className={`min-h-screen relative text-white ${era === '2020' ? 'bg-slate-900' : 'bg-[#001020]'}`}>
                  <div className="absolute inset-0 opacity-20 bg-[url('https://www.transparenttextures.com/patterns/nautical-leather.png')]"></div>

                  <div className="relative z-10 max-w-2xl mx-auto p-6 flex flex-col h-screen">

                      {/* Fishing Header */}
                      <div className="flex justify-between items-center mb-8 bg-black/40 backdrop-blur p-4 border border-white/20 rounded-sm shadow-xl">
                          <div>
                              <h2 className="font-header text-xl text-yellow-100">Á VEIÐUM</h2>
                              <div className="text-xs text-white/70">{ships.find(s => s.id === selectedShipId)?.name}</div>
                          </div>
                          <div className="text-right">
                              <div className="text-xs text-white/70">Afli í lest</div>
                              <div className="font-typewriter text-2xl text-green-400">{currentCatch.toLocaleString()} kr.</div>
                          </div>
                      </div>

                      {/* Grid */}
                      <div className="flex-1 flex items-center justify-center">
                          <div className="grid grid-cols-3 gap-3 w-full max-w-md aspect-square">
                              {fishingGrid.map((tile) => (
                                  <button
                                      key={tile.id}
                                      onClick={() => fishTile(tile)}
                                      disabled={tile.status === 'REVEALED'}
                                      className={`relative rounded-sm border-2 transition-all duration-500 overflow-hidden ${
                                          tile.status === 'HIDDEN' 
                                          ? (era === '2020' ? 'bg-blue-600 border-blue-500 hover:bg-blue-500' : 'bg-[#0d47a1] border-[#1565c0] hover:bg-[#1565c0]') 
                                          : 'bg-[#f6f1e1] border-[#8d6e63]'
                                      }`}
                                  >
                                      {tile.status === 'HIDDEN' ? (
                                          <div className="absolute inset-0 flex items-center justify-center opacity-20">
                                              <Waves size={32} className="text-white animate-pulse"/>
                                          </div>
                                      ) : (
                                          <div className="flex flex-col items-center justify-center h-full animate-[fadeIn_0.5s] text-slate-900">
                                              {tile.content === 'EMPTY' && <div className="text-[#a1887f] font-typewriter text-xs">Tómt</div>}
                                              {tile.content === 'FISH' && <Fish size={32} className="text-[#1b5e20] mb-1"/>}
                                              {tile.content === 'BIG_CATCH' && <div className="text-[#f57f17]"><Fish size={40}/><Sparkles size={16} className="absolute top-2 right-2"/></div>}
                                              {tile.content === 'DANGER' && <AlertTriangle size={32} className="text-[#b71c1c]"/>}

                                              {tile.value !== 0 && (
                                                  <div className={`text-xs font-bold mt-1 ${tile.value > 0 ? 'text-[#1b5e20]' : 'text-[#b71c1c]'}`}>
                                                      {tile.value > 0 ? '+' : ''}{tile.value.toLocaleString()}
                                                  </div>
                                              )}
                                          </div>
                                      )}
                                  </button>
                              ))}
                          </div>
                      </div>

                      {/* Controls */}
                      <div className="mt-8 space-y-4">
                          <div className="flex gap-4">
                              <button 
                                  onClick={useDepthMeter}
                                  disabled={money < DEPTH_METER_COST}
                                  className="flex-1 btn-paper py-4 bg-slate-800 border-slate-700 text-slate-200 flex flex-col items-center justify-center gap-1 hover:bg-slate-700 disabled:opacity-50"
                              >
                                  <div className="flex items-center gap-2">
                                      <Search size={18} /> {era === '2020' ? 'SONAR SKANNI' : 'DÝPTARMÆLIR'}
                                  </div>
                                  <div className="text-[10px] text-slate-400">-5.000 kr. / notkun</div>
                              </button>

                              <button 
                                  onClick={endFishing}
                                  className="flex-1 btn-paper py-4 bg-green-900 border-green-800 text-white flex flex-col items-center justify-center gap-1 hover:bg-green-800"
                              >
                                  <div className="flex items-center gap-2">
                                      <Anchor size={18} /> LANDA & HEIM
                                  </div>
                                  <div className="text-[10px] text-green-300">Ljúka veiðiferð</div>
                              </button>
                          </div>
                      </div>

                  </div>
              </div>
          </GameWrapper>
      );
  }

  return null;
}

const root = createRoot(document.getElementById('root')!);
root.render(<App />);

import React, { useState, useEffect, useRef } from 'react';
import { createRoot } from 'react-dom/client';
import { Ship, Anchor, Fish, Coins, User, Waves, Bot, Play, Sparkles, AlertTriangle, X, ScrollText, Save, Trash2, ArrowRight, ShoppingCart, Map, DollarSign, Search, Calendar, Briefcase, FileText, Wrench, Clock, Battery } from 'lucide-react';

// --- Configuration ---

const START_MONEY = 500000;
const DEPTH_METER_COST = 5000;
const SAVE_KEY = 'maigreifinn_split_v1';
const SEASONS = ["Vor", "Sumar", "Haust", "Vetur"];

// Parody Names & Data
const COMPANY_NAMES = [
  "Brimverzlun hf.", "Hafdráttur h/f", "Togglarinn ehf.", "Sjómannafélagið Víkingur",
  "Útgerðarfélag Akureyrar", "Fiskvinnslan Alda", "Norðurljósavinnslan", "Vestfjarða-Skel hf.",
  "Ísbjörninn hf.", "Skeljungur Útgerð", "IceFresh Seafood", "Arctic Catch"
];

const SHIP_NAMES = [
  "MS Brimrós", "MS Togglari", "MS Djúpvera", "Guðrún Björg", "Sæljónið", 
  "Haförninn", "Sjöstjarnan", "Kjölurinn", "Aldan", "Vonin", "Víkingur", "Stormur"
];

type EventType = {
  id: string;
  title: string;
  text: string;
  type: 'BAD' | 'GOOD';
  effect: {
    money: number;
    rep: number;
    conditionDamage?: number; // Damage to the active ship
  }
};

const EVENTS: EventType[] = [
  { id: 'investigation', title: "Rannsóknarnefnd", text: "☠️ Hættuspil! Rannsóknarnefnd sjávarútvegsins mætir á svæðið.", effect: { money: 0, rep: -3 }, type: 'BAD' },
  { id: 'bank', title: "Bankinn hringir", text: "🏦 Útvegsspils-andi svífur yfir vötnum. Bankastjórinn vill sitt.", effect: { money: -25000, rep: 0 }, type: 'BAD' },
  { id: 'tire', title: "Rallýspil", text: "🏁 Rallýspil! Dekkið springur á bryggjubílnum og varahlutir tefjast. Skipið fær slæma meðferð.", effect: { money: 0, rep: 0, conditionDamage: 10 }, type: 'BAD' },
  { id: 'play', title: "Aktjóneri", text: "🎭 Leikritið í höfninni slær í gegn. Allir kátir.", effect: { money: 5000, rep: 2 }, type: 'GOOD' },
  { id: 'omar', title: "Ómar-style", text: "📻 „Þetta reddast“. Bjartsýni skilar sér í kassan.", effect: { money: 15000, rep: 1 }, type: 'GOOD' }
];

const MARKET_SHIPS = [
  { id: 1, name: "Trilla (Opinn)", type: 'TRILLA', price: 50000, capacity: 5, upkeep: 1000 },
  { id: 2, name: "Kvótakóngur", type: 'TRAWLER', price: 150000, capacity: 15, upkeep: 5000 },
  { id: 3, name: "MS Togglari", type: 'TRAWLER', price: 300000, capacity: 30, upkeep: 10000 },
  { id: 4, name: "Gullskipið", type: 'YACHT', price: 1000000, capacity: 50, upkeep: 25000 },
];

// --- Types ---

type GameView = 'SPLIT' | 'TITLE' | 'HQ' | 'MARKET' | 'FISHING';
type Era = '1920' | '2020';

interface ShipItem {
  id: string; // Unique ID
  modelId: number;
  name: string;
  type: string;
  condition: number; // 0-100%
  equipped: boolean; // Has depth meter?
}

interface LogEntry {
  id: number;
  timestamp: string; // "Vor 1955"
  text: string;
  type: 'INFO' | 'MONEY' | 'ALERT' | 'EVENT';
}

interface FishingTile {
  id: number;
  status: 'HIDDEN' | 'REVEALED';
  content: 'FISH' | 'EMPTY' | 'DANGER' | 'BIG_CATCH';
  value: number;
}

// --- Helper Components ---

const GameWrapper = ({ children, era }: { children: React.ReactNode; era: Era }) => {
  const themeClass = era === '2020' ? 'theme-modern' : 'theme-vintage';
  return (
      <div className={themeClass}>
          {children}
      </div>
  );
};

// --- Main Component ---

function App() {
  // State
  const [view, setView] = useState<GameView>('SPLIT');
  const [era, setEra] = useState<Era>('1920');
  const [companyName, setCompanyName] = useState("");
  const [money, setMoney] = useState(START_MONEY);
  const [ships, setShips] = useState<ShipItem[]>([]);

  // Time System
  const [year, setYear] = useState(1920);
  const [seasonIndex, setSeasonIndex] = useState(0); // 0=Vor, 1=Sumar, 2=Haust, 3=Vetur

  const [logs, setLogs] = useState<LogEntry[]>([]);

  // Fishing State
  const [fishingGrid, setFishingGrid] = useState<FishingTile[]>([]);
  const [selectedShipId, setSelectedShipId] = useState<string | null>(null);
  const [currentCatch, setCurrentCatch] = useState(0);

  // UI State
  const [randomHint, setRandomHint] = useState("");

  // Initialize
  useEffect(() => {
    setRandomHint(COMPANY_NAMES[Math.floor(Math.random() * COMPANY_NAMES.length)]);

    const saved = localStorage.getItem(SAVE_KEY);
    if (saved) {
      try {
        const data = JSON.parse(saved);
        if (data.companyName) {
            setCompanyName(data.companyName);
            setMoney(data.money);
            setShips(data.ships);
            setYear(data.year);
            setSeasonIndex(data.seasonIndex || 0);
            setLogs(data.logs);
            setEra(data.era || '1920');
            setView('HQ');
        }
      } catch(e) {}
    }
  }, []);

  // Autosave
  useEffect(() => {
    if (view !== 'SPLIT' && view !== 'TITLE') {
       const timer = setTimeout(() => {
          localStorage.setItem(SAVE_KEY, JSON.stringify({ companyName, money, ships, year, seasonIndex, logs, era }));
       }, 1000);
       return () => clearTimeout(timer);
    }
  }, [companyName, money, ships, year, seasonIndex, logs, view, era]);

  const getCurrentTimestamp = () => `${SEASONS[seasonIndex]} ${year}`;

  const addLog = (text: string, type: LogEntry['type'] = 'INFO') => {
      setLogs(prev => [{
          id: Date.now(),
          timestamp: getCurrentTimestamp(),
          text,
          type
      }, ...prev]);
  };

  const advanceTime = () => {
      setSeasonIndex(prev => {
          const next = prev + 1;
          if (next >= SEASONS.length) {
              setYear(y => y + 1);
              return 0;
          }
          return next;
      });
  };

  const handleSelectEra = (selectedEra: Era) => {
      setEra(selectedEra);
      setYear(parseInt(selectedEra));
      setView('TITLE');
  };

  const handleStartGame = () => {
      const finalName = companyName || randomHint;
      setCompanyName(finalName);
      addLog(`Útgerðin ${finalName} stofnuð (${era}).`, 'INFO');
      setView('HQ');
  };

  const handleBuyShip = (shipModel: typeof MARKET_SHIPS[0]) => {
      if (money >= shipModel.price) {
          setMoney(m => m - shipModel.price);
          const newShip: ShipItem = {
              id: Date.now().toString(),
              modelId: shipModel.id,
              name: SHIP_NAMES[Math.floor(Math.random() * SHIP_NAMES.length)] + ` ${Math.floor(Math.random() * 100)}`,
              type: shipModel.type,
              condition: 100,
              equipped: false
          };
          setShips(prev => [...prev, newShip]);
          addLog(`Keypti ${newShip.name} (${shipModel.name}) fyrir ${shipModel.price.toLocaleString()} kr.`, 'MONEY');
      }
  };

  const repairShip = (shipId: string) => {
      const ship = ships.find(s => s.id === shipId);
      if (!ship || ship.condition >= 100) return;

      const cost = Math.floor((100 - ship.condition) * 500); // 500kr per 1%
      if (money >= cost) {
          setMoney(m => m - cost);
          setShips(prev => prev.map(s => s.id === shipId ? { ...s, condition: 100 } : s));
          addLog(`Gerði við ${ship.name} fyrir ${cost.toLocaleString()} kr.`, 'MONEY');
      }
  };

  const startFishing = (shipId: string) => {
      const ship = ships.find(s => s.id === shipId);
      if (ship && ship.condition < 20) {
          alert("Skip er í of slæmu ástandi til að fara á sjó! Gerðu við það fyrst.");
          return;
      }

      setSelectedShipId(shipId);
      // Generate Grid
      const newGrid: FishingTile[] = Array(9).fill(null).map((_, i) => {
          const rand = Math.random();
          let content: FishingTile['content'] = 'EMPTY';
          let value = 0;

          if (rand > 0.7) { content = 'FISH'; value = 50000; }
          else if (rand > 0.9) { content = 'BIG_CATCH'; value = 150000; }
          else if (rand < 0.1) { content = 'DANGER'; value = -10000; }

          return { id: i, status: 'HIDDEN', content, value };
      });
      setFishingGrid(newGrid);
      setCurrentCatch(0);
      setView('FISHING');
      addLog(`Hélt til veiða á ${ship?.name}.`, 'INFO');
  };

  const useDepthMeter = () => {
      if (money >= DEPTH_METER_COST) {
          setMoney(m => m - DEPTH_METER_COST);
          // Find unrevealed tiles
          const hidden = fishingGrid.filter(t => t.status === 'HIDDEN');
          if (hidden.length > 0) {
              const target = hidden[Math.floor(Math.random() * hidden.length)];
              setFishingGrid(prev => prev.map(t => t.id === target.id ? { ...t, status: 'REVEALED' } : t));
          }
      }
  };

  const fishTile = (tile: FishingTile) => {
      if (tile.status === 'REVEALED' && (tile.content === 'EMPTY' || tile.content === 'DANGER')) {
         // Fishing revealed bad tiles is allowed but usually has no gain or is bad
      }

      const updatedGrid = fishingGrid.map(t => t.id === tile.id ? { ...t, status: 'REVEALED' as const } : t);
      setFishingGrid(updatedGrid);

      if (tile.content === 'DANGER') {
          addLog("Hætta! Netin festust eða veður versnaði.", 'ALERT');
          setCurrentCatch(c => c - 5000);
          // Small immediate damage on danger tiles
          if (selectedShipId) {
             setShips(prev => prev.map(s => s.id === selectedShipId ? { ...s, condition: Math.max(0, s.condition - 5) } : s));
          }
      } else if (tile.content === 'FISH' || tile.content === 'BIG_CATCH') {
          setCurrentCatch(c => c + tile.value);
      }
  };

  const endFishing = () => {
      // Payout
      setMoney(m => m + currentCatch);
      addLog(`Löndun: ${currentCatch.toLocaleString()} kr. komu í kassann.`, 'MONEY');

      // Wear and tear (normal)
      if (selectedShipId) {
          setShips(prev => prev.map(s => s.id === selectedShipId ? { ...s, condition: Math.max(0, s.condition - 2) } : s));
      }

      // 20% Chance of Event
      if (Math.random() < 0.2) {
          const event = EVENTS[Math.floor(Math.random() * EVENTS.length)];
          addLog(`${event.title}: ${event.text}`, 'EVENT');

          // Apply Money Effect
          if (event.effect.money !== 0) {
              setMoney(m => m + event.effect.money);
          }

          // Apply Condition Damage (Rallýspil)
          if (event.effect.conditionDamage && selectedShipId) {
              setShips(prev => prev.map(s => s.id === selectedShipId ? { 
                  ...s, 
                  condition: Math.max(0, s.condition - event.effect.conditionDamage!) 
              } : s));
          }
      }

      advanceTime();
      setView('HQ');
  };

  // --- Views ---

  if (view === 'SPLIT') {
      return (
          <div className="flex h-screen w-full overflow-hidden">
              {/* 1920 Side */}
              <div 
                  className="w-1/2 h-full bg-[#f6f1e1] text-[#2c1810] flex flex-col items-center justify-center p-8 relative cursor-pointer hover:bg-[#eaddcf] transition-colors group border-r-4 border-[#3e2723]"
                  onClick={() => handleSelectEra('1920')}
                  style={{ fontFamily: "'Playfair Display', serif" }}
              >
                  <div className="absolute inset-0 opacity-10 bg-[url('https://www.transparenttextures.com/patterns/aged-paper.png')]"></div>
                  <h1 className="text-6xl mb-4 font-bold tracking-widest group-hover:scale-110 transition-transform">1920</h1>
                  <h2 className="text-2xl italic mb-8">Upphaf Útgerðar</h2>
                  <Anchor size={64} className="text-[#3e2723] opacity-80" />
                  <div className="mt-8 text-sm uppercase tracking-widest border-t border-b border-[#3e2723] py-2">Smelltu til að velja</div>
              </div>

              {/* 2020 Side */}
              <div 
                  className="w-1/2 h-full bg-[#0f172a] text-white flex flex-col items-center justify-center p-8 relative cursor-pointer hover:bg-[#1e293b] transition-colors group"
                  onClick={() => handleSelectEra('2020')}
                  style={{ fontFamily: "ui-sans-serif, system-ui, sans-serif" }}
              >
                  <h1 className="text-6xl mb-4 font-extrabold tracking-tight text-blue-400 group-hover:scale-110 transition-transform">2020</h1>
                  <h2 className="text-2xl font-light mb-8 text-slate-300">Nútíma Tækni</h2>
                  <Bot size={64} className="text-blue-500 opacity-80" />
                  <div className="mt-8 text-sm uppercase tracking-widest text-slate-400 border-t border-b border-slate-700 py-2">Smelltu til að velja</div>
              </div>
          </div>
      );
  }

  if (view === 'TITLE') {
      return (
          <GameWrapper era={era}>
              <div className="min-h-screen flex flex-col items-center justify-center p-4 relative">
                  <div className="absolute inset-0 opacity-5 pointer-events-none bg-current"></div>

                  <div className="max-w-lg w-full text-center space-y-8 relative z-10">
                      <div className="space-y-2">
                          <h1 className="text-6xl font-header tracking-widest drop-shadow-sm">MAÍ GREIFINN</h1>
                          <div className="text-xl font-serif italic opacity-75">- Útvegsspilið {era} -</div>
                      </div>

                      <div className="paper-card p-8 rounded-sm transform rotate-1">
                          <label className="block text-left font-bold mb-2 font-header opacity-80">NAFN ÚTGERÐAR</label>
                          <input 
                              type="text" 
                              value={companyName}
                              onChange={(e) => setCompanyName(e.target.value)}
                              placeholder={`t.d. ${randomHint}`}
                              className="w-full bg-transparent border-b-2 border-current p-2 font-typewriter text-xl focus:outline-none placeholder-opacity-50"
                          />
                          <div className="text-left mt-2 text-xs opacity-60 font-serif italic">
                              Ábending: Prófaðu nöfn eins og „{randomHint}“.
                          </div>
                      </div>

                      <button 
                          onClick={handleStartGame}
                          className="btn-paper px-8 py-4 text-xl w-full hover:scale-[1.02] transition-transform flex items-center justify-center gap-3"
                      >
                          <Anchor size={24}/> Hefja Útgerð
                      </button>

                      <button 
                          onClick={() => setView('SPLIT')}
                          className="text-xs uppercase tracking-widest opacity-50 hover:opacity-100 hover:underline"
                      >
                          ← Breyta Tímabili
                      </button>
                  </div>
              </div>
          </GameWrapper>
      );
  }

  // HEADER COMPONENT (Shared)
  const Header = () => (
      <header className="bg-header p-4 shadow-lg sticky top-0 z-50 flex justify-between items-center transition-colors duration-300">
          <div className="flex items-center gap-4">
              <div className="w-12 h-12 bg-white/20 rounded-full flex items-center justify-center border-2 border-current">
                  <Anchor size={24}/>
              </div>
              <div>
                  <h2 className="font-header text-xl tracking-wide leading-none">{companyName}</h2>
                  <div className="text-xs opacity-70 font-typewriter mt-1">Stofnað {era}</div>
              </div>
          </div>
          <div className="flex items-center gap-6">
              <div className="text-right">
                  <div className="text-xs opacity-60 uppercase">Sjóður</div>
                  <div className="font-typewriter text-xl text-money">{money.toLocaleString()} kr.</div>
              </div>
              <div className="text-right hidden sm:block">
                  <div className="text-xs opacity-60 uppercase">Tími</div>
                  <div className="font-header text-xl capitalize">{getCurrentTimestamp()}</div>
              </div>
          </div>
      </header>
  );

  if (view === 'HQ') {
      return (
          <GameWrapper era={era}>
              <div className="min-h-screen pb-12">
                  <Header />

                  <main className="max-w-6xl mx-auto p-6 grid grid-cols-1 md:grid-cols-3 gap-6">

                      {/* Left Column: Fleet */}
                      <div className="md:col-span-2 space-y-6">
                          <div className="flex justify-between items-end border-b-2 border-current pb-2 mb-4 opacity-80">
                              <h3 className="font-header text-2xl flex items-center gap-2">
                                  <Ship className="text-accent"/> Flotinn
                              </h3>
                              <button onClick={() => setView('MARKET')} className="btn-paper px-4 py-2 text-sm flex items-center gap-2">
                                  <ShoppingCart size={14}/> Skipamarkaður
                              </button>
                          </div>

                          {ships.length === 0 ? (
                              <div className="paper-card p-8 text-center opacity-70 italic">
                                  Engin skip í flota. Farðu á markaðinn til að hefja rekstur.
                              </div>
                          ) : (
                              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                                  {ships.map(ship => (
                                      <div key={ship.id} className="paper-card relative group flex flex-col overflow-hidden transition-all duration-300 hover:shadow-lg">
                                          {/* Decorative 'Hole Punch' or Stamp for vintage feel */}
                                          {era !== '2020' && (
                                              <div className="absolute top-2 right-2 w-16 h-16 border-4 border-red-900/10 rounded-full flex items-center justify-center transform rotate-12 pointer-events-none">
                                                  <span className="text-[8px] font-bold text-red-900/20 uppercase text-center leading-none">Skráð<br/>Ísland</span>
                                              </div>
                                          )}

                                          {/* Header Strip */}
                                          <div className={`px-4 py-2 border-b border-black/10 flex justify-between items-center ${era === '2020' ? 'bg-slate-100/50' : 'bg-[#efebe0]'}`}>
                                              <div className="flex items-center gap-2">
                                                  <Ship size={14} className="opacity-50"/>
                                                  <span className="text-[10px] font-bold opacity-60 font-typewriter tracking-widest">
                                                      {era === '2020' ? 'ID:' : 'NR:'} {ship.id.slice(-4)}
                                                  </span>
                                              </div>
                                              <div className={`text-[10px] px-2 py-0.5 rounded font-bold ${era === '2020' ? 'bg-blue-100 text-blue-800' : 'bg-[#d7ccc8] text-[#3e2723]'}`}>
                                                  {ship.type}
                                              </div>
                                          </div>

                                          <div className="p-5 space-y-4">
                                              {/* Name */}
                                              <div>
                                                  <label className="text-[9px] uppercase tracking-wider opacity-50 block mb-1">
                                                      {era === '2020' ? 'Vessel Name' : 'Heiti Skips'}
                                                  </label>
                                                  <h4 className="font-header text-2xl font-bold leading-none">{ship.name}</h4>
                                              </div>

                                              {/* Data Table */}
                                              <div className={`grid grid-cols-2 gap-px ${era === '2020' ? 'bg-slate-200' : 'bg-[#d7ccc8]'} border border-transparent opacity-80 rounded overflow-hidden`}>
                                                   <div className={`${era === '2020' ? 'bg-white' : 'bg-[#fbf9f5]'} p-2`}>
                                                       <span className="block text-[9px] opacity-50 uppercase">Ástand</span>
                                                       <span className={`font-typewriter font-bold ${ship.condition < 50 ? 'text-red-600' : ''}`}>{ship.condition}%</span>
                                                   </div>
                                                   <div className={`${era === '2020' ? 'bg-white' : 'bg-[#fbf9f5]'} p-2`}>
                                                       <span className="block text-[9px] opacity-50 uppercase">Tæknibúnaður</span>
                                                       <span className="font-typewriter font-bold">{era === '2020' ? (ship.equipped ? 'Sonar' : 'Enginn') : (ship.equipped ? 'Dýptarm.' : 'Enginn')}</span>
                                                   </div>
                                              </div>

                                              {/* Action Area */}
                                              <div className="pt-2 flex items-center justify-end gap-2 mt-2">
                                                  {ship.condition < 100 && (
                                                      <button 
                                                          onClick={() => repairShip(ship.id)} 
                                                          className="text-xs underline decoration-dotted text-blue-600 hover:text-blue-800 flex items-center gap-1 mr-auto"
                                                      >
                                                          <Wrench size={12} /> <span className="hidden sm:inline">Viðgerð</span>
                                                      </button>
                                                  )}

                                                  <button 
                                                      onClick={() => startFishing(ship.id)}
                                                      className="btn-paper px-4 py-2 text-xs flex items-center gap-2 hover:translate-y-[-1px]"
                                                  >
                                                      <Waves size={14}/> 
                                                      <span>{era === '2020' ? 'Veiða' : 'Á Sjó'}</span>
                                                  </button>
                                              </div>
                                          </div>
                                      </div>
                                  ))}
                              </div>
                          )}
                      </div>

                      {/* Right Column: Logbook */}
                      <div className="space-y-4">
                           <div className="flex items-center justify-between border-b-2 border-current pb-2 opacity-80">
                              <h3 className="font-header text-xl flex items-center gap-2">
                                  <FileText className="text-accent"/> Dagbók
                              </h3>
                           </div>

                           <div className="paper-card p-4 min-h-[400px] max-h-[600px] overflow-y-auto font-typewriter text-sm space-y-4">
                               {logs.length === 0 && <div className="text-center opacity-50 italic pt-10">Bókin er auð...</div>}
                               {logs.map(log => (
                                   <div key={log.id} className="border-b border-black/10 pb-2 last:border-0">
                                       <div className="text-[10px] opacity-60 uppercase tracking-wider mb-1 flex items-center gap-2">
                                           <span>{log.timestamp}</span>
                                           <div className="h-px flex-1 bg-current opacity-20"></div>
                                       </div>
                                       <div className={`${
                                           log.type === 'MONEY' ? 'text-money font-bold' : 
                                           log.type === 'ALERT' ? 'text-red-600 font-bold' : 
                                           log.type === 'EVENT' ? 'text-orange-600 font-bold' : ''
                                       }`}>
                                           {log.text}
                                       </div>
                                   </div>
                               ))}
                           </div>
                      </div>

                  </main>
              </div>
          </GameWrapper>
      );
  }

  if (view === 'MARKET') {
      return (
          <GameWrapper era={era}>
              <div className="min-h-screen pb-12">
                  <Header />
                  <main className="max-w-4xl mx-auto p-6">
                      <div className="flex items-center gap-4 mb-6">
                          <button onClick={() => setView('HQ')} className="btn-paper p-2 rounded-full">
                              <ArrowRight className="rotate-180" size={20}/>
                          </button>
                          <h2 className="font-header text-3xl text-accent">SKIPAMARKAÐUR</h2>
                      </div>

                      <div className="space-y-4">
                          {MARKET_SHIPS.map(model => (
                              <div key={model.id} className="paper-card p-6 flex flex-col sm:flex-row items-center gap-6">
                                  <div className="w-32 h-24 bg-black/5 border border-black/10 flex items-center justify-center text-accent">
                                      <Ship size={48} strokeWidth={1}/>
                                  </div>
                                  <div className="flex-1 text-center sm:text-left">
                                      <h3 className="font-header text-xl font-bold">{model.name}</h3>
                                      <div className="text-sm opacity-70 font-typewriter mt-1">
                                          Burðargeta: {model.capacity} tonn | Viðhald: {model.upkeep} kr/ár
                                      </div>
                                  </div>
                                  <div className="text-right">
                                      <div className="font-header text-2xl mb-2">{model.price.toLocaleString()} kr.</div>
                                      <button 
                                          onClick={() => handleBuyShip(model)}
                                          disabled={money < model.price}
                                          className="btn-paper w-full py-2 disabled:opacity-50 disabled:cursor-not-allowed"
                                      >
                                          KAUPA
                                      </button>
                                  </div>
                              </div>
                          ))}
                      </div>
                  </main>
              </div>
          </GameWrapper>
      );
  }

  if (view === 'FISHING') {
      return (
          <GameWrapper era={era}>
            <div className={`min-h-screen relative text-white ${era === '2020' ? 'bg-slate-900' : 'bg-[#001020]'}`}>
                  <div className="absolute inset-0 opacity-20 bg-[url('https://www.transparenttextures.com/patterns/nautical-leather.png')]"></div>

                  <div className="relative z-10 max-w-2xl mx-auto p-6 flex flex-col h-screen">

                      {/* Fishing Header */}
                      <div className="flex justify-between items-center mb-8 bg-black/40 backdrop-blur p-4 border border-white/20 rounded-sm shadow-xl">
                          <div>
                              <h2 className="font-header text-xl text-yellow-100">Á VEIÐUM</h2>
                              <div className="text-xs text-white/70">{ships.find(s => s.id === selectedShipId)?.name}</div>
                          </div>
                          <div className="text-right">
                              <div className="text-xs text-white/70">Afli í lest</div>
                              <div className="font-typewriter text-2xl text-green-400">{currentCatch.toLocaleString()} kr.</div>
                          </div>
                      </div>

                      {/* Grid */}
                      <div className="flex-1 flex items-center justify-center">
                          <div className="grid grid-cols-3 gap-3 w-full max-w-md aspect-square">
                              {fishingGrid.map((tile) => (
                                  <button
                                      key={tile.id}
                                      onClick={() => fishTile(tile)}
                                      disabled={tile.status === 'REVEALED'}
                                      className={`relative rounded-sm border-2 transition-all duration-500 overflow-hidden ${
                                          tile.status === 'HIDDEN' 
                                          ? (era === '2020' ? 'bg-blue-600 border-blue-500 hover:bg-blue-500' : 'bg-[#0d47a1] border-[#1565c0] hover:bg-[#1565c0]') 
                                          : 'bg-[#f6f1e1] border-[#8d6e63]'
                                      }`}
                                  >
                                      {tile.status === 'HIDDEN' ? (
                                          <div className="absolute inset-0 flex items-center justify-center opacity-20">
                                              <Waves size={32} className="text-white animate-pulse"/>
                                          </div>
                                      ) : (
                                          <div className="flex flex-col items-center justify-center h-full animate-[fadeIn_0.5s] text-slate-900">
                                              {tile.content === 'EMPTY' && <div className="text-[#a1887f] font-typewriter text-xs">Tómt</div>}
                                              {tile.content === 'FISH' && <Fish size={32} className="text-[#1b5e20] mb-1"/>}
                                              {tile.content === 'BIG_CATCH' && <div className="text-[#f57f17]"><Fish size={40}/><Sparkles size={16} className="absolute top-2 right-2"/></div>}
                                              {tile.content === 'DANGER' && <AlertTriangle size={32} className="text-[#b71c1c]"/>}

                                              {tile.value !== 0 && (
                                                  <div className={`text-xs font-bold mt-1 ${tile.value > 0 ? 'text-[#1b5e20]' : 'text-[#b71c1c]'}`}>
                                                      {tile.value > 0 ? '+' : ''}{tile.value.toLocaleString()}
                                                  </div>
                                              )}
                                          </div>
                                      )}
                                  </button>
                              ))}
                          </div>
                      </div>

                      {/* Controls */}
                      <div className="mt-8 space-y-4">
                          <div className="flex gap-4">
                              <button 
                                  onClick={useDepthMeter}
                                  disabled={money < DEPTH_METER_COST}
                                  className="flex-1 btn-paper py-4 bg-slate-800 border-slate-700 text-slate-200 flex flex-col items-center justify-center gap-1 hover:bg-slate-700 disabled:opacity-50"
                              >
                                  <div className="flex items-center gap-2">
                                      <Search size={18} /> {era === '2020' ? 'SONAR SKANNI' : 'DÝPTARMÆLIR'}
                                  </div>
                                  <div className="text-[10px] text-slate-400">-5.000 kr. / notkun</div>
                              </button>

                              <button 
                                  onClick={endFishing}
                                  className="flex-1 btn-paper py-4 bg-green-900 border-green-800 text-white flex flex-col items-center justify-center gap-1 hover:bg-green-800"
                              >
                                  <div className="flex items-center gap-2">
                                      <Anchor size={18} /> LANDA & HEIM
                                  </div>
                                  <div className="text-[10px] text-green-300">Ljúka veiðiferð</div>
                              </button>
                          </div>
                      </div>

                  </div>
              </div>
          </GameWrapper>
      );
  }

  return null;
}

const root = createRoot(document.getElementById('root')!);
root.render(<App />);

import React, { useState, useEffect, useRef } from 'react';
import { createRoot } from 'react-dom/client';
import { Ship, Anchor, Fish, Coins, User, Waves, Bot, Play, Sparkles, AlertTriangle, X, ScrollText, Save, Trash2, ArrowRight, ShoppingCart, Map, DollarSign, Search, Calendar, Briefcase, FileText, Wrench, Clock, Battery } from 'lucide-react';

// --- Configuration ---

const START_MONEY = 500000;
const DEPTH_METER_COST = 5000;
const SAVE_KEY = 'maigreifinn_split_v1';
const SEASONS = ["Vor", "Sumar", "Haust", "Vetur"];

// Parody Names & Data
const COMPANY_NAMES = [
  "Brimverzlun hf.", "Hafdráttur h/f", "Togglarinn ehf.", "Sjómannafélagið Víkingur",
  "Útgerðarfélag Akureyrar", "Fiskvinnslan Alda", "Norðurljósavinnslan", "Vestfjarða-Skel hf.",
  "Ísbjörninn hf.", "Skeljungur Útgerð", "IceFresh Seafood", "Arctic Catch"
];

const SHIP_NAMES = [
  "MS Brimrós", "MS Togglari", "MS Djúpvera", "Guðrún Björg", "Sæljónið", 
  "Haförninn", "Sjöstjarnan", "Kjölurinn", "Aldan", "Vonin", "Víkingur", "Stormur"
];

type EventType = {
  id: string;
  title: string;
  text: string;
  type: 'BAD' | 'GOOD';
  effect: {
    money: number;
    rep: number;
    conditionDamage?: number; // Damage to the active ship
  }
};

const EVENTS: EventType[] = [
  { id: 'investigation', title: "Rannsóknarnefnd", text: "☠️ Hættuspil! Rannsóknarnefnd sjávarútvegsins mætir á svæðið.", effect: { money: 0, rep: -3 }, type: 'BAD' },
  { id: 'bank', title: "Bankinn hringir", text: "🏦 Útvegsspils-andi svífur yfir vötnum. Bankastjórinn vill sitt.", effect: { money: -25000, rep: 0 }, type: 'BAD' },
  { id: 'tire', title: "Rallýspil", text: "🏁 Rallýspil! Dekkið springur á bryggjubílnum og varahlutir tefjast. Skipið fær slæma meðferð.", effect: { money: 0, rep: 0, conditionDamage: 10 }, type: 'BAD' },
  { id: 'play', title: "Aktjóneri", text: "🎭 Leikritið í höfninni slær í gegn. Allir kátir.", effect: { money: 5000, rep: 2 }, type: 'GOOD' },
  { id: 'omar', title: "Ómar-style", text: "📻 „Þetta reddast“. Bjartsýni skilar sér í kassan.", effect: { money: 15000, rep: 1 }, type: 'GOOD' }
];

const MARKET_SHIPS = [
  { id: 1, name: "Trilla (Opinn)", type: 'TRILLA', price: 50000, capacity: 5, upkeep: 1000 },
  { id: 2, name: "Kvótakóngur", type: 'TRAWLER', price: 150000, capacity: 15, upkeep: 5000 },
  { id: 3, name: "MS Togglari", type: 'TRAWLER', price: 300000, capacity: 30, upkeep: 10000 },
  { id: 4, name: "Gullskipið", type: 'YACHT', price: 1000000, capacity: 50, upkeep: 25000 },
];

// --- Types ---

type GameView = 'SPLIT' | 'TITLE' | 'HQ' | 'MARKET' | 'FISHING';
type Era = '1920' | '2020';

interface ShipItem {
  id: string; // Unique ID
  modelId: number;
  name: string;
  type: string;
  condition: number; // 0-100%
  equipped: boolean; // Has depth meter?
}

interface LogEntry {
  id: number;
  timestamp: string; // "Vor 1955"
  text: string;
  type: 'INFO' | 'MONEY' | 'ALERT' | 'EVENT';
}

interface FishingTile {
  id: number;
  status: 'HIDDEN' | 'REVEALED';
  content: 'FISH' | 'EMPTY' | 'DANGER' | 'BIG_CATCH';
  value: number;
}

// --- Helper Components ---

const GameWrapper = ({ children, era }: { children?: React.ReactNode; era: Era }) => {
  const themeClass = era === '2020' ? 'theme-modern' : 'theme-vintage';
  return (
      <div className={themeClass}>
          {children}
      </div>
  );
};

// --- Main Component ---

function App() {
  // State
  const [view, setView] = useState<GameView>('SPLIT');
  const [era, setEra] = useState<Era>('1920');
  const [companyName, setCompanyName] = useState("");
  const [money, setMoney] = useState(START_MONEY);
  const [ships, setShips] = useState<ShipItem[]>([]);

  // Time System
  const [year, setYear] = useState(1920);
  const [seasonIndex, setSeasonIndex] = useState(0); // 0=Vor, 1=Sumar, 2=Haust, 3=Vetur

  const [logs, setLogs] = useState<LogEntry[]>([]);

  // Fishing State
  const [fishingGrid, setFishingGrid] = useState<FishingTile[]>([]);
  const [selectedShipId, setSelectedShipId] = useState<string | null>(null);
  const [currentCatch, setCurrentCatch] = useState(0);

  // UI State
  const [randomHint, setRandomHint] = useState("");

  // Initialize
  useEffect(() => {
    setRandomHint(COMPANY_NAMES[Math.floor(Math.random() * COMPANY_NAMES.length)]);

    const saved = localStorage.getItem(SAVE_KEY);
    if (saved) {
      try {
        const data = JSON.parse(saved);
        if (data.companyName) {
            setCompanyName(data.companyName);
            setMoney(data.money);
            setShips(data.ships);
            setYear(data.year);
            setSeasonIndex(data.seasonIndex || 0);
            setLogs(data.logs);
            setEra(data.era || '1920');
            setView('HQ');
        }
      } catch(e) {}
    }
  }, []);

  // Autosave
  useEffect(() => {
    if (view !== 'SPLIT' && view !== 'TITLE') {
       const timer = setTimeout(() => {
          localStorage.setItem(SAVE_KEY, JSON.stringify({ companyName, money, ships, year, seasonIndex, logs, era }));
       }, 1000);
       return () => clearTimeout(timer);
    }
  }, [companyName, money, ships, year, seasonIndex, logs, view, era]);

  const getCurrentTimestamp = () => `${SEASONS[seasonIndex]} ${year}`;

  const addLog = (text: string, type: LogEntry['type'] = 'INFO') => {
      setLogs(prev => [{
          id: Date.now(),
          timestamp: getCurrentTimestamp(),
          text,
          type
      }, ...prev]);
  };

  const advanceTime = () => {
      setSeasonIndex(prev => {
          const next = prev + 1;
          if (next >= SEASONS.length) {
              setYear(y => y + 1);
              return 0;
          }
          return next;
      });
  };

  const handleSelectEra = (selectedEra: Era) => {
      setEra(selectedEra);
      setYear(parseInt(selectedEra));
      setView('TITLE');
  };

  const handleStartGame = () => {
      const finalName = companyName || randomHint;
      setCompanyName(finalName);
      addLog(`Útgerðin ${finalName} stofnuð (${era}).`, 'INFO');
      setView('HQ');
  };

  const handleBuyShip = (shipModel: typeof MARKET_SHIPS[0]) => {
      if (money >= shipModel.price) {
          setMoney(m => m - shipModel.price);
          const newShip: ShipItem = {
              id: Date.now().toString(),
              modelId: shipModel.id,
              name: SHIP_NAMES[Math.floor(Math.random() * SHIP_NAMES.length)] + ` ${Math.floor(Math.random() * 100)}`,
              type: shipModel.type,
              condition: 100,
              equipped: false
          };
          setShips(prev => [...prev, newShip]);
          addLog(`Keypti ${newShip.name} (${shipModel.name}) fyrir ${shipModel.price.toLocaleString()} kr.`, 'MONEY');
      }
  };

  const repairShip = (shipId: string) => {
      const ship = ships.find(s => s.id === shipId);
      if (!ship || ship.condition >= 100) return;

      const cost = Math.floor((100 - ship.condition) * 500); // 500kr per 1%
      if (money >= cost) {
          setMoney(m => m - cost);
          setShips(prev => prev.map(s => s.id === shipId ? { ...s, condition: 100 } : s));
          addLog(`Gerði við ${ship.name} fyrir ${cost.toLocaleString()} kr.`, 'MONEY');
      }
  };

  const startFishing = (shipId: string) => {
      const ship = ships.find(s => s.id === shipId);
      if (ship && ship.condition < 20) {
          alert("Skip er í of slæmu ástandi til að fara á sjó! Gerðu við það fyrst.");
          return;
      }

      setSelectedShipId(shipId);
      // Generate Grid
      const newGrid: FishingTile[] = Array(9).fill(null).map((_, i) => {
          const rand = Math.random();
          let content: FishingTile['content'] = 'EMPTY';
          let value = 0;

          if (rand > 0.7) { content = 'FISH'; value = 50000; }
          else if (rand > 0.9) { content = 'BIG_CATCH'; value = 150000; }
          else if (rand < 0.1) { content = 'DANGER'; value = -10000; }

          return { id: i, status: 'HIDDEN', content, value };
      });
      setFishingGrid(newGrid);
      setCurrentCatch(0);
      setView('FISHING');
      addLog(`Hélt til veiða á ${ship?.name}.`, 'INFO');
  };

  const useDepthMeter = () => {
      if (money >= DEPTH_METER_COST) {
          setMoney(m => m - DEPTH_METER_COST);
          // Find unrevealed tiles
          const hidden = fishingGrid.filter(t => t.status === 'HIDDEN');
          if (hidden.length > 0) {
              const target = hidden[Math.floor(Math.random() * hidden.length)];
              setFishingGrid(prev => prev.map(t => t.id === target.id ? { ...t, status: 'REVEALED' } : t));
          }
      }
  };

  const fishTile = (tile: FishingTile) => {
      if (tile.status === 'REVEALED' && (tile.content === 'EMPTY' || tile.content === 'DANGER')) {
         // Fishing revealed bad tiles is allowed but usually has no gain or is bad
      }

      const updatedGrid = fishingGrid.map(t => t.id === tile.id ? { ...t, status: 'REVEALED' as const } : t);
      setFishingGrid(updatedGrid);

      if (tile.content === 'DANGER') {
          addLog("Hætta! Netin festust eða veður versnaði.", 'ALERT');
          setCurrentCatch(c => c - 5000);
          // Small immediate damage on danger tiles
          if (selectedShipId) {
             setShips(prev => prev.map(s => s.id === selectedShipId ? { ...s, condition: Math.max(0, s.condition - 5) } : s));
          }
      } else if (tile.content === 'FISH' || tile.content === 'BIG_CATCH') {
          setCurrentCatch(c => c + tile.value);
      }
  };

  const endFishing = () => {
      // Payout
      setMoney(m => m + currentCatch);
      addLog(`Löndun: ${currentCatch.toLocaleString()} kr. komu í kassann.`, 'MONEY');

      // Wear and tear (normal)
      if (selectedShipId) {
          setShips(prev => prev.map(s => s.id === selectedShipId ? { ...s, condition: Math.max(0, s.condition - 2) } : s));
      }

      // 20% Chance of Event
      if (Math.random() < 0.2) {
          const event = EVENTS[Math.floor(Math.random() * EVENTS.length)];
          addLog(`${event.title}: ${event.text}`, 'EVENT');

          // Apply Money Effect
          if (event.effect.money !== 0) {
              setMoney(m => m + event.effect.money);
          }

          // Apply Condition Damage (Rallýspil)
          if (event.effect.conditionDamage && selectedShipId) {
              setShips(prev => prev.map(s => s.id === selectedShipId ? { 
                  ...s, 
                  condition: Math.max(0, s.condition - event.effect.conditionDamage!) 
              } : s));
          }
      }

      advanceTime();
      setView('HQ');
  };

  // --- Views ---

  if (view === 'SPLIT') {
      return (
          <div className="flex h-screen w-full overflow-hidden">
              {/* 1920 Side */}
              <div 
