                                      {tile.content === 'DANGER' && <AlertTriangle size={32} className="text-red-500"/>}
                                      {tile.value !== 0 && <div className="absolute bottom-1 text-xs font-bold">{tile.value > 0 ? '+' : ''}{tile.value}</div>}
                                  </div>
                              )}
                          </button>
                      ))}
